import React, { useState, useMemo, useEffect } from 'react';
import Layout from './components/Layout';
import AgroExpert from './components/AgroExpert';
import { CATEGORIES, COURSES, PLANS } from './constants';
import { Phone, ChevronRight, CheckCircle2, CreditCard, Smartphone, Play, Loader2, Video, Sparkles, Filter, X, Clock, BarChart, ListOrdered } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState<any>(null);
  const [showPayModal, setShowPayModal] = useState(false);

  // Filtering states
  const [filterCategory, setFilterCategory] = useState<string>('all');
  const [filterLevel, setFilterLevel] = useState<string>('all');
  const [filterDuration, setFilterDuration] = useState<string>('all');

  // Video generation states
  const [generatingVideoId, setGeneratingVideoId] = useState<string | null>(null);
  const [generatedVideos, setGeneratedVideos] = useState<Record<string, string>>({});
  const [videoLoadingMessage, setVideoLoadingMessage] = useState("");

  // Learning steps states
  const [courseSteps, setCourseSteps] = useState<Record<string, string[]>>({});
  const [loadingSteps, setLoadingSteps] = useState<Record<string, boolean>>({});

  const handleLogin = (method: 'google' | 'phone') => {
    setIsLoggedIn(true);
    setUser({ name: "Bonaventure", plan: 'Free' });
  };

  const fetchStepsForCourse = async (course: any) => {
    if (courseSteps[course.id] || loadingSteps[course.id]) return;

    setLoadingSteps(prev => ({ ...prev, [course.id]: true }));
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Génère 3 à 5 étapes clés d'apprentissage pour ce cours d'agronomie africaine. 
        Titre: ${course.title}
        Description: ${course.description}

        Réponds uniquement sous forme de liste JSON de chaînes de caractères (strings).
        Exemple: ["Étape 1...", "Étape 2..."]`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });

      const steps = JSON.parse(response.text);
      setCourseSteps(prev => ({ ...prev, [course.id]: steps }));
    } catch (error) {
      console.error("Error fetching steps:", error);
    } finally {
      setLoadingSteps(prev => ({ ...prev, [course.id]: false }));
    }
  };

  // Trigger steps fetching when learn tab is active and courses change
  useEffect(() => {
    if (activeTab === 'learn') {
      filteredCourses.forEach(course => {
        if (!courseSteps[course.id]) {
          fetchStepsForCourse(course);
        }
      });
    }
  }, [activeTab, filterCategory, filterLevel, filterDuration]);

  const filteredCourses = useMemo(() => {
    return COURSES.filter(course => {
      const matchCategory = filterCategory === 'all' || course.category === filterCategory;
      const matchLevel = filterLevel === 'all' || course.level === filterLevel;
      const matchDuration = filterDuration === 'all' || course.duration === filterDuration;
      return matchCategory && matchLevel && matchDuration;
    });
  }, [filterCategory, filterLevel, filterDuration]);

  const generateCourseVideo = async (course: any) => {
    try {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        // @ts-ignore
        await window.aistudio.openSelectKey();
      }

      setGeneratingVideoId(course.id);
      setVideoLoadingMessage("Analyse du contenu pédagogique...");

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const loadingStepsArr = [
        "Analyse du contenu pédagogique...",
        "Génération du script visuel...",
        "Création des séquences cinématiques...",
        "Optimisation pour le contexte africain...",
        "Finalisation du tutoriel vidéo..."
      ];

      let stepIdx = 0;
      const interval = setInterval(() => {
        stepIdx = (stepIdx + 1) % loadingStepsArr.length;
        setVideoLoadingMessage(loadingStepsArr[stepIdx]);
      }, 7000);

      const prompt = `Un tutoriel éducatif professionnel de haute qualité montrant : ${course.title}. ${course.description}. Style cinématographique, environnement agricole africain réaliste, lumière naturelle, pédagogique, montrant les bonnes pratiques.`;

      let operation = await ai.models.generateVideos({
        model: 'veo-3.1-fast-generate-preview',
        prompt: prompt,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: '16:9'
        }
      });

      while (!operation.done) {
        await new Promise(resolve => setTimeout(resolve, 10000));
        operation = await ai.operations.getVideosOperation({ operation: operation });
      }

      clearInterval(interval);
      const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
      if (downloadLink) {
        const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
        if (response.status === 404) {
          // @ts-ignore
          await window.aistudio.openSelectKey();
          throw new Error("Clé API non valide ou projet non configuré.");
        }
        const blob = await response.blob();
        const url = URL.createObjectURL(blob);
        setGeneratedVideos(prev => ({ ...prev, [course.id]: url }));
      }
    } catch (error) {
      console.error("Video Generation Error:", error);
      alert("Erreur lors de la génération. Assurez-vous d'utiliser une clé API valide avec facturation activée.");
    } finally {
      setGeneratingVideoId(null);
      setVideoLoadingMessage("");
    }
  };

  const resetFilters = () => {
    setFilterCategory('all');
    setFilterLevel('all');
    setFilterDuration('all');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'home':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <section>
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-xl font-bold text-stone-900">Modules Agro</h2>
                <button className="text-emerald-600 text-sm font-semibold" onClick={() => setActiveTab('learn')}>Tout voir</button>
              </div>
              <div className="grid grid-cols-3 gap-4">
                {CATEGORIES.map((cat) => (
                  <button 
                    key={cat.id} 
                    onClick={() => {
                      setFilterCategory(cat.id);
                      setActiveTab('learn');
                    }}
                    className="flex flex-col items-center gap-2 group"
                  >
                    <div className={`${cat.color} w-14 h-14 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-stone-200 group-active:scale-95 transition-all`}>
                      {React.cloneElement(cat.icon as React.ReactElement, { size: 28 })}
                    </div>
                    <span className="text-[10px] font-bold text-stone-600 uppercase text-center leading-tight">{cat.name}</span>
                  </button>
                ))}
              </div>
            </section>

            <section className="bg-emerald-900 rounded-3xl p-6 text-white relative overflow-hidden shadow-xl">
               <div className="relative z-10">
                 <h3 className="text-lg font-bold mb-2">Conseil du Jour</h3>
                 <p className="text-emerald-100 text-sm mb-4 leading-relaxed">
                   C'est le moment idéal pour préparer vos poquets en vue des prochaines pluies. Pensez à l'apport de fumure organique bien décomposée.
                 </p>
                 <button className="bg-white text-emerald-900 px-4 py-2 rounded-xl text-sm font-bold shadow-lg">
                   Lire la fiche
                 </button>
               </div>
               <div className="absolute right-[-20px] bottom-[-20px] opacity-20">
                  <div className="w-32 h-32 border-8 border-white rounded-full"></div>
               </div>
            </section>

            <section>
              <h2 className="text-xl font-bold text-stone-900 mb-4">Formations recommandées</h2>
              <div className="space-y-4">
                {COURSES.slice(0, 3).map(course => (
                  <div key={course.id} onClick={() => setActiveTab('learn')} className="bg-white p-3 rounded-2xl border border-stone-200 flex gap-4 shadow-sm hover:border-emerald-200 transition-all cursor-pointer">
                    <img src={course.image} className="w-24 h-24 rounded-xl object-cover" alt={course.title} />
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[10px] font-bold px-2 py-0.5 bg-stone-100 text-stone-500 rounded-full uppercase">{course.level}</span>
                        <span className="text-[10px] font-bold px-2 py-0.5 bg-emerald-50 text-emerald-600 rounded-full uppercase">{course.duration}</span>
                      </div>
                      <h4 className="font-bold text-stone-900 leading-tight mb-1">{course.title}</h4>
                      <p className="text-xs text-stone-500 line-clamp-2">{course.description}</p>
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>
        );
      case 'learn':
        return (
          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <div>
                <h1 className="text-2xl font-bold text-stone-900">Catalogue Formation</h1>
                <p className="text-stone-500 text-sm">Apprenez à votre rythme.</p>
              </div>
              {(filterCategory !== 'all' || filterLevel !== 'all' || filterDuration !== 'all') && (
                <button 
                  onClick={resetFilters}
                  className="flex items-center gap-1 text-xs font-bold text-red-500 bg-red-50 px-3 py-2 rounded-full hover:bg-red-100 transition-colors"
                >
                  <X size={14} /> Effacer les filtres
                </button>
              )}
            </div>

            {/* Filters Section */}
            <div className="flex flex-col gap-3">
              <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide no-scrollbar text-nowrap">
                <div className="flex items-center gap-2 bg-white px-3 py-2 rounded-2xl border border-stone-200 shrink-0">
                  <Filter size={14} className="text-stone-400" />
                  <select 
                    value={filterCategory} 
                    onChange={(e) => setFilterCategory(e.target.value)}
                    className="bg-transparent text-xs font-bold text-stone-700 outline-none border-none p-0 cursor-pointer"
                  >
                    <option value="all">Toutes Catégories</option>
                    {CATEGORIES.map(cat => (
                      <option key={cat.id} value={cat.id}>{cat.name}</option>
                    ))}
                  </select>
                </div>

                <div className="flex items-center gap-2 bg-white px-3 py-2 rounded-2xl border border-stone-200 shrink-0">
                  <BarChart size={14} className="text-stone-400" />
                  <select 
                    value={filterLevel} 
                    onChange={(e) => setFilterLevel(e.target.value)}
                    className="bg-transparent text-xs font-bold text-stone-700 outline-none border-none p-0 cursor-pointer"
                  >
                    <option value="all">Tous Niveaux</option>
                    <option value="Débutant">Débutant</option>
                    <option value="Intermédiaire">Intermédiaire</option>
                    <option value="Expert">Expert</option>
                  </select>
                </div>

                <div className="flex items-center gap-2 bg-white px-3 py-2 rounded-2xl border border-stone-200 shrink-0">
                  <Clock size={14} className="text-stone-400" />
                  <select 
                    value={filterDuration} 
                    onChange={(e) => setFilterDuration(e.target.value)}
                    className="bg-transparent text-xs font-bold text-stone-700 outline-none border-none p-0 cursor-pointer"
                  >
                    <option value="all">Toutes Durées</option>
                    <option value="3h">3 heures</option>
                    <option value="4h">4 heures</option>
                    <option value="6h">6 heures</option>
                    <option value="10h">10 heures</option>
                  </select>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-6">
              {filteredCourses.length > 0 ? (
                filteredCourses.map(course => (
                  <div key={course.id} className="bg-white rounded-[2.5rem] overflow-hidden border border-stone-200 shadow-sm transition-all hover:shadow-md">
                    <div className="relative">
                      {generatedVideos[course.id] ? (
                        <video 
                          src={generatedVideos[course.id]} 
                          controls 
                          className="w-full aspect-video object-cover bg-black"
                        />
                      ) : (
                        <div className="relative">
                          <img src={course.image} className="w-full h-56 object-cover" alt={course.title} />
                          {generatingVideoId === course.id && (
                            <div className="absolute inset-0 bg-stone-900/80 flex flex-col items-center justify-center p-6 text-center">
                              <Loader2 className="animate-spin text-emerald-400 mb-4" size={48} />
                              <p className="text-white font-bold text-lg mb-2">{videoLoadingMessage}</p>
                              <p className="text-stone-400 text-xs italic">La génération peut prendre quelques minutes...</p>
                            </div>
                          )}
                        </div>
                      )}
                    </div>

                    <div className="p-6">
                      <div className="flex items-center gap-2 mb-3">
                        <span className="px-3 py-1 bg-emerald-100 text-emerald-700 rounded-full text-[10px] font-black uppercase tracking-widest">{course.level}</span>
                        <span className="px-3 py-1 bg-stone-100 text-stone-500 rounded-full text-[10px] font-black uppercase tracking-widest">{course.duration}</span>
                        <span className="px-3 py-1 bg-blue-50 text-blue-600 rounded-full text-[10px] font-black uppercase tracking-widest">
                          {CATEGORIES.find(c => c.id === course.category)?.name}
                        </span>
                      </div>
                      <h3 className="font-bold text-xl mb-2 text-stone-900">{course.title}</h3>
                      <p className="text-sm text-stone-600 mb-4 leading-relaxed">{course.description}</p>

                      {/* Learning Steps Section */}
                      <div className="mb-6 bg-stone-50 rounded-2xl p-4 border border-stone-100">
                        <div className="flex items-center gap-2 mb-3 text-emerald-800">
                          <ListOrdered size={16} />
                          <span className="text-xs font-bold uppercase tracking-wider">Parcours d'apprentissage</span>
                        </div>

                        {loadingSteps[course.id] ? (
                          <div className="flex items-center gap-2 text-stone-400 py-2">
                            <Loader2 size={14} className="animate-spin" />
                            <span className="text-[10px] font-medium italic">Génération du programme par l'IA...</span>
                          </div>
                        ) : courseSteps[course.id] ? (
                          <div className="space-y-2">
                            {courseSteps[course.id].map((step, idx) => (
                              <div key={idx} className="flex gap-3">
                                <div className="flex flex-col items-center">
                                  <div className="w-5 h-5 rounded-full bg-emerald-600 text-white flex items-center justify-center text-[9px] font-bold">
                                    {idx + 1}
                                  </div>
                                  {idx < courseSteps[course.id].length - 1 && (
                                    <div className="w-px h-full bg-emerald-200 mt-1"></div>
                                  )}
                                </div>
                                <span className="text-xs text-stone-700 font-medium leading-tight pb-2">{step}</span>
                              </div>
                            ))}
                          </div>
                        ) : (
                          <button 
                            onClick={() => fetchStepsForCourse(course)}
                            className="text-[10px] text-emerald-600 font-bold hover:underline"
                          >
                            Charger les étapes clés
                          </button>
                        )}
                      </div>

                      <div className="grid grid-cols-2 gap-3">
                        <button className="flex items-center justify-center gap-2 bg-stone-900 text-white py-4 rounded-2xl font-bold text-sm hover:bg-black transition-all">
                          <Play size={18} /> Lire le cours
                        </button>
                        {!generatedVideos[course.id] && (
                          <button 
                            onClick={() => generateCourseVideo(course)}
                            disabled={!!generatingVideoId}
                            className="flex items-center justify-center gap-2 bg-emerald-100 text-emerald-700 py-4 rounded-2xl font-bold text-sm hover:bg-emerald-200 transition-all disabled:opacity-50"
                          >
                            <Video size={18} /> Vidéo IA
                          </button>
                        )}
                        {generatedVideos[course.id] && (
                          <button 
                            onClick={() => generateCourseVideo(course)}
                            className="flex items-center justify-center gap-2 bg-stone-100 text-stone-600 py-4 rounded-2xl font-bold text-sm hover:bg-stone-200 transition-all"
                          >
                            <Sparkles size={18} /> Régénérer
                          </button>
                        )}
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="py-20 text-center bg-white rounded-3xl border border-dashed border-stone-200">
                  <Filter className="mx-auto text-stone-200 mb-4" size={48} />
                  <p className="text-stone-500 font-medium">Aucun cours ne correspond à ces filtres.</p>
                  <button onClick={resetFilters} className="mt-4 text-emerald-600 font-bold underline">Voir tout le catalogue</button>
                </div>
              )}
            </div>
          </div>
        );
      case 'expert':
        return (
          <div className="space-y-6">
            <div>
              <h1 className="text-2xl font-bold text-stone-900 mb-2">Expert IA</h1>
              <p className="text-stone-500 text-sm">Posez vos questions techniques ou envoyez une photo de votre culture malade.</p>
            </div>
            <AgroExpert />
          </div>
        );
      case 'profile':
        return (
          <div className="space-y-8">
            <div className="flex items-center gap-4 bg-white p-6 rounded-3xl border border-stone-200">
              <div className="w-16 h-16 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center font-bold text-2xl border-4 border-white shadow-md">
                {user?.name[0]}
              </div>
              <div>
                <h2 className="text-xl font-bold text-stone-900">{user?.name}</h2>
                <div className="flex items-center gap-2">
                  <span className={`text-xs px-2 py-0.5 rounded-full font-bold uppercase ${
                    user?.plan === 'Pro' ? 'bg-amber-100 text-amber-600' : 'bg-stone-100 text-stone-500'
                  }`}>
                    Plan {user?.plan}
                  </span>
                  {user?.plan === 'Free' && (
                    <button 
                      onClick={() => setShowPayModal(true)}
                      className="text-xs text-emerald-600 font-bold hover:underline"
                    >
                      Passer au Pro
                    </button>
                  )}
                </div>
              </div>
            </div>

            <section>
              <h3 className="font-bold text-stone-900 mb-4">Abonnements</h3>
              <div className="grid grid-cols-1 gap-4">
                {PLANS.map(plan => (
                  <div key={plan.id} className={`p-6 rounded-3xl border-2 transition-all ${
                    plan.popular ? 'border-emerald-500 bg-emerald-50/30' : 'border-stone-100 bg-white'
                  }`}>
                    {plan.popular && (
                      <span className="text-[10px] font-bold bg-emerald-500 text-white px-3 py-1 rounded-full uppercase mb-2 inline-block tracking-widest">Recommandé</span>
                    )}
                    <div className="flex justify-between items-center mb-4">
                      <h4 className="text-xl font-bold">{plan.name}</h4>
                      <span className="font-bold text-emerald-700">{plan.price}</span>
                    </div>
                    <ul className="space-y-3 mb-6">
                      {plan.features.map((f, i) => (
                        <li key={i} className="flex items-start gap-2 text-sm text-stone-600">
                          <CheckCircle2 size={16} className="text-emerald-500 mt-0.5 shrink-0" />
                          {f}
                        </li>
                      ))}
                    </ul>
                    <button 
                      onClick={() => plan.id !== 'free' && setShowPayModal(true)}
                      disabled={plan.id === 'free'}
                      className={`w-full py-4 rounded-2xl font-bold shadow-sm ${
                        plan.popular ? 'bg-emerald-600 text-white shadow-emerald-200' : 'bg-stone-100 text-stone-400'
                      }`}
                    >
                      {plan.id === 'free' ? 'Plan Actuel' : 'Souscrire'}
                    </button>
                  </div>
                ))}
              </div>
            </section>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} user={user}>
      {renderContent()}

      {/* Payment Modal */}
      {showPayModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-stone-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-300">
            <h3 className="text-2xl font-bold text-stone-900 mb-2">Paiement Sécurisé</h3>
            <p className="text-stone-500 text-sm mb-8">Choisissez votre mode de paiement local ou international.</p>

            <div className="space-y-3 mb-8">
              <button className="w-full flex items-center justify-between p-4 rounded-2xl border-2 border-stone-100 hover:border-emerald-500 transition-all group">
                <div className="flex items-center gap-3">
                  <div className="bg-blue-50 p-2 rounded-xl group-hover:bg-emerald-50">
                    <CreditCard className="text-blue-600 group-hover:text-emerald-600" />
                  </div>
                  <span className="font-bold text-stone-700">Visa / Mastercard</span>
                </div>
                <ChevronRight className="text-stone-300" />
              </button>

              <button className="w-full flex items-center justify-between p-4 rounded-2xl border-2 border-stone-100 hover:border-emerald-500 transition-all group">
                <div className="flex items-center gap-3">
                  <div className="bg-amber-50 p-2 rounded-xl group-hover:bg-emerald-50">
                    <Smartphone className="text-amber-600 group-hover:text-emerald-600" />
                  </div>
                  <div className="text-left">
                    <span className="block font-bold text-stone-700">Mobile Money</span>
                    <span className="text-[10px] text-stone-400 uppercase font-bold">Moov / Orange / Airtel</span>
                  </div>
                </div>
                <ChevronRight className="text-stone-300" />
              </button>
            </div>

            <button 
              onClick={() => setShowPayModal(false)}
              className="w-full py-4 text-stone-400 font-bold"
            >
              Annuler
            </button>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

{
  "name": "AgroExpert Afrique",
  "description": "Une plateforme agronomique complète pour l'Afrique : formation, itinéraires techniques, phytopathologie, agro-business et plus encore.",
  "requestFramePermissions": [
    "camera",
    "microphone",
    "geolocation"
  ]
}

import React, { useState, useMemo, useEffect } from 'react';
import Layout from './components/Layout';
import AgroExpert from './components/AgroExpert';
import { CATEGORIES, COURSES, PLANS } from './constants';
import { Phone, ChevronRight, CheckCircle2, CreditCard, Smartphone, Play, Loader2, Video, Sparkles, Filter, X, Clock, BarChart, ListOrdered, CloudSun, MapPin, Wind, Droplets, Thermometer } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState<any>(null);
  const [showPayModal, setShowPayModal] = useState(false);

  // Weather states
  const [weatherData, setWeatherData] = useState<any>(null);
  const [weatherLoading, setWeatherLoading] = useState(false);
  const [locationError, setLocationError] = useState<string | null>(null);

  // Filtering states
  const [filterCategory, setFilterCategory] = useState<string>('all');
  const [filterLevel, setFilterLevel] = useState<string>('all');
  const [filterDuration, setFilterDuration] = useState<string>('all');

  // Video generation states
  const [generatingVideoId, setGeneratingVideoId] = useState<string | null>(null);
  const [generatedVideos, setGeneratedVideos] = useState<Record<string, string>>({});
  const [videoLoadingMessage, setVideoLoadingMessage] = useState("");

  // Learning steps states
  const [courseSteps, setCourseSteps] = useState<Record<string, string[]>>({});
  const [loadingSteps, setLoadingSteps] = useState<Record<string, boolean>>({});

  const handleLogin = (method: 'google' | 'phone') => {
    setIsLoggedIn(true);
    setUser({ name: "Bonaventure", plan: 'Free' });
  };

  const fetchWeather = async (lat: number, lon: number) => {
    setWeatherLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Donne-moi la météo actuelle précise pour les coordonnées lat: ${lat}, lon: ${lon}. 
        Inclus la température (°C), l'humidité (%), la vitesse du vent (km/h), les conditions (ensoleillé, pluvieux, etc.) et le nom de la ville/zone.
        Ajoute aussi un conseil agronomique court adapté à cette météo pour un agriculteur africain.
        Réponds uniquement en format JSON structuré.`,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              location: { type: Type.STRING },
              temp: { type: Type.NUMBER },
              condition: { type: Type.STRING },
              humidity: { type: Type.NUMBER },
              wind: { type: Type.NUMBER },
              agroAdvice: { type: Type.STRING }
            },
            required: ["location", "temp", "condition", "humidity", "wind", "agroAdvice"]
          }
        }
      });

      const data = JSON.parse(response.text);
      setWeatherData(data);
    } catch (error) {
      console.error("Weather fetching error:", error);
    } finally {
      setWeatherLoading(false);
    }
  };

  useEffect(() => {
    if (isLoggedIn && !weatherData && !weatherLoading) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          fetchWeather(position.coords.latitude, position.coords.longitude);
        },
        (error) => {
          console.error("Geolocation error:", error);
          setLocationError("Géolocalisation refusée ou indisponible.");
          // Fallback to a default location like N'Djamena for the user context
          fetchWeather(12.1348, 15.0557);
        }
      );
    }
  }, [isLoggedIn]);

  const fetchStepsForCourse = async (course: any) => {
    if (courseSteps[course.id] || loadingSteps[course.id]) return;

    setLoadingSteps(prev => ({ ...prev, [course.id]: true }));
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Génère 3 à 5 étapes clés d'apprentissage pour ce cours d'agronomie africaine. 
        Titre: ${course.title}
        Description: ${course.description}

        Réponds uniquement sous forme de liste JSON de chaînes de caractères (strings).
        Exemple: ["Étape 1...", "Étape 2..."]`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });

      const steps = JSON.parse(response.text);
      setCourseSteps(prev => ({ ...prev, [course.id]: steps }));
    } catch (error) {
      console.error("Error fetching steps:", error);
    } finally {
      setLoadingSteps(prev => ({ ...prev, [course.id]: false }));
    }
  };

  useEffect(() => {
    if (activeTab === 'learn') {
      filteredCourses.forEach(course => {
        if (!courseSteps[course.id]) {
          fetchStepsForCourse(course);
        }
      });
    }
  }, [activeTab, filterCategory, filterLevel, filterDuration]);

  const filteredCourses = useMemo(() => {
    return COURSES.filter(course => {
      const matchCategory = filterCategory === 'all' || course.category === filterCategory;
      const matchLevel = filterLevel === 'all' || course.level === filterLevel;
      const matchDuration = filterDuration === 'all' || course.duration === filterDuration;
      return matchCategory && matchLevel && matchDuration;
    });
  }, [filterCategory, filterLevel, filterDuration]);

  const generateCourseVideo = async (course: any) => {
    try {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        // @ts-ignore
        await window.aistudio.openSelectKey();
      }

      setGeneratingVideoId(course.id);
      setVideoLoadingMessage("Analyse du contenu pédagogique...");

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const loadingStepsArr = [
        "Analyse du contenu pédagogique...",
        "Génération du script visuel...",
        "Création des séquences cinématiques...",
        "Optimisation pour le contexte africain...",
        "Finalisation du tutoriel vidéo..."
      ];

      let stepIdx = 0;
      const interval = setInterval(() => {
        stepIdx = (stepIdx + 1) % loadingStepsArr.length;
        setVideoLoadingMessage(loadingStepsArr[stepIdx]);
      }, 7000);

      const prompt = `Un tutoriel éducatif professionnel de haute qualité montrant : ${course.title}. ${course.description}. Style cinématographique, environnement agricole africain réaliste, lumière naturelle, pédagogique, montrant les bonnes pratiques.`;

      let operation = await ai.models.generateVideos({
        model: 'veo-3.1-fast-generate-preview',
        prompt: prompt,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: '16:9'
        }
      });

      while (!operation.done) {
        await new Promise(resolve => setTimeout(resolve, 10000));
        operation = await ai.operations.getVideosOperation({ operation: operation });
      }

      clearInterval(interval);
      const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
      if (downloadLink) {
        const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
        if (response.status === 404) {
          // @ts-ignore
          await window.aistudio.openSelectKey();
          throw new Error("Clé API non valide ou projet non configuré.");
        }
        const blob = await response.blob();
        const url = URL.createObjectURL(blob);
        setGeneratedVideos(prev => ({ ...prev, [course.id]: url }));
      }
    } catch (error) {
      console.error("Video Generation Error:", error);
      alert("Erreur lors de la génération. Assurez-vous d'utiliser une clé API valide avec facturation activée.");
    } finally {
      setGeneratingVideoId(null);
      setVideoLoadingMessage("");
    }
  };

  const resetFilters = () => {
    setFilterCategory('all');
    setFilterLevel('all');
    setFilterDuration('all');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'home':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            {/* Weather Section */}
            <section className="bg-white rounded-3xl p-6 shadow-sm border border-stone-100 overflow-hidden relative">
              <div className="flex items-center justify-between mb-6 relative z-10">
                <div className="flex items-center gap-2">
                  <div className="bg-amber-100 p-2 rounded-xl text-amber-600">
                    <CloudSun size={24} />
                  </div>
                  <div>
                    <h2 className="text-lg font-bold text-stone-900 leading-tight">Météo Locale</h2>
                    <div className="flex items-center gap-1 text-stone-400">
                      <MapPin size={12} />
                      <span className="text-[10px] font-bold uppercase tracking-wider">
                        {weatherLoading ? "Localisation..." : weatherData?.location || "N'Djamena (Par défaut)"}
                      </span>
                    </div>
                  </div>
                </div>
                {weatherLoading ? (
                  <Loader2 className="animate-spin text-stone-300" size={20} />
                ) : (
                  <div className="text-right">
                    <div className="text-3xl font-black text-stone-900">{weatherData?.temp ?? '--'}°C</div>
                    <div className="text-xs font-bold text-stone-400 capitalize">{weatherData?.condition ?? 'Chargement...'}</div>
                  </div>
                )}
              </div>

              {weatherData && (
                <div className="grid grid-cols-2 gap-4 mb-6 relative z-10">
                  <div className="bg-stone-50 rounded-2xl p-3 flex items-center gap-3">
                    <Droplets className="text-blue-500" size={20} />
                    <div>
                      <span className="block text-[10px] font-bold text-stone-400 uppercase">Humidité</span>
                      <span className="font-bold text-stone-800">{weatherData.humidity}%</span>
                    </div>
                  </div>
                  <div className="bg-stone-50 rounded-2xl p-3 flex items-center gap-3">
                    <Wind className="text-emerald-500" size={20} />
                    <div>
                      <span className="block text-[10px] font-bold text-stone-400 uppercase">Vent</span>
                      <span className="font-bold text-stone-800">{weatherData.wind} km/h</span>
                    </div>
                  </div>
                </div>
              )}

              {weatherData?.agroAdvice && (
                <div className="bg-emerald-50 rounded-2xl p-4 flex gap-3 relative z-10 border border-emerald-100">
                  <div className="bg-emerald-600 w-8 h-8 rounded-full flex items-center justify-center text-white shrink-0 shadow-sm">
                    <Sparkles size={16} />
                  </div>
                  <div>
                    <span className="block text-[10px] font-black text-emerald-800 uppercase mb-1 tracking-widest">Conseil IA en temps réel</span>
                    <p className="text-sm text-emerald-900 font-medium leading-snug">
                      {weatherData.agroAdvice}
                    </p>
                  </div>
                </div>
              )}

              {/* Decorative background sun blur */}
              <div className="absolute top-[-20%] right-[-10%] w-32 h-32 bg-amber-400/10 rounded-full blur-3xl"></div>
            </section>

            <section>
              <div className="flex items-center justify-between mb-4">
