import React, { useState, useRef, useEffect } from 'react';
import { Send, Camera, Sparkles, Loader2, Image as ImageIcon, X, RotateCcw, Copy, Check, Calendar, Plus, Trash2, ClipboardList } from 'lucide-react';
import { getAgroAdvice, diagnosePlant } from '../services/geminiService';

interface Message {
  role: 'user' | 'bot';
  text: string;
  image?: string;
}

interface ItineraryStep {
  id: string;
  description: string;
  deadline: string;
  completed: boolean;
}

const AgroExpert: React.FC = () => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante malade pour un diagnostic.' }
  ]);
  const [loading, setLoading] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  // Itinerary states
  const [cropName, setCropName] = useState('');
  const [scientificName, setScientificName] = useState('');
  const [steps, setSteps] = useState<ItineraryStep[]>([]);
  const [newStepDesc, setNewStepDesc] = useState('');
  const [newStepDate, setNewStepDate] = useState('');
  const [isItineraryOpen, setIsItineraryOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const botResponse = await getAgroAdvice(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setLoading(false);
  };

  const handleReset = () => {
    if (window.confirm("Voulez-vous vraiment effacer toute la conversation ?")) {
      setMessages([
        { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante malade pour un diagnostic.' }
      ]);
    }
  };

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedIndex(index);
      setTimeout(() => setCopiedIndex(null), 2000);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      alert("L'image est trop volumineuse. Veuillez choisir une image de moins de 5 Mo.");
      return;
    }

    const reader = new FileReader();
    reader.onloadstart = () => setLoading(true);

    reader.onloadend = async () => {
      const dataUrl = reader.result as string;
      const base64 = dataUrl.split(',')[1];

      setMessages(prev => [...prev, { 
        role: 'user', 
        text: "Pouvez-vous diagnostiquer cette plante ?", 
        image: dataUrl 
      }]);

      try {
        const diagnosis = await diagnosePlant(base64);
        setMessages(prev => [...prev, { role: 'bot', text: diagnosis }]);
      } catch (error) {
        setMessages(prev => [...prev, { role: 'bot', text: "Désolé, je n'ai pas pu analyser cette image. Assurez-vous qu'elle est bien éclairée et que les symptômes sont visibles." }]);
      } finally {
        setLoading(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };

    reader.readAsDataURL(file);
  };

  // Itinerary functions
  const addStep = () => {
    if (!newStepDesc || !newStepDate) return;
    const newStep: ItineraryStep = {
      id: Date.now().toString(),
      description: newStepDesc,
      deadline: newStepDate,
      completed: false,
    };
    setSteps([...steps, newStep]);
    setNewStepDesc('');
    setNewStepDate('');
  };

  const removeStep = (id: string) => {
    setSteps(steps.filter(s => s.id !== id));
  };

  const toggleStep = (id: string) => {
    setSteps(steps.map(s => s.id === id ? { ...s, completed: !s.completed } : s));
  };

  return (
    <div className="flex flex-col space-y-4">
      {/* Chat Container */}
      <div className="flex flex-col h-[60vh] bg-white rounded-[2rem] shadow-sm border border-stone-200 overflow-hidden">
        <div className="bg-emerald-600 px-6 py-4 text-white flex items-center justify-between shadow-lg relative z-10">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl">
              <Sparkles size={20} />
            </div>
            <div>
              <span className="font-bold block leading-tight">IA Agro Expert</span>
              <span className="text-[10px] uppercase font-black tracking-widest opacity-80">Conseil & Diagnostic</span>
            </div>
          </div>
          <button 
            onClick={handleReset}
            className="p-2 hover:bg-white/10 rounded-xl transition-colors text-white/90"
            title="Réinitialiser la conversation"
          >
            <RotateCcw size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-stone-50/50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
              <div className={`max-w-[85%] overflow-hidden relative group ${
                m.role === 'user' 
                  ? 'bg-emerald-600 text-white rounded-3xl rounded-tr-none shadow-md shadow-emerald-100' 
                  : 'bg-white border border-stone-200 text-stone-800 rounded-3xl rounded-tl-none shadow-sm'
              }`}>
                {m.role === 'bot' && (
                  <button 
                    onClick={() => handleCopy(m.text, i)}
                    className="absolute top-2 right-2 p-1.5 rounded-lg bg-stone-100/50 text-stone-400 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-stone-100 hover:text-emerald-600"
                    title="Copier la réponse"
                  >
                    {copiedIndex === i ? <Check size={14} /> : <Copy size={14} />}
                  </button>
                )}
                {m.image && (
                  <div className="p-1">
                    <img src={m.image} alt="Upload" className="w-full max-h-64 object-cover rounded-2xl" />
                  </div>
                )}
                <div className="p-4 pr-10">
                  <p className="text-sm whitespace-pre-wrap leading-relaxed">{m.text}</p>
                </div>
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex justify-start animate-pulse">
              <div className="bg-white border border-stone-200 p-4 rounded-3xl rounded-tl-none shadow-sm flex items-center gap-3">
                <div className="flex gap-1">
                  <span className="w-1.5 h-1.5 bg-emerald-600 rounded-full animate-bounce"></span>
                  <span className="w-1.5 h-1.5 bg-emerald-600 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                  <span className="w-1.5 h-1.5 bg-emerald-600 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                </div>
                <span className="text-xs font-bold text-stone-400 uppercase tracking-widest italic">Analyse en cours...</span>
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        <div className="p-4 border-t border-stone-100 bg-white">
          <div className="flex items-center gap-2">
            <div className="flex gap-1">
              <button 
                onClick={() => fileInputRef.current?.click()}
                title="Télécharger une image"
                className="p-3 text-emerald-600 hover:bg-emerald-50 rounded-2xl transition-all active:scale-90"
              >
                <ImageIcon size={22} />
              </button>
              <button 
                onClick={() => {
                  if (fileInputRef.current) {
                    fileInputRef.current.setAttribute('capture', 'environment');
                    fileInputRef.current.click();
                  }
                }}
                title="Prendre une photo"
                className="p-3 text-emerald-600 hover:bg-emerald-50 rounded-2xl transition-all active:scale-90 hidden sm:block"
              >
                <Camera size={22} />
              </button>
            </div>

            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
              accept="image/*" 
              className="hidden" 
            />

            <div className="flex-1 relative">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Posez une question à l'IA..."
                className="w-full bg-stone-100 border-none rounded-2xl px-5 py-3.5 focus:ring-2 focus:ring-emerald-500 transition-all text-sm outline-none font-medium placeholder:text-stone-400"
              />
            </div>

            <button 
              onClick={handleSend}
              disabled={!input.trim() || loading}
              className="p-3.5 bg-emerald-600 text-white rounded-2xl shadow-lg shadow-emerald-100 hover:bg-emerald-700 disabled:opacity-30 disabled:shadow-none transition-all active:scale-95"
            >
              <Send size={20} />
            </button>
          </div>
        </div>
      </div>

      {/* Technical Itinerary Section */}
      <div className="bg-white rounded-[2rem] border border-stone-200 overflow-hidden shadow-sm">
        <button 
          onClick={() => setIsItineraryOpen(!isItineraryOpen)}
          className="w-full flex items-center justify-between p-6 hover:bg-stone-50 transition-colors"
        >
          <div className="flex items-center gap-3">
            <div className="bg-amber-100 p-2.5 rounded-xl text-amber-600">
              <ClipboardList size={22} />
            </div>
            <div className="text-left">
              <h3 className="font-bold text-stone-900 leading-tight">Itinéraire Technique</h3>
              <p className="text-[10px] uppercase font-black tracking-widest text-stone-400">Planifier vos cultures</p>
            </div>
          </div>
          <div className={`transition-transform duration-300 ${isItineraryOpen ? 'rotate-180' : ''}`}>
            <Plus size={20} className="text-stone-400" />
          </div>
        </button>

        {isItineraryOpen && (
          <div className="p-6 border-t border-stone-100 space-y-6 animate-in slide-in-from-top-4 duration-300">
            {/* Crop Info */}
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase tracking-widest mb-2">Nom de la Culture</label>
                <input 
                  type="text" 
                  value={cropName}
                  onChange={(e) => setCropName(e.target.value)}
                  placeholder="Ex: Maïs Grain, Tomate, Riz..."
                  className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-5 py-3 outline-none focus:ring-2 focus:ring-emerald-500 font-bold text-stone-800"
                />
              </div>

              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase tracking-widest mb-2">Nom Scientifique</label>
                <input 
                  type="text" 
                  value={scientificName}
                  onChange={(e) => setScientificName(e.target.value)}
                  placeholder="Ex: Zea mays, Solanum lycopersicum..."
                  className="w-full bg-stone-50 border border-stone-100 rounded-2xl px-5 py-3 outline-none focus:ring-2 focus:ring-emerald-500 font-medium italic text-stone-700"
                />
              </div>
            </div>

            {/* Add Step Form */}
            <div className="bg-stone-50 p-4 rounded-3xl border border-stone-100 space-y-3">
              <span className="block text-[10px] font-black text-emerald-700 uppercase tracking-widest mb-1">Nouvelle Étape</span>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <input 
                  type="text" 
                  value={newStepDesc}
                  onChange={(e) => setNewStepDesc(e.target.value)}
                  placeholder="Description de l'étape (ex: Semis)"
                  className="bg-white border-none rounded-xl px-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-emerald-500"
                />
                <div className="flex gap-2">
                  <input 
                    type="date" 
                    value={newStepDate}
                    onChange={(e) => setNewStepDate(e.target.value)}
                    className="flex-1 bg-white border-none rounded-xl px-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-emerald-500"
                  />
                  <button 
                    onClick={addStep}
                    className="p-2.5 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 active:scale-95 transition-all"
                  >
                    <Plus size={20} />
                  </button>
                </div>
              </div>
            </div>

            {/* Steps List */}
            <div className="space-y-3">
              {steps.length > 0 ? (
                steps.sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).map((step) => (
                  <div 
                    key={step.id} 
                    className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                      step.completed ? 'bg-stone-50 border-stone-200' : 'bg-white border-stone-100 shadow-sm'
                    }`}
                  >
                    <div className="flex items-center gap-4">
                      <button 
                        onClick={() => toggleStep(step.id)}
                        className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${
                          step.completed ? 'bg-emerald-600 border-emerald-600 text-white' : 'border-stone-200 text-transparent'
                        }`}
                      >
                        <Check size={14} />
                      </button>
                      <div>
                        <p className={`text-sm font-bold ${step.completed ? 'text-stone-400 line-through' : 'text-stone-800'}`}>
                          {step.description}
                        </p>
                        <div className="flex items-center gap-1.5 text-[10px] font-black uppercase text-stone-400 mt-1">
                          <Calendar size={10} />
                          {new Date(step.deadline).toLocaleDateString('fr-FR', { day: 'numeric', month: 'long' })}
                        </div>
                      </div>
                    </div>
                    <button 
                      onClick={() => removeStep(step.id)}
                      className="p-2 text-stone-300 hover:text-red-500 transition-colors"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                ))
              ) : (
                <div className="py-8 text-center border-2 border-dashed border-stone-100 rounded-3xl">
                  <ClipboardList className="mx-auto text-stone-100 mb-3" size={40} />
                  <p className="text-sm text-stone-400 font-medium">Aucune étape planifiée pour {cropName || 'votre culture'}.</p>
                </div>
              )}
            </div>

            {(cropName || scientificName) && steps.length > 0 && (
              <button 
                className="w-full flex items-center justify-center gap-2 py-4 bg-stone-900 text-white rounded-2xl font-bold text-sm hover:bg-black transition-all shadow-xl shadow-stone-100"
              >
                <Sparkles size={18} className="text-amber-400" /> Enregistrer l'itinéraire
              </button>
            )}
          </div>
        )}
      </div>

      <p className="text-[9px] text-center text-stone-400 font-bold uppercase tracking-widest opacity-60">L'IA peut faire des erreurs, vérifiez toujours auprès d'un agronome local.</p>
    </div>
  );
};

