import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getAgroAdvice = async (prompt: string, context?: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Tu es un expert agronome africain senior. Réponds de manière précise, adaptée au contexte africain (climat, types de sols, moyens financiers).

      Question de l'utilisateur: ${prompt}
      ${context ? `Contexte supplémentaire: ${context}` : ''}`,
      config: {
        temperature: 0.7,
        topP: 0.95,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Désolé, je rencontre une difficulté technique. Veuillez réessayer plus tard.";
  }
};

export const diagnosePlant = async (imageBase64: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: imageBase64 } },
          { text: "Diagnostique cette plante. Donne le nom de la maladie, les symptômes, et surtout les solutions bio et chimiques adaptées au contexte africain." }
        ]
      }
    });
    return response.text;
  } catch (error) {
    console.error("Diagnosis Error:", error);
    return "Échec du diagnostic. Assurez-vous qu'elle est bien éclairée.";
  }
};

export const generateCropItinerary = async (crop: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Génère un itinéraire technique complet et chronologique pour la culture de: ${crop} en Afrique.
      Inclus les étapes clés : préparation du sol, semis, fertilisation (N-P-K), sarclage, traitement phytosanitaire et récolte.
      Pour chaque étape, donne une description précise et le nombre de jours recommandés APRÈS le semis (J+X).

      Réponds uniquement en format JSON structuré.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              description: { type: Type.STRING },
              daysFromStart: { type: Type.NUMBER }
            },
            required: ["description", "daysFromStart"]
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Itinerary Generation Error:", error);
    return null;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Camera, Sparkles, Loader2, Image as ImageIcon, X, RotateCcw, Copy, Check, Calendar, Plus, Trash2, ClipboardList, User, Wand2 } from 'lucide-react';
import { getAgroAdvice, diagnosePlant, generateCropItinerary } from '../services/geminiService';

interface Message {
  role: 'user' | 'bot';
  text: string;
  image?: string;
}

interface ItineraryStep {
  id: string;
  description: string;
  deadline: string;
  completed: boolean;
  daysFromStart?: number;
}

const AgroExpert: React.FC = () => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
  ]);
  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  // Profile states
  const [userAvatar, setUserAvatar] = useState<string | null>(null);
  const avatarInputRef = useRef<HTMLInputElement>(null);

  // Itinerary states
  const [cropName, setCropName] = useState('');
  const [scientificName, setScientificName] = useState('');
  const [startDate, setStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [steps, setSteps] = useState<ItineraryStep[]>([]);
  const [newStepDesc, setNewStepDesc] = useState('');
  const [newStepDate, setNewStepDate] = useState('');
  const [isItineraryOpen, setIsItineraryOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const botResponse = await getAgroAdvice(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setLoading(false);
  };

  const handleReset = () => {
    if (window.confirm("Voulez-vous vraiment effacer toute la conversation ?")) {
      setMessages([
        { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
      ]);
    }
  };

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedIndex(index);
      setTimeout(() => setCopiedIndex(null), 2000);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadstart = () => setLoading(true);

    reader.onloadend = async () => {
      const dataUrl = reader.result as string;
      const base64 = dataUrl.split(',')[1];

      setMessages(prev => [...prev, { 
        role: 'user', 
        text: "Pouvez-vous diagnostiquer cette plante ?", 
        image: dataUrl 
      }]);

      try {
        const diagnosis = await diagnosePlant(base64);
        setMessages(prev => [...prev, { role: 'bot', text: diagnosis }]);
      } catch (error) {
        setMessages(prev => [...prev, { role: 'bot', text: "Erreur lors du diagnostic." }]);
      } finally {
        setLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUserAvatar(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  // Itinerary functions
  const addStep = () => {
    if (!newStepDesc || !newStepDate) return;
    const newStep: ItineraryStep = {
      id: Date.now().toString(),
      description: newStepDesc,
      deadline: newStepDate,
      completed: false,
    };
    setSteps([...steps, newStep]);
    setNewStepDesc('');
    setNewStepDate('');
  };

  const handleAiSuggest = async () => {
    if (!cropName) {
      alert("Veuillez d'abord saisir le nom de la culture.");
      return;
    }
    setSuggesting(true);
    const suggestedSteps = await generateCropItinerary(cropName);
    if (suggestedSteps) {
      const start = new Date(startDate);
      const newSteps: ItineraryStep[] = suggestedSteps.map((s: any, idx: number) => {
        const deadlineDate = new Date(start);
        deadlineDate.setDate(start.getDate() + s.daysFromStart);
        return {
          id: `ai-${Date.now()}-${idx}`,
          description: s.description,
          deadline: deadlineDate.toISOString().split('T')[0],
          completed: false,
          daysFromStart: s.daysFromStart
        };
      });
      setSteps(newSteps);
    }
    setSuggesting(false);
  };

  const removeStep = (id: string) => {
    setSteps(steps.filter(s => s.id !== id));
  };

  const toggleStep = (id: string) => {
    setSteps(steps.map(s => s.id === id ? { ...s, completed: !s.completed } : s));
  };

  return (
    <div className="flex flex-col space-y-4">
      {/* Profile Photo Section */}
      <div className="bg-white rounded-[2rem] p-4 border border-stone-200 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="relative group cursor-pointer" onClick={() => avatarInputRef.current?.click()}>
            <div className="w-[40px] h-[40px] rounded-full overflow-hidden border-2 border-emerald-100 flex items-center justify-center bg-stone-100">
              {userAvatar ? (
                <img src={userAvatar} alt="Profile" className="w-full h-full object-cover" />
              ) : (
                <User size={20} className="text-stone-400" />
              )}
            </div>
            <div className="absolute inset-0 bg-black/40 rounded-full opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
              <Camera size={12} className="text-white" />
            </div>
            <input type="file" ref={avatarInputRef} className="hidden" accept="image/*" onChange={handleAvatarUpload} />
          </div>
          <div>
            <h4 className="text-sm font-bold text-stone-900 leading-tight">Mon Profil</h4>
            <p className="text-[10px] text-stone-400 uppercase font-black tracking-widest">Avatar Agriculteur</p>
          </div>
        </div>
      </div>

      {/* Chat Container */}
      <div className="flex flex-col h-[60vh] bg-white rounded-[2rem] shadow-sm border border-stone-200 overflow-hidden">
        <div className="bg-emerald-600 px-6 py-4 text-white flex items-center justify-between shadow-lg relative z-10">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl"><Sparkles size={20} /></div>
            <div>
              <span className="font-bold block leading-tight">IA Agro Expert</span>
