      </div>

      <p className="text-[9px] text-center text-stone-400 font-bold uppercase tracking-widest opacity-60">Utilisez les suggestions de l'IA comme base de travail.</p>
    </div>
  );
};

export default AgroExpert;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Camera, Sparkles, Loader2, Image as ImageIcon, X, RotateCcw, Copy, Check, Calendar, Plus, Trash2, ClipboardList, User, Wand2, AlertCircle, BellRing } from 'lucide-react';
import { getAgroAdvice, diagnosePlant, generateCropItinerary } from '../services/geminiService';

interface Message {
  role: 'user' | 'bot';
  text: string;
  image?: string;
}

interface ItineraryStep {
  id: string;
  description: string;
  deadline: string;
  completed: boolean;
  daysFromStart?: number;
}

const AgroExpert: React.FC = () => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
  ]);
  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  // Profile states
  const [userAvatar, setUserAvatar] = useState<string | null>(null);
  const avatarInputRef = useRef<HTMLInputElement>(null);

  // Itinerary states
  const [cropName, setCropName] = useState('');
  const [scientificName, setScientificName] = useState('');
  const [startDate, setStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [steps, setSteps] = useState<ItineraryStep[]>([]);
  const [newStepDesc, setNewStepDesc] = useState('');
  const [newStepDate, setNewStepDate] = useState('');
  const [isItineraryOpen, setIsItineraryOpen] = useState(false);

  // Notifications calculation
  const { overdueCount, upcomingCount } = useMemo(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    let overdue = 0;
    let upcoming = 0;

    steps.forEach(step => {
      if (!step.completed) {
        const deadlineDate = new Date(step.deadline);
        deadlineDate.setHours(0, 0, 0, 0);

        if (deadlineDate < today) {
          overdue++;
        } else {
          const diffTime = deadlineDate.getTime() - today.getTime();
          const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
          if (diffDays <= 3) {
            upcoming++;
          }
        }
      }
    });

    return { overdueCount: overdue, upcomingCount: upcoming };
  }, [steps]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const botResponse = await getAgroAdvice(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setLoading(false);
  };

  const handleReset = () => {
    if (window.confirm("Voulez-vous vraiment effacer toute la conversation ?")) {
      setMessages([
        { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
      ]);
    }
  };

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedIndex(index);
      setTimeout(() => setCopiedIndex(null), 2000);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadstart = () => setLoading(true);

    reader.onloadend = async () => {
      const dataUrl = reader.result as string;
      const base64 = dataUrl.split(',')[1];

      setMessages(prev => [...prev, { 
        role: 'user', 
        text: "Pouvez-vous diagnostiquer cette plante ?", 
        image: dataUrl 
      }]);

      try {
        const diagnosis = await diagnosePlant(base64);
        setMessages(prev => [...prev, { role: 'bot', text: diagnosis }]);
      } catch (error) {
        setMessages(prev => [...prev, { role: 'bot', text: "Erreur lors du diagnostic." }]);
      } finally {
        setLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUserAvatar(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  // Itinerary functions
  const addStep = () => {
    if (!newStepDesc || !newStepDate) return;
    const newStep: ItineraryStep = {
      id: Date.now().toString(),
      description: newStepDesc,
      deadline: newStepDate,
      completed: false,
    };
    setSteps([...steps, newStep]);
    setNewStepDesc('');
    setNewStepDate('');
  };

  const handleAiSuggest = async () => {
    if (!cropName) {
      alert("Veuillez d'abord saisir le nom de la culture.");
      return;
    }
    setSuggesting(true);
    const suggestedSteps = await generateCropItinerary(cropName);
    if (suggestedSteps) {
      const start = new Date(startDate);
      const newSteps: ItineraryStep[] = suggestedSteps.map((s: any, idx: number) => {
        const deadlineDate = new Date(start);
        deadlineDate.setDate(start.getDate() + s.daysFromStart);
        return {
          id: `ai-${Date.now()}-${idx}`,
          description: s.description,
          deadline: deadlineDate.toISOString().split('T')[0],
          completed: false,
          daysFromStart: s.daysFromStart
        };
      });
      setSteps(newSteps);
    }
    setSuggesting(false);
  };

  const removeStep = (id: string) => {
    setSteps(steps.filter(s => s.id !== id));
  };

  const toggleStep = (id: string) => {
    setSteps(steps.map(s => s.id === id ? { ...s, completed: !s.completed } : s));
  };

  const getStepStatus = (step: ItineraryStep) => {
    if (step.completed) return 'completed';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const deadlineDate = new Date(step.deadline);
    deadlineDate.setHours(0, 0, 0, 0);

    if (deadlineDate < today) return 'overdue';
    const diffTime = deadlineDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    if (diffDays <= 3) return 'upcoming';
    return 'pending';
  };

  return (
    <div className="flex flex-col space-y-4">
      {/* Profile Photo Section */}
      <div className="bg-white rounded-[2rem] p-4 border border-stone-200 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="relative group cursor-pointer" onClick={() => avatarInputRef.current?.click()}>
            <div className="w-[40px] h-[40px] rounded-full overflow-hidden border-2 border-emerald-100 flex items-center justify-center bg-stone-100">
              {userAvatar ? (
                <img src={userAvatar} alt="Profile" className="w-full h-full object-cover" />
              ) : (
                <User size={20} className="text-stone-400" />
              )}
            </div>
            <div className="absolute inset-0 bg-black/40 rounded-full opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
              <Camera size={12} className="text-white" />
            </div>
            <input type="file" ref={avatarInputRef} className="hidden" accept="image/*" onChange={handleAvatarUpload} />
          </div>
          <div>
            <h4 className="text-sm font-bold text-stone-900 leading-tight">Mon Profil</h4>
            <p className="text-[10px] text-stone-400 uppercase font-black tracking-widest">Avatar Agriculteur</p>
          </div>
        </div>
      </div>

      {/* Chat Container */}
      <div className="flex flex-col h-[60vh] bg-white rounded-[2rem] shadow-sm border border-stone-200 overflow-hidden">
        <div className="bg-emerald-600 px-6 py-4 text-white flex items-center justify-between shadow-lg relative z-10">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl"><Sparkles size={20} /></div>
            <div>
              <span className="font-bold block leading-tight">IA Agro Expert</span>
              <span className="text-[10px] uppercase font-black tracking-widest opacity-80">Conseil & Diagnostic</span>
            </div>
          </div>
          <button onClick={handleReset} className="p-2 hover:bg-white/10 rounded-xl transition-colors"><RotateCcw size={20} /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-stone-50/50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
              <div className="flex flex-col gap-1 items-end">
                <div className={`max-w-[85%] overflow-hidden relative group ${
                  m.role === 'user' ? 'bg-emerald-600 text-white rounded-3xl rounded-tr-none shadow-md' : 'bg-white border border-stone-200 text-stone-800 rounded-3xl rounded-tl-none shadow-sm'
                }`}>
                  {m.role === 'bot' && (
                    <button onClick={() => handleCopy(m.text, i)} className="absolute top-2 right-2 p-1.5 rounded-lg bg-stone-100/50 text-stone-400 opacity-0 group-hover:opacity-100 transition-opacity">
                      {copiedIndex === i ? <Check size={14} /> : <Copy size={14} />}
                    </button>
                  )}
                  {m.image && <div className="p-1"><img src={m.image} className="w-full max-h-64 object-cover rounded-2xl" /></div>}
                  <div className="p-4 pr-10"><p className="text-sm whitespace-pre-wrap leading-relaxed">{m.text}</p></div>
                </div>
                {m.role === 'user' && userAvatar && (
                  <div className="w-[24px] h-[24px] rounded-full overflow-hidden border border-emerald-200 mr-2 mt-[-10px] z-20 shadow-sm bg-white">
                    <img src={userAvatar} className="w-full h-full object-cover" />
                  </div>
                )}
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex justify-start animate-pulse">
              <div className="bg-white border border-stone-200 p-4 rounded-3xl rounded-tl-none shadow-sm flex items-center gap-3">
                <div className="flex gap-1"><span className="w-1.5 h-1.5 bg-emerald-600 rounded-full animate-bounce"></span></div>
                <span className="text-xs font-bold text-stone-400 uppercase tracking-widest italic">Analyse...</span>
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        <div className="p-4 border-t border-stone-100 bg-white">
          <div className="flex items-center gap-2">
            <button onClick={() => fileInputRef.current?.click()} className="p-3 text-emerald-600 hover:bg-emerald-50 rounded-2xl"><ImageIcon size={22} /></button>
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept="image/*" className="hidden" />
            <input type="text" value={input} onChange={(e) => setInput(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleSend()} placeholder="Une question ?" className="flex-1 bg-stone-100 border-none rounded-2xl px-5 py-3.5 text-sm outline-none" />
            <button onClick={handleSend} disabled={!input.trim() || loading} className="p-3.5 bg-emerald-600 text-white rounded-2xl shadow-lg"><Send size={20} /></button>
          </div>
        </div>
      </div>

      {/* Technical Itinerary Section */}
      <div className="bg-white rounded-[2rem] border border-stone-200 overflow-hidden shadow-sm">
        <button onClick={() => setIsItineraryOpen(!isItineraryOpen)} className="w-full flex items-center justify-between p-6 hover:bg-stone-50 transition-colors">
          <div className="flex items-center gap-3">
            <div className="bg-amber-100 p-2.5 rounded-xl text-amber-600 relative">
              <ClipboardList size={22} />
              {(overdueCount > 0 || upcomingCount > 0) && (
                <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 border-2 border-white rounded-full animate-pulse"></span>
              )}
            </div>
            <div className="text-left">
              <h3 className="font-bold text-stone-900 leading-tight">Itinéraire Technique</h3>
              <p className="text-[10px] uppercase font-black tracking-widest text-stone-400">
                {overdueCount > 0 ? `${overdueCount} en retard` : 'Planifier mes récoltes'}
              </p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            {overdueCount > 0 && (
              <span className="px-2 py-0.5 bg-red-100 text-red-600 text-[10px] font-black rounded-full uppercase tracking-widest">
                Attention
              </span>
            )}
            <Plus size={20} className={`transition-transform duration-300 text-stone-400 ${isItineraryOpen ? 'rotate-45' : ''}`} />
          </div>
        </button>

        {isItineraryOpen && (
          <div className="p-6 border-t border-stone-100 space-y-6 animate-in slide-in-from-top-4 duration-300">
            {/* Notification Summary */}
            {(overdueCount > 0 || upcomingCount > 0) && (
              <div className="flex flex-col gap-2">
                {overdueCount > 0 && (
                  <div className="bg-red-50 border border-red-100 rounded-2xl p-3 flex items-center gap-3 text-red-700">
                    <AlertCircle size={18} />
                    <span className="text-xs font-bold">Attention : {overdueCount} {overdueCount > 1 ? 'étapes sont' : 'étape est'} en retard !</span>
                  </div>
                )}
                {upcomingCount > 0 && (
                  <div className="bg-amber-50 border border-amber-100 rounded-2xl p-3 flex items-center gap-3 text-amber-700">
                    <BellRing size={18} className="animate-bounce" />
                    <span className="text-xs font-bold">{upcomingCount} {upcomingCount > 1 ? 'étapes approchent' : 'étape approche'} (J-3).</span>
                  </div>
                )}
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div>
                <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest mb-2">Culture</label>
                <div className="flex gap-2">
                  <input type="text" value={cropName} onChange={(e) => setCropName(e.target.value)} placeholder="Ex: Maïs" className="flex-1 bg-stone-50 border border-stone-100 rounded-xl px-4 py-2.5 text-sm font-bold" />
                  <button onClick={handleAiSuggest} disabled={suggesting || !cropName} className="p-2.5 bg-amber-500 text-white rounded-xl hover:bg-amber-600 disabled:opacity-50 flex items-center gap-2">
                    {suggesting ? <Loader2 size={18} className="animate-spin" /> : <Wand2 size={18} />}
                    <span className="text-xs font-bold hidden sm:inline">IA</span>
                  </button>
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest mb-2">Nom Scientifique</label>
                <input 
                  type="text" 
                  value={scientificName} 
                  onChange={(e) => setScientificName(e.target.value)} 
                  placeholder="Ex: Zea mays" 
                  className="w-full bg-stone-50 border border-stone-100 rounded-xl px-4 py-2.5 text-sm font-medium italic text-stone-700 outline-none focus:ring-2 focus:ring-emerald-500" 
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest mb-2">Date du Semis</label>
                <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl px-4 py-2.5 text-sm font-bold" />
              </div>
            </div>

            <div className="bg-stone-50 p-4 rounded-2xl border border-stone-100 space-y-3">
              <span className="block text-[10px] font-black text-emerald-700 uppercase tracking-widest">Nouvelle Étape Manuelle</span>
              <div className="flex flex-col sm:flex-row gap-3">
                <input type="text" value={newStepDesc} onChange={(e) => setNewStepDesc(e.target.value)} placeholder="Description (ex: Apport Urée)" className="flex-1 bg-white border border-stone-200 rounded-xl px-4 py-2.5 text-sm" />
                <div className="flex gap-2 shrink-0">
                  <input type="date" value={newStepDate} onChange={(e) => setNewStepDate(e.target.value)} className="bg-white border border-stone-200 rounded-xl px-4 py-2.5 text-sm" />
                  <button onClick={addStep} className="bg-emerald-600 text-white px-4 rounded-xl hover:bg-emerald-700"><Plus size={20} /></button>
                </div>
              </div>
            </div>

            <div className="space-y-3">
              {steps.length > 0 ? (
                steps.sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).map((step) => {
                  const status = getStepStatus(step);
                  return (
                    <div key={step.id} className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                      step.completed ? 'bg-stone-50 border-stone-200 opacity-60' : 
                      status === 'overdue' ? 'bg-red-50 border-red-100 shadow-sm' :
                      status === 'upcoming' ? 'bg-amber-50 border-amber-100 shadow-sm' :
                      'bg-white border-stone-100 shadow-sm'
                    }`}>
                      <div className="flex items-center gap-4">
                        <button onClick={() => toggleStep(step.id)} className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${
                          step.completed ? 'bg-emerald-600 border-emerald-600 text-white' : 
                          status === 'overdue' ? 'border-red-300' :
                          'border-stone-200'
                        }`}>
                          {step.completed && <Check size={14} />}
                        </button>
                        <div>
                          <p className={`text-sm font-bold ${step.completed ? 'line-through text-stone-400' : 'text-stone-800'}`}>
                            {step.description}
                          </p>
                          <div className="flex items-center gap-2 mt-1">
                            <span className={`text-[10px] font-black uppercase flex items-center gap-1 ${
                              status === 'overdue' ? 'text-red-500' : 'text-stone-400'
                            }`}>
                              <Calendar size={10} /> {new Date(step.deadline).toLocaleDateString('fr-FR')}
                            </span>
                            {step.daysFromStart !== undefined && (
                              <span className="text-[10px] font-black bg-stone-100 text-stone-500 px-1.5 py-0.5 rounded uppercase">
                                J+{step.daysFromStart}
                              </span>
                            )}
                            {status === 'overdue' && !step.completed && (
                              <span className="text-[9px] font-black bg-red-600 text-white px-1.5 py-0.5 rounded uppercase animate-pulse">
                                En retard
                              </span>
                            )}
                            {status === 'upcoming' && !step.completed && (
                              <span className="text-[9px] font-black bg-amber-500 text-white px-1.5 py-0.5 rounded uppercase">
                                Urgent
                              </span>
                            )}
                          </div>
                        </div>
                      </div>
                      <button onClick={() => removeStep(step.id)} className="text-stone-300 hover:text-red-500 transition-colors">
                        <Trash2 size={16} />
                      </button>
                    </div>
                  );
                })
              ) : (
                <div className="py-12 text-center border-2 border-dashed border-stone-100 rounded-3xl">
                  <ClipboardList className="mx-auto text-stone-100 mb-2" size={32} />
                  <p className="text-xs text-stone-400 font-bold uppercase tracking-widest">Aucun itinéraire planifié</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <p className="text-[9px] text-center text-stone-400 font-bold uppercase tracking-widest opacity-60">Utilisez les suggestions de l'IA comme base de travail.</p>
    </div>
  );
};

export default AgroExpert;

