import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Camera, Sparkles, Loader2, Image as ImageIcon, X, RotateCcw, Copy, Check, Calendar, Plus, Trash2, ClipboardList, User, Wand2, AlertCircle, BellRing, WifiOff, Wifi } from 'lucide-react';
import { getAgroAdvice, diagnosePlant, generateCropItinerary } from '../services/geminiService';

interface Message {
  role: 'user' | 'bot';
  text: string;
  image?: string;
}

interface ItineraryStep {
  id: string;
  description: string;
  deadline: string;
  completed: boolean;
  daysFromStart?: number;
}

const STORAGE_KEYS = {
  CHAT: 'agroexpert_chat_history',
  ITINERARY: 'agroexpert_itinerary_data',
  AVATAR: 'agroexpert_user_avatar'
};

const AgroExpert: React.FC = () => {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [input, setInput] = useState('');

  // Initialize states from localStorage
  const [messages, setMessages] = useState<Message[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CHAT);
    return saved ? JSON.parse(saved) : [
      { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
    ];
  });

  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  // Profile states
  const [userAvatar, setUserAvatar] = useState<string | null>(() => {
    return localStorage.getItem(STORAGE_KEYS.AVATAR);
  });
  const avatarInputRef = useRef<HTMLInputElement>(null);

  // Itinerary states
  const [itineraryData, setItineraryData] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ITINERARY);
    return saved ? JSON.parse(saved) : {
      cropName: '',
      scientificName: '',
      startDate: new Date().toISOString().split('T')[0],
      steps: [] as ItineraryStep[]
    };
  });

  const [cropName, setCropName] = useState(itineraryData.cropName);
  const [scientificName, setScientificName] = useState(itineraryData.scientificName);
  const [startDate, setStartDate] = useState(itineraryData.startDate);
  const [steps, setSteps] = useState<ItineraryStep[]>(itineraryData.steps);

  const [newStepDesc, setNewStepDesc] = useState('');
  const [newStepDate, setNewStepDate] = useState('');
  const [isItineraryOpen, setIsItineraryOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Connection listeners
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Save states to localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.CHAT, JSON.stringify(messages));
  }, [messages]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AVATAR, userAvatar || '');
  }, [userAvatar]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.ITINERARY, JSON.stringify({
      cropName,
      scientificName,
      startDate,
      steps
    }));
  }, [cropName, scientificName, startDate, steps]);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    if (!isOnline) {
      alert("Vous êtes hors ligne. La connexion est nécessaire pour utiliser l'IA.");
      return;
    }

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const botResponse = await getAgroAdvice(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setLoading(false);
  };

  const handleReset = () => {
    if (window.confirm("Voulez-vous vraiment effacer toute la conversation ?")) {
      const initialMessage: Message[] = [
        { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
      ];
      setMessages(initialMessage);
      localStorage.removeItem(STORAGE_KEYS.CHAT);
    }
  };

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedIndex(index);
      setTimeout(() => setCopiedIndex(null), 2000);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (!isOnline) {
      alert("La connexion est nécessaire pour le diagnostic d'image.");
      return;
    }

    const reader = new FileReader();
    reader.onloadstart = () => setLoading(true);

    reader.onloadend = async () => {
      const dataUrl = reader.result as string;
      const base64 = dataUrl.split(',')[1];

      setMessages(prev => [...prev, { 
        role: 'user', 
        text: "Pouvez-vous diagnostiquer cette plante ?", 
        image: dataUrl 
      }]);

      try {
        const diagnosis = await diagnosePlant(base64);
        setMessages(prev => [...prev, { role: 'bot', text: diagnosis }]);
      } catch (error) {
        setMessages(prev => [...prev, { role: 'bot', text: "Erreur lors du diagnostic." }]);
      } finally {
        setLoading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUserAvatar(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  // Itinerary functions
  const addStep = () => {
    if (!newStepDesc || !newStepDate) return;
    const newStep: ItineraryStep = {
      id: Date.now().toString(),
      description: newStepDesc,
      deadline: newStepDate,
      completed: false,
    };
    setSteps([...steps, newStep]);
    setNewStepDesc('');
    setNewStepDate('');
  };

  const handleAiSuggest = async () => {
    if (!cropName) {
      alert("Veuillez d'abord saisir le nom de la culture.");
      return;
    }
    if (!isOnline) {
      alert("La connexion est nécessaire pour générer un itinéraire via l'IA.");
      return;
    }
    setSuggesting(true);
    const suggestedSteps = await generateCropItinerary(cropName);
    if (suggestedSteps) {
      const start = new Date(startDate);
      const newSteps: ItineraryStep[] = suggestedSteps.map((s: any, idx: number) => {
        const deadlineDate = new Date(start);
        deadlineDate.setDate(start.getDate() + s.daysFromStart);
        return {
          id: `ai-${Date.now()}-${idx}`,
          description: s.description,
          deadline: deadlineDate.toISOString().split('T')[0],
          completed: false,
          daysFromStart: s.daysFromStart
        };
      });
      setSteps(newSteps);
    }
    setSuggesting(false);
  };

  const removeStep = (id: string) => {
    setSteps(steps.filter(s => s.id !== id));
  };

  const toggleStep = (id: string) => {
    setSteps(steps.map(s => s.id === id ? { ...s, completed: !s.completed } : s));
  };

  const getStepStatus = (step: ItineraryStep) => {
    if (step.completed) return 'completed';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const deadlineDate = new Date(step.deadline);
    deadlineDate.setHours(0, 0, 0, 0);

    if (deadlineDate < today) return 'overdue';
    const diffTime = deadlineDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    if (diffDays <= 3) return 'upcoming';
    return 'pending';
  };

  // Notifications calculation
  const { overdueCount, upcomingCount } = useMemo(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    let overdue = 0;
    let upcoming = 0;

    steps.forEach(step => {
      if (!step.completed) {
        const deadlineDate = new Date(step.deadline);
        deadlineDate.setHours(0, 0, 0, 0);

        if (deadlineDate < today) {
          overdue++;
        } else {
          const diffTime = deadlineDate.getTime() - today.getTime();
          const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
          if (diffDays <= 3) {
            upcoming++;
          }
        }
      }
    });

    return { overdueCount: overdue, upcomingCount: upcoming };
  }, [steps]);

  return (
    <div className="flex flex-col space-y-4">
      {/* Profile Photo Section & Connection Status */}
      <div className="bg-white rounded-[2rem] p-4 border border-stone-200 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="relative group cursor-pointer" onClick={() => avatarInputRef.current?.click()}>
            <div className="w-[40px] h-[40px] rounded-full overflow-hidden border-2 border-emerald-100 flex items-center justify-center bg-stone-100">
              {userAvatar ? (
                <img src={userAvatar} alt="Profile" className="w-full h-full object-cover" />
              ) : (
                <User size={20} className="text-stone-400" />
              )}
            </div>
            <div className="absolute inset-0 bg-black/40 rounded-full opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
              <Camera size={12} className="text-white" />
            </div>
            <input type="file" ref={avatarInputRef} className="hidden" accept="image/*" onChange={handleAvatarUpload} />
          </div>
          <div>
            <h4 className="text-sm font-bold text-stone-900 leading-tight">Mon Profil</h4>
            <div className="flex items-center gap-1.5 mt-0.5">
              {isOnline ? (
                <span className="flex items-center gap-1 text-[9px] font-black uppercase tracking-widest text-emerald-600">
                  <Wifi size={10} /> Connecté
                </span>
              ) : (
                <span className="flex items-center gap-1 text-[9px] font-black uppercase tracking-widest text-amber-600">
                  <WifiOff size={10} /> Hors ligne
                </span>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Chat Container */}
      <div className="flex flex-col h-[60vh] bg-white rounded-[2rem] shadow-sm border border-stone-200 overflow-hidden">
        <div className="bg-emerald-600 px-6 py-4 text-white flex items-center justify-between shadow-lg relative z-10">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl"><Sparkles size={20} /></div>
            <div>
              <span className="font-bold block leading-tight">IA Agro Expert</span>
              <span className="text-[10px] uppercase font-black tracking-widest opacity-80">Conseil & Diagnostic</span>
            </div>
          </div>
          <button onClick={handleReset} className="p-2 hover:bg-white/10 rounded-xl transition-colors"><RotateCcw size={20} /></button>
        </div>

        {!isOnline && (
          <div className="bg-amber-50 border-b border-amber-100 px-4 py-2 flex items-center gap-2">
            <WifiOff size={14} className="text-amber-600" />
            <span className="text-[10px] font-bold text-amber-700 uppercase tracking-widest">
              Mode consultation uniquement (Hors ligne)
            </span>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-stone-50/50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
              <div className="flex flex-col gap-1 items-end">
                <div className={`max-w-[85%] overflow-hidden relative group ${
                  m.role === 'user' ? 'bg-emerald-600 text-white rounded-3xl rounded-tr-none shadow-md' : 'bg-white border border-stone-200 text-stone-800 rounded-3xl rounded-tl-none shadow-sm'
                }`}>
                  {m.role === 'bot' && (
                    <button onClick={() => handleCopy(m.text, i)} className="absolute top-2 right-2 p-1.5 rounded-lg bg-stone-100/50 text-stone-400 opacity-0 group-hover:opacity-100 transition-opacity">
                      {copiedIndex === i ? <Check size={14} /> : <Copy size={14} />}
                    </button>
                  )}
                  {m.image && <div className="p-1"><img src={m.image} className="w-full max-h-64 object-cover rounded-2xl" /></div>}
                  <div className="p-4 pr-10"><p className="text-sm whitespace-pre-wrap leading-relaxed">{m.text}</p></div>
                </div>
                {m.role === 'user' && userAvatar && (
                  <div className="w-[24px] h-[24px] rounded-full overflow-hidden border border-emerald-200 mr-2 mt-[-10px] z-20 shadow-sm bg-white">
                    <img src={userAvatar} className="w-full h-full object-cover" />
                  </div>
                )}
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex justify-start animate-pulse">
              <div className="bg-white border border-stone-200 p-4 rounded-3xl rounded-tl-none shadow-sm flex items-center gap-3">
                <div className="flex gap-1"><span className="w-1.5 h-1.5 bg-emerald-600 rounded-full animate-bounce"></span></div>
                <span className="text-xs font-bold text-stone-400 uppercase tracking-widest italic">Analyse...</span>
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        <div className="p-4 border-t border-stone-100 bg-white">
          <div className="flex items-center gap-2">
            <button 
              onClick={() => fileInputRef.current?.click()} 
              disabled={!isOnline}
              className={`p-3 rounded-2xl transition-all ${isOnline ? 'text-emerald-600 hover:bg-emerald-50' : 'text-stone-300'}`}
            >
              <ImageIcon size={22} />
            </button>
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept="image/*" className="hidden" />
            <input 
              type="text" 
              value={input} 
              onChange={(e) => setInput(e.target.value)} 
              onKeyPress={(e) => e.key === 'Enter' && handleSend()} 
              placeholder={isOnline ? "Une question ?" : "Connexion requise pour l'IA..."}
              disabled={!isOnline}
              className="flex-1 bg-stone-100 border-none rounded-2xl px-5 py-3.5 text-sm outline-none disabled:opacity-50" 
            />
            <button 
              onClick={handleSend} 
              disabled={!input.trim() || loading || !isOnline} 
              className="p-3.5 bg-emerald-600 text-white rounded-2xl shadow-lg disabled:bg-stone-200 disabled:shadow-none transition-all active:scale-95"
            >
              <Send size={20} />
            </button>
          </div>
        </div>
      </div>

      {/* Technical Itinerary Section */}
      <div className="bg-white rounded-[2rem] border border-stone-200 overflow-hidden shadow-sm">
        <button onClick={() => setIsItineraryOpen(!isItineraryOpen)} className="w-full flex items-center justify-between p-6 hover:bg-stone-50 transition-colors">
          <div className="flex items-center gap-3">
            <div className="bg-amber-100 p-2.5 rounded-xl text-amber-600 relative">
              <ClipboardList size={22} />
              {(overdueCount > 0 || upcomingCount > 0) && (
                <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 border-2 border-white rounded-full animate-pulse"></span>
              )}
            </div>
            <div className="text-left">
              <h3 className="font-bold text-stone-900 leading-tight">Itinéraire Technique</h3>
              <p className="text-[10px] uppercase font-black tracking-widest text-stone-400">
                {overdueCount > 0 ? `${overdueCount} en retard` : 'Planifier mes récoltes'}
              </p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            {overdueCount > 0 && (
              <span className="px-2 py-0.5 bg-red-100 text-red-600 text-[10px] font-black rounded-full uppercase tracking-widest">
                Attention
              </span>
            )}
            <Plus size={20} className={`transition-transform duration-300 text-stone-400 ${isItineraryOpen ? 'rotate-45' : ''}`} />
          </div>
        </button>

        {isItineraryOpen && (
          <div className="p-6 border-t border-stone-100 space-y-6 animate-in slide-in-from-top-4 duration-300">
            {/* Notification Summary */}
            {(overdueCount > 0 || upcomingCount > 0) && (
              <div className="flex flex-col gap-2">
                {overdueCount > 0 && (
                  <div className="bg-red-50 border border-red-100 rounded-2xl p-3 flex items-center gap-3 text-red-700">
                    <AlertCircle size={18} />
                    <span className="text-xs font-bold">Attention : {overdueCount} {overdueCount > 1 ? 'étapes sont' : 'étape est'} en retard !</span>
                  </div>
                )}
                {upcomingCount > 0 && (
                  <div className="bg-amber-50 border border-amber-100 rounded-2xl p-3 flex items-center gap-3 text-amber-700">
                    <BellRing size={18} className="animate-bounce" />
                    <span className="text-xs font-bold">{upcomingCount} {upcomingCount > 1 ? 'étapes approchent' : 'étape approche'} (J-3).</span>
                  </div>
                )}
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <div>
                <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest mb-2">Culture</label>
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={cropName} 
                    onChange={(e) => setCropName(e.target.value)} 
                    placeholder="Ex: Maïs" 
                    className="flex-1 bg-stone-50 border border-stone-100 rounded-xl px-4 py-2.5 text-sm font-bold" 
                  />
                  <button 
                    onClick={handleAiSuggest} 
                    disabled={suggesting || !cropName || !isOnline} 
                    title={isOnline ? "Suggérer via l'IA" : "IA indisponible hors ligne"}
                    className="p-2.5 bg-amber-500 text-white rounded-xl hover:bg-amber-600 disabled:opacity-50 flex items-center gap-2 transition-all active:scale-95 shadow-lg shadow-amber-100"
                  >
                    {suggesting ? <Loader2 size={18} className="animate-spin" /> : <Wand2 size={18} />}
                    <span className="text-xs font-bold hidden sm:inline">IA</span>
                  </button>
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest mb-2">Nom Scientifique</label>
                <input 
                  type="text" 
                  value={scientificName} 
                  onChange={(e) => setScientificName(e.target.value)} 
                  placeholder="Ex: Zea mays" 
                  className="w-full bg-stone-50 border border-stone-100 rounded-xl px-4 py-2.5 text-sm font-medium italic text-stone-700 outline-none focus:ring-2 focus:ring-emerald-500" 
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest mb-2">Date du Semis</label>
                <input 
                  type="date" 
                  value={startDate} 
                  onChange={(e) => setStartDate(e.target.value)} 
                  className="w-full bg-stone-50 border border-stone-100 rounded-xl px-4 py-2.5 text-sm font-bold" 
                />
              </div>
            </div>

            <div className="bg-stone-50 p-4 rounded-2xl border border-stone-100 space-y-3">
              <span className="block text-[10px] font-black text-emerald-700 uppercase tracking-widest">Nouvelle Étape Manuelle</span>
              <div className="flex flex-col sm:flex-row gap-3">
                <input 
                  type="text" 
                  value={newStepDesc} 
                  onChange={(e) => setNewStepDesc(e.target.value)} 
                  placeholder="Description (ex: Apport Urée)" 
                  className="flex-1 bg-white border border-stone-200 rounded-xl px-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-emerald-500" 
                />
                <div className="flex gap-2 shrink-0">
                  <input 
                    type="date" 
                    value={newStepDate} 
                    onChange={(e) => setNewStepDate(e.target.value)} 
                    className="bg-white border border-stone-200 rounded-xl px-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-emerald-500" 
                  />
                  <button 
                    onClick={addStep} 
                    className="bg-emerald-600 text-white px-4 rounded-xl hover:bg-emerald-700 transition-all active:scale-95 shadow-md"
                  >
                    <Plus size={20} />
                  </button>
                </div>
              </div>
            </div>

            <div className="space-y-3">
              {steps.length > 0 ? (
                steps.sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).map((step) => {
                  const status = getStepStatus(step);
                  return (
                    <div key={step.id} className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                      step.completed ? 'bg-stone-50 border-stone-200 opacity-60' : 
                      status === 'overdue' ? 'bg-red-50 border-red-100 shadow-sm' :
                      status === 'upcoming' ? 'bg-amber-50 border-amber-100 shadow-sm' :
                      'bg-white border-stone-100 shadow-sm'
                    }`}>
                      <div className="flex items-center gap-4">
                        <button onClick={() => toggleStep(step.id)} className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${
                          step.completed ? 'bg-emerald-600 border-emerald-600 text-white' : 
                          status === 'overdue' ? 'border-red-300' :
                          'border-stone-200'
                        }`}>
                          {step.completed && <Check size={14} />}
                        </button>
                        <div>
                          <p className={`text-sm font-bold ${step.completed ? 'line-through text-stone-400' : 'text-stone-800'}`}>
                            {step.description}
                          </p>
                          <div className="flex items-center gap-2 mt-1">
                            <span className={`text-[10px] font-black uppercase flex items-center gap-1 ${
                              status === 'overdue' ? 'text-red-500' : 'text-stone-400'
                            }`}>
                              <Calendar size={10} /> {new Date(step.deadline).toLocaleDateString('fr-FR')}
                            </span>
                            {step.daysFromStart !== undefined && (
                              <span className="text-[10px] font-black bg-stone-100 text-stone-500 px-1.5 py-0.5 rounded uppercase">
                                J+{step.daysFromStart}
                              </span>
                            )}
                            {status === 'overdue' && !step.completed && (
                              <span className="text-[9px] font-black bg-red-600 text-white px-1.5 py-0.5 rounded uppercase animate-pulse">
                                En retard
                              </span>
                            )}
                            {status === 'upcoming' && !step.completed && (
                              <span className="text-[9px] font-black bg-amber-500 text-white px-1.5 py-0.5 rounded uppercase">
                                Urgent
                              </span>
                            )}
                          </div>
                        </div>
                      </div>
                      <button onClick={() => removeStep(step.id)} className="text-stone-300 hover:text-red-500 transition-colors">
                        <Trash2 size={16} />
                      </button>
                    </div>
                  );
                })
              ) : (
                <div className="py-12 text-center border-2 border-dashed border-stone-100 rounded-3xl">
                  <ClipboardList className="mx-auto text-stone-100 mb-2" size={32} />
                  <p className="text-xs text-stone-400 font-bold uppercase tracking-widest">Aucun itinéraire planifié</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <p className="text-[9px] text-center text-stone-400 font-bold uppercase tracking-widest opacity-60">
        Vos données sont sauvegardées localement. L'IA nécessite une connexion active.
      </p>
    </div>
  );
};

export default AgroExpert;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Camera, Sparkles, Loader2, Image as ImageIcon, X, RotateCcw, Copy, Check, Calendar, Plus, Trash2, ClipboardList, User, Wand2, AlertCircle, BellRing, WifiOff, Wifi, Save, Share2 } from 'lucide-react';
import { getAgroAdvice, diagnosePlant, generateCropItinerary } from '../services/geminiService';

interface Message {
  role: 'user' | 'bot';
  text: string;
  image?: string;
}

interface ItineraryStep {
  id: string;
  description: string;
  deadline: string;
  completed: boolean;
  daysFromStart?: number;
}

const STORAGE_KEYS = {
  CHAT: 'agroexpert_chat_history',
  ITINERARY: 'agroexpert_itinerary_data',
  AVATAR: 'agroexpert_user_avatar'
};

const AgroExpert: React.FC = () => {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [input, setInput] = useState('');
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Initialize states from localStorage
  const [messages, setMessages] = useState<Message[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CHAT);
    return saved ? JSON.parse(saved) : [
      { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
    ];
  });

  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);
  const [showShareSuccess, setShowShareSuccess] = useState(false);

  // Profile states
  const [userAvatar, setUserAvatar] = useState<string | null>(() => {
    return localStorage.getItem(STORAGE_KEYS.AVATAR);
  });
  const avatarInputRef = useRef<HTMLInputElement>(null);

  // Itinerary states
  const [itineraryData, setItineraryData] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ITINERARY);
    return saved ? JSON.parse(saved) : {
      cropName: '',
      scientificName: '',
      startDate: new Date().toISOString().split('T')[0],
      steps: [] as ItineraryStep[]
    };
  });

  const [cropName, setCropName] = useState(itineraryData.cropName);
  const [scientificName, setScientificName] = useState(itineraryData.scientificName);
  const [startDate, setStartDate] = useState(itineraryData.startDate);
  const [steps, setSteps] = useState<ItineraryStep[]>(itineraryData.steps);

  const [newStepDesc, setNewStepDesc] = useState('');
  const [newStepDate, setNewStepDate] = useState('');
  const [isItineraryOpen, setIsItineraryOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Connection listeners
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Sync state and Save to localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.CHAT, JSON.stringify(messages));
    setLastSaved(new Date());
  }, [messages]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AVATAR, userAvatar || '');
  }, [userAvatar]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.ITINERARY, JSON.stringify({
      cropName,
      scientificName,
      startDate,
      steps
    }));
    setLastSaved(new Date());
  }, [cropName, scientificName, startDate, steps]);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    if (!isOnline) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const botResponse = await getAgroAdvice(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setLoading(false);
  };

  const handleReset = () => {
    if (window.confirm("Effacer l'historique ? (Les données de l'itinéraire seront conservées)")) {
      const initialMessage: Message[] = [
        { role: 'bot', text: 'Historique effacé. Comment puis-je vous aider ?' }
      ];
      setMessages(initialMessage);
    }
  };

  const copyItineraryToClipboard = () => {
    if (steps.length === 0) return;

    let text = `📋 ITINÉRAIRE TECHNIQUE : ${cropName.toUpperCase()}\n`;
    if (scientificName) text += `🧬 Nom Scientifique : ${scientificName}\n`;
    text += `📅 Date de début : ${new Date(startDate).toLocaleDateString('fr-FR')}\n\n`;
    text += `ÉTAPES PRÉVUES :\n`;

    steps.sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).forEach((s, i) => {
      text += `${i + 1}. [${new Date(s.deadline).toLocaleDateString('fr-FR')}] ${s.description}${s.completed ? ' ✅' : ''}\n`;
    });

    text += `\nExporté depuis AgroExpert Afrique`;

    navigator.clipboard.writeText(text).then(() => {
      setShowShareSuccess(true);
      setTimeout(() => setShowShareSuccess(null), 3000);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !isOnline) return;

    const reader = new FileReader();
    reader.onloadstart = () => setLoading(true);
    reader.onloadend = async () => {
      const dataUrl = reader.result as string;
      const base64 = dataUrl.split(',')[1];
      setMessages(prev => [...prev, { role: 'user', text: "Diagnostic photo en cours...", image: dataUrl }]);
      const diagnosis = await diagnosePlant(base64);
      setMessages(prev => [...prev, { role: 'bot', text: diagnosis }]);
      setLoading(false);
    };
    reader.readAsDataURL(file);
  };

  const addStep = () => {
    if (!newStepDesc || !newStepDate) return;
    const newStep: ItineraryStep = {
      id: Date.now().toString(),
      description: newStepDesc,
      deadline: newStepDate,
      completed: false,
    };
    setSteps([...steps, newStep]);
    setNewStepDesc('');
    setNewStepDate('');
  };

  const handleAiSuggest = async () => {
    if (!cropName || !isOnline) return;
    setSuggesting(true);
    const suggestedSteps = await generateCropItinerary(cropName);
    if (suggestedSteps) {
      const start = new Date(startDate);
      const newSteps: ItineraryStep[] = suggestedSteps.map((s: any, idx: number) => {
        const deadlineDate = new Date(start);
        deadlineDate.setDate(start.getDate() + s.daysFromStart);
        return {
          id: `ai-${Date.now()}-${idx}`,
          description: s.description,
          deadline: deadlineDate.toISOString().split('T')[0],
          completed: false,
          daysFromStart: s.daysFromStart
        };
      });
      setSteps(newSteps);
    }
    setSuggesting(false);
  };

  const toggleStep = (id: string) => {
    setSteps(steps.map(s => s.id === id ? { ...s, completed: !s.completed } : s));
  };

  const removeStep = (id: string) => {
    setSteps(steps.filter(s => s.id !== id));
  };

  const getStepStatus = (step: ItineraryStep) => {
    if (step.completed) return 'completed';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const deadlineDate = new Date(step.deadline);
    if (deadlineDate < today) return 'overdue';
    const diffDays = Math.ceil((deadlineDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    return diffDays <= 3 ? 'upcoming' : 'pending';
  };

  const counts = useMemo(() => {
    const today = new Date();
    today.setHours(0,0,0,0);
    return steps.reduce((acc, s) => {
      if (!s.completed) {
        const d = new Date(s.deadline);
        if (d < today) acc.overdue++;
        else if (Math.ceil((d.getTime() - today.getTime())/(86400000)) <= 3) acc.upcoming++;
      }
      return acc;
    }, { overdue: 0, upcoming: 0 });
  }, [steps]);

  return (
    <div className="flex flex-col space-y-4">
      {/* Header Statut & Profil */}
      <div className="bg-white rounded-[2rem] p-4 border border-stone-200 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="relative group cursor-pointer" onClick={() => avatarInputRef.current?.click()}>
            <div className="w-[42px] h-[42px] rounded-full overflow-hidden border-2 border-emerald-100 flex items-center justify-center bg-stone-100 shadow-inner">
              {userAvatar ? <img src={userAvatar} className="w-full h-full object-cover" /> : <User size={20} className="text-stone-400" />}
            </div>
            <input type="file" ref={avatarInputRef} className="hidden" accept="image/*" onChange={(e) => {
               const file = e.target.files?.[0];
               if (file) {
                 const reader = new FileReader();
                 reader.onloadend = () => setUserAvatar(reader.result as string);
                 reader.readAsDataURL(file);
               }
            }} />
          </div>
          <div>
            <h4 className="text-sm font-bold text-stone-900 leading-tight">Mon Espace Agricole</h4>
            <div className="flex items-center gap-2 mt-0.5">
              <span className={`flex items-center gap-1 text-[9px] font-black uppercase tracking-widest ${isOnline ? 'text-emerald-600' : 'text-amber-600'}`}>
                {isOnline ? <Wifi size={10} /> : <WifiOff size={10} />}
                {isOnline ? 'En ligne' : 'Hors ligne (Local)'}
              </span>
              {lastSaved && (
                <span className="text-[8px] text-stone-300 font-bold uppercase flex items-center gap-1">
                  <Save size={8} /> {lastSaved.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                </span>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Chat IA */}
      <div className="flex flex-col h-[55vh] bg-white rounded-[2rem] shadow-sm border border-stone-200 overflow-hidden relative">
        <div className="bg-emerald-600 px-6 py-4 text-white flex items-center justify-between shadow-lg relative z-10">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl"><Sparkles size={20} /></div>
            <div>
              <span className="font-bold block leading-tight">Assistant IA</span>
              <span className="text-[10px] uppercase font-black tracking-widest opacity-80 italic">Contextualisé Afrique</span>
            </div>
          </div>
          <button onClick={handleReset} className="p-2 hover:bg-white/10 rounded-xl transition-colors"><RotateCcw size={18} /></button>
        </div>

        {!isOnline && (
          <div className="bg-amber-50 px-4 py-2 border-b border-amber-100 flex items-center gap-2 animate-pulse">
            <AlertCircle size={14} className="text-amber-600" />
            <span className="text-[9px] font-black text-amber-700 uppercase tracking-widest">Connexion perdue. IA indisponible.</span>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-stone-50/50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
               <div className={`max-w-[85%] rounded-3xl p-4 shadow-sm ${
                 m.role === 'user' ? 'bg-emerald-600 text-white rounded-tr-none' : 'bg-white border border-stone-200 text-stone-800 rounded-tl-none'
               }`}>
                 {m.image && <img src={m.image} className="rounded-xl mb-2 max-h-48 w-full object-cover" />}
                 <p className="text-sm leading-relaxed">{m.text}</p>
               </div>
            </div>
          ))}
          {loading && <div className="flex gap-2 p-2"><Loader2 size={16} className="animate-spin text-emerald-600" /><span className="text-xs italic text-stone-400">L'IA réfléchit...</span></div>}
          <div ref={chatEndRef} />
        </div>

        <div className="p-4 bg-white border-t border-stone-100">
           <div className="flex items-center gap-2">
             <button onClick={() => fileInputRef.current?.click()} disabled={!isOnline} className={`p-3 rounded-2xl ${isOnline ? 'text-emerald-600 hover:bg-emerald-50' : 'text-stone-300 cursor-not-allowed'}`}><ImageIcon size={20} /></button>
             <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
             <input value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleSend()} disabled={!isOnline} placeholder={isOnline ? "Votre question..." : "Reconnectez-vous pour parler à l'IA"} className="flex-1 bg-stone-100 rounded-2xl px-4 py-3 text-sm outline-none disabled:opacity-50" />
             <button onClick={handleSend} disabled={!isOnline || !input.trim()} className="p-3.5 bg-emerald-600 text-white rounded-2xl shadow-lg disabled:bg-stone-200 transition-all active:scale-95"><Send size={18} /></button>
           </div>
        </div>
      </div>

      {/* Itinéraire Technique */}
      <div className="bg-white rounded-[2rem] border border-stone-200 shadow-sm overflow-hidden">
        <div className="p-6 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="bg-amber-100 p-2.5 rounded-xl text-amber-600 relative">
               <ClipboardList size={22} />
               {(counts.overdue > 0 || counts.upcoming > 0) && <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>}
             </div>
             <div>
               <h3 className="font-bold text-stone-900 leading-tight">Itinéraire Technique</h3>
               <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest">Disponible Hors Ligne</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             <button onClick={copyItineraryToClipboard} disabled={steps.length === 0} className={`p-2.5 rounded-xl transition-all ${showShareSuccess ? 'bg-emerald-500 text-white' : 'bg-stone-100 text-stone-500 hover:bg-stone-200'}`} title="Copier pour WhatsApp/SMS">
               {showShareSuccess ? <Check size={18} /> : <Share2 size={18} />}
             </button>
             <button onClick={() => setIsItineraryOpen(!isItineraryOpen)} className="p-2.5 bg-stone-100 text-stone-500 rounded-xl"><Plus size={18} className={`transition-transform ${isItineraryOpen ? 'rotate-45' : ''}`} /></button>
          </div>
        </div>

        {isItineraryOpen && (
          <div className="px-6 pb-6 space-y-6 animate-in slide-in-from-top-4">
             <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Culture</label>
                  <div className="flex gap-1">
                    <input value={cropName} onChange={e => setCropName(e.target.value)} placeholder="Ex: Mil" className="flex-1 bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                    <button onClick={handleAiSuggest} disabled={!isOnline || !cropName || suggesting} className="p-2.5 bg-amber-500 text-white rounded-xl disabled:opacity-50 transition-all active:scale-90 shadow-sm">
                      {suggesting ? <Loader2 size={16} className="animate-spin" /> : <Wand2 size={16} />}
                    </button>
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Nom Scientifique</label>
                  <input value={scientificName} onChange={e => setScientificName(e.target.value)} placeholder="Ex: Pennisetum glaucum" className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm italic font-medium" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Date du Semis</label>
                  <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                </div>
             </div>

             <div className="bg-emerald-50/50 p-4 rounded-2xl border border-emerald-100/50 space-y-3">
                <span className="text-[9px] font-black text-emerald-700 uppercase tracking-widest block">Ajouter une tâche manuelle</span>
                <div className="flex flex-col sm:flex-row gap-2">
                  <input value={newStepDesc} onChange={e => setNewStepDesc(e.target.value)} placeholder="Ex: Sarclage n°1" className="flex-1 bg-white border border-stone-200 rounded-xl px-4 py-2 text-sm outline-none focus:ring-1 focus:ring-emerald-500" />
                  <div className="flex gap-2">
                    <input type="date" value={newStepDate} onChange={e => setNewStepDate(e.target.value)} className="bg-white border border-stone-200 rounded-xl px-3 py-2 text-xs font-bold" />
                    <button onClick={addStep} className="bg-emerald-600 text-white px-4 rounded-xl shadow-sm"><Plus size={18} /></button>
                  </div>
                </div>
             </div>

             <div className="space-y-3">
                {steps.length > 0 ? (
                  steps.sort((a,b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).map(step => {
                    const status = getStepStatus(step);
                    return (
                      <div key={step.id} className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                        step.completed ? 'bg-stone-50 border-stone-100 opacity-60' :
                        status === 'overdue' ? 'bg-red-50 border-red-100' :
                        status === 'upcoming' ? 'bg-amber-50 border-amber-100' : 'bg-white border-stone-100'
                      }`}>
                        <div className="flex items-center gap-4">
                           <button onClick={() => toggleStep(step.id)} className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${step.completed ? 'bg-emerald-600 border-emerald-600 text-white' : 'border-stone-300 bg-white'}`}>
                             {step.completed && <Check size={14} />}
                           </button>
                           <div>
                              <p className={`text-sm font-bold ${step.completed ? 'line-through text-stone-400' : 'text-stone-800'}`}>{step.description}</p>
                              <div className="flex items-center gap-2 mt-0.5">
                                 <span className={`text-[10px] font-bold flex items-center gap-1 uppercase ${status === 'overdue' ? 'text-red-500' : 'text-stone-400'}`}>
                                   <Calendar size={10} /> {new Date(step.deadline).toLocaleDateString('fr-FR')}
                                 </span>
                                 {status === 'overdue' && !step.completed && <span className="text-[8px] font-black bg-red-600 text-white px-1.5 py-0.5 rounded uppercase animate-pulse">Retard</span>}
                                 {status === 'upcoming' && !step.completed && <span className="text-[8px] font-black bg-amber-500 text-white px-1.5 py-0.5 rounded uppercase">Urgent</span>}
                              </div>
                           </div>
                        </div>
                        <button onClick={() => removeStep(step.id)} className="text-stone-300 hover:text-red-500 p-1"><Trash2 size={16} /></button>
                      </div>
                    );
                  })
                ) : (
                  <div className="py-12 text-center border-2 border-dashed border-stone-100 rounded-3xl">
                     <ClipboardList className="mx-auto text-stone-200 mb-2" size={32} />
                     <p className="text-xs text-stone-400 font-bold uppercase tracking-widest">Aucun plan enregistré localement</p>
                  </div>
                )}
             </div>
          </div>
        )}
      </div>

      <p className="text-[8px] text-center text-stone-300 font-bold uppercase tracking-[0.2em] py-2">
        AgroExpert Afrique • Sécurité & Sauvegarde Locale Active
      </p>
    </div>
  );
};

export default AgroExpert;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Camera, Sparkles, Loader2, Image as ImageIcon, X, RotateCcw, Copy, Check, Calendar, Plus, Trash2, ClipboardList, User, Wand2, AlertCircle, BellRing, WifiOff, Wifi, Save, Share2, Mail, Link } from 'lucide-react';
import { getAgroAdvice, diagnosePlant, generateCropItinerary } from '../services/geminiService';

interface Message {
  role: 'user' | 'bot';
  text: string;
  image?: string;
}

interface ItineraryStep {
  id: string;
  description: string;
  deadline: string;
  completed: boolean;
  daysFromStart?: number;
}

const STORAGE_KEYS = {
  CHAT: 'agroexpert_chat_history',
  ITINERARY: 'agroexpert_itinerary_data',
  AVATAR: 'agroexpert_user_avatar'
};

const AgroExpert: React.FC = () => {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [input, setInput] = useState('');
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Initialize states from localStorage
  const [messages, setMessages] = useState<Message[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CHAT);
    return saved ? JSON.parse(saved) : [
      { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
    ];
  });

  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);
  const [showShareSuccess, setShowShareSuccess] = useState<string | null>(null);

  // Profile states
  const [userAvatar, setUserAvatar] = useState<string | null>(() => {
    return localStorage.getItem(STORAGE_KEYS.AVATAR);
  });
  const avatarInputRef = useRef<HTMLInputElement>(null);

  // Itinerary states
  const [itineraryData, setItineraryData] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ITINERARY);
    return saved ? JSON.parse(saved) : {
      cropName: '',
      scientificName: '',
      startDate: new Date().toISOString().split('T')[0],
      steps: [] as ItineraryStep[]
    };
  });

  const [cropName, setCropName] = useState(itineraryData.cropName);
  const [scientificName, setScientificName] = useState(itineraryData.scientificName);
  const [startDate, setStartDate] = useState(itineraryData.startDate);
  const [steps, setSteps] = useState<ItineraryStep[]>(itineraryData.steps);

  const [newStepDesc, setNewStepDesc] = useState('');
  const [newStepDate, setNewStepDate] = useState('');
  const [isItineraryOpen, setIsItineraryOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Connection listeners
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Sync state and Save to localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.CHAT, JSON.stringify(messages));
    setLastSaved(new Date());
  }, [messages]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AVATAR, userAvatar || '');
  }, [userAvatar]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.ITINERARY, JSON.stringify({
      cropName,
      scientificName,
      startDate,
      steps
    }));
    setLastSaved(new Date());
  }, [cropName, scientificName, startDate, steps]);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    if (!isOnline) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const botResponse = await getAgroAdvice(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setLoading(false);
  };

  const handleReset = () => {
    if (window.confirm("Effacer l'historique ? (Les données de l'itinéraire seront conservées)")) {
      const initialMessage: Message[] = [
        { role: 'bot', text: 'Historique effacé. Comment puis-je vous aider ?' }
      ];
      setMessages(initialMessage);
    }
  };

  const getItineraryAsText = () => {
    let text = `📋 ITINÉRAIRE TECHNIQUE : ${cropName.toUpperCase() || 'Sans titre'}\n`;
    if (scientificName) text += `🧬 Nom Scientifique : ${scientificName}\n`;
    text += `📅 Date de début : ${new Date(startDate).toLocaleDateString('fr-FR')}\n\n`;
    text += `ÉTAPES PRÉVUES :\n`;

    steps.slice().sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).forEach((s, i) => {
      text += `${i + 1}. [${new Date(s.deadline).toLocaleDateString('fr-FR')}] ${s.description}${s.completed ? ' ✅' : ''}\n`;
    });

    text += `\nExporté depuis AgroExpert Afrique`;
    return text;
  };

  const copyItineraryToClipboard = () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    navigator.clipboard.writeText(text).then(() => {
      setShowShareSuccess('copy');
      setTimeout(() => setShowShareSuccess(null), 3000);
    });
  };

  const shareViaEmail = () => {
    if (steps.length === 0) return;
    const subject = encodeURIComponent(`Mon Itinéraire Technique : ${cropName}`);
    const body = encodeURIComponent(getItineraryAsText());
    window.location.href = `mailto:?subject=${subject}&body=${body}`;
    setShowShareSuccess('email');
    setTimeout(() => setShowShareSuccess(null), 3000);
  };

  const shareViaNative = async () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Itinéraire ${cropName}`,
          text: text,
        });
        setShowShareSuccess('share');
        setTimeout(() => setShowShareSuccess(null), 3000);
      } catch (err) {
        copyItineraryToClipboard();
      }
    } else {
      copyItineraryToClipboard();
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !isOnline) return;

    const reader = new FileReader();
    reader.onloadstart = () => setLoading(true);
    reader.onloadend = async () => {
      const dataUrl = reader.result as string;
      const base64 = dataUrl.split(',')[1];
      setMessages(prev => [...prev, { role: 'user', text: "Diagnostic photo en cours...", image: dataUrl }]);
      const diagnosis = await diagnosePlant(base64);
      setMessages(prev => [...prev, { role: 'bot', text: diagnosis }]);
      setLoading(false);
    };
    reader.readAsDataURL(file);
  };

  const addStep = () => {
    if (!newStepDesc || !newStepDate) return;
    const newStep: ItineraryStep = {
      id: Date.now().toString(),
      description: newStepDesc,
      deadline: newStepDate,
      completed: false,
    };
    setSteps([...steps, newStep]);
    setNewStepDesc('');
    setNewStepDate('');
  };

  const handleAiSuggest = async () => {
    if (!cropName || !isOnline) return;
    setSuggesting(true);
    const suggestedSteps = await generateCropItinerary(cropName);
    if (suggestedSteps) {
      const start = new Date(startDate);
      const newSteps: ItineraryStep[] = suggestedSteps.map((s: any, idx: number) => {
        const deadlineDate = new Date(start);
        deadlineDate.setDate(start.getDate() + s.daysFromStart);
        return {
          id: `ai-${Date.now()}-${idx}`,
          description: s.description,
          deadline: deadlineDate.toISOString().split('T')[0],
          completed: false,
          daysFromStart: s.daysFromStart
        };
      });
      setSteps(newSteps);
    }
    setSuggesting(false);
  };

  const toggleStep = (id: string) => {
    setSteps(steps.map(s => s.id === id ? { ...s, completed: !s.completed } : s));
  };

  const removeStep = (id: string) => {
    setSteps(steps.filter(s => s.id !== id));
  };

  const getStepStatus = (step: ItineraryStep) => {
    if (step.completed) return 'completed';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const deadlineDate = new Date(step.deadline);
    if (deadlineDate < today) return 'overdue';
    const diffDays = Math.ceil((deadlineDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    return diffDays <= 3 ? 'upcoming' : 'pending';
  };

  const counts = useMemo(() => {
    const today = new Date();
    today.setHours(0,0,0,0);
    return steps.reduce((acc, s) => {
      if (!s.completed) {
        const d = new Date(s.deadline);
        if (d < today) acc.overdue++;
        else if (Math.ceil((d.getTime() - today.getTime())/(86400000)) <= 3) acc.upcoming++;
      }
      return acc;
    }, { overdue: 0, upcoming: 0 });
  }, [steps]);

  return (
    <div className="flex flex-col space-y-4">
      {/* Header Statut & Profil */}
      <div className="bg-white rounded-[2rem] p-4 border border-stone-200 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="relative group cursor-pointer" onClick={() => avatarInputRef.current?.click()}>
            <div className="w-[42px] h-[42px] rounded-full overflow-hidden border-2 border-emerald-100 flex items-center justify-center bg-stone-100 shadow-inner">
              {userAvatar ? <img src={userAvatar} className="w-full h-full object-cover" /> : <User size={20} className="text-stone-400" />}
            </div>
            <input type="file" ref={avatarInputRef} className="hidden" accept="image/*" onChange={(e) => {
               const file = e.target.files?.[0];
               if (file) {
                 const reader = new FileReader();
                 reader.onloadend = () => setUserAvatar(reader.result as string);
                 reader.readAsDataURL(file);
               }
            }} />
          </div>
          <div>
            <h4 className="text-sm font-bold text-stone-900 leading-tight">Mon Espace Agricole</h4>
            <div className="flex items-center gap-2 mt-0.5">
              <span className={`flex items-center gap-1 text-[9px] font-black uppercase tracking-widest ${isOnline ? 'text-emerald-600' : 'text-amber-600'}`}>
                {isOnline ? <Wifi size={10} /> : <WifiOff size={10} />}
                {isOnline ? 'En ligne' : 'Hors ligne (Local)'}
              </span>
              {lastSaved && (
                <span className="text-[8px] text-stone-300 font-bold uppercase flex items-center gap-1">
                  <Save size={8} /> {lastSaved.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                </span>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Chat IA */}
      <div className="flex flex-col h-[55vh] bg-white rounded-[2rem] shadow-sm border border-stone-200 overflow-hidden relative">
        <div className="bg-emerald-600 px-6 py-4 text-white flex items-center justify-between shadow-lg relative z-10">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl"><Sparkles size={20} /></div>
            <div>
              <span className="font-bold block leading-tight">Assistant IA</span>
              <span className="text-[10px] uppercase font-black tracking-widest opacity-80 italic">Contextualisé Afrique</span>
            </div>
          </div>
          <button onClick={handleReset} className="p-2 hover:bg-white/10 rounded-xl transition-colors"><RotateCcw size={18} /></button>
        </div>

        {!isOnline && (
          <div className="bg-amber-50 px-4 py-2 border-b border-amber-100 flex items-center gap-2 animate-pulse">
            <AlertCircle size={14} className="text-amber-600" />
            <span className="text-[9px] font-black text-amber-700 uppercase tracking-widest">Connexion perdue. IA indisponible.</span>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-stone-50/50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
               <div className={`max-w-[85%] rounded-3xl p-4 shadow-sm ${
                 m.role === 'user' ? 'bg-emerald-600 text-white rounded-tr-none' : 'bg-white border border-stone-200 text-stone-800 rounded-tl-none'
               }`}>
                 {m.image && <img src={m.image} className="rounded-xl mb-2 max-h-48 w-full object-cover" />}
                 <p className="text-sm leading-relaxed">{m.text}</p>
               </div>
            </div>
          ))}
          {loading && <div className="flex gap-2 p-2"><Loader2 size={16} className="animate-spin text-emerald-600" /><span className="text-xs italic text-stone-400">L'IA réfléchit...</span></div>}
          <div ref={chatEndRef} />
        </div>

        <div className="p-4 bg-white border-t border-stone-100">
           <div className="flex items-center gap-2">
             <button onClick={() => fileInputRef.current?.click()} disabled={!isOnline} className={`p-3 rounded-2xl ${isOnline ? 'text-emerald-600 hover:bg-emerald-50' : 'text-stone-300 cursor-not-allowed'}`}><ImageIcon size={20} /></button>
             <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
             <input value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleSend()} disabled={!isOnline} placeholder={isOnline ? "Votre question..." : "Reconnectez-vous pour parler à l'IA"} className="flex-1 bg-stone-100 rounded-2xl px-4 py-3 text-sm outline-none disabled:opacity-50" />
             <button onClick={handleSend} disabled={!isOnline || !input.trim()} className="p-3.5 bg-emerald-600 text-white rounded-2xl shadow-lg disabled:bg-stone-200 transition-all active:scale-95"><Send size={18} /></button>
           </div>
        </div>
      </div>

      {/* Itinéraire Technique */}
      <div className="bg-white rounded-[2rem] border border-stone-200 shadow-sm overflow-hidden">
        <div className="p-6 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
             <div className="bg-amber-100 p-2.5 rounded-xl text-amber-600 relative">
               <ClipboardList size={22} />
               {(counts.overdue > 0 || counts.upcoming > 0) && <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>}
             </div>
             <div>
               <h3 className="font-bold text-stone-900 leading-tight">Itinéraire Technique</h3>
               <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest">Disponible Hors Ligne</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             {/* Share Button Group */}
             <div className="flex items-center bg-stone-50 rounded-2xl p-1 border border-stone-100">
               <button 
                onClick={shareViaEmail} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'email' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Partager par Email"
               >
                 <Mail size={18} />
               </button>
               <button 
                onClick={shareViaNative} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'share' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Partager un lien ou via application"
               >
                 <Share2 size={18} />
               </button>
               <button 
                onClick={copyItineraryToClipboard} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'copy' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Copier en texte (Lien)"
               >
                 {showShareSuccess === 'copy' ? <Check size={18} /> : <Link size={18} />}
               </button>
             </div>
             <button onClick={() => setIsItineraryOpen(!isItineraryOpen)} className="p-2.5 bg-emerald-600 text-white rounded-xl shadow-lg active:scale-95 transition-all"><Plus size={18} className={`transition-transform ${isItineraryOpen ? 'rotate-45' : ''}`} /></button>
          </div>
        </div>

        {isItineraryOpen && (
          <div className="px-6 pb-6 space-y-6 animate-in slide-in-from-top-4">
             <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Culture</label>
                  <div className="flex gap-1">
                    <input value={cropName} onChange={e => setCropName(e.target.value)} placeholder="Ex: Mil" className="flex-1 bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                    <button onClick={handleAiSuggest} disabled={!isOnline || !cropName || suggesting} className="p-2.5 bg-amber-500 text-white rounded-xl disabled:opacity-50 transition-all active:scale-90 shadow-sm">
                      {suggesting ? <Loader2 size={16} className="animate-spin" /> : <Wand2 size={16} />}
                    </button>
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Nom Scientifique</label>
                  <input value={scientificName} onChange={e => setScientificName(e.target.value)} placeholder="Ex: Pennisetum glaucum" className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm italic font-medium" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Date du Semis</label>
                  <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                </div>
             </div>

             <div className="bg-emerald-50/50 p-4 rounded-2xl border border-emerald-100/50 space-y-3">
                <span className="text-[9px] font-black text-emerald-700 uppercase tracking-widest block">Ajouter une tâche manuelle</span>
                <div className="flex flex-col sm:flex-row gap-2">
                  <input value={newStepDesc} onChange={e => setNewStepDesc(e.target.value)} placeholder="Ex: Sarclage n°1" className="flex-1 bg-white border border-stone-200 rounded-xl px-4 py-2 text-sm outline-none focus:ring-1 focus:ring-emerald-500" />
                  <div className="flex gap-2">
                    <input type="date" value={newStepDate} onChange={e => setNewStepDate(e.target.value)} className="bg-white border border-stone-200 rounded-xl px-3 py-2 text-xs font-bold" />
                    <button onClick={addStep} className="bg-emerald-600 text-white px-4 rounded-xl shadow-sm"><Plus size={18} /></button>
                  </div>
                </div>
             </div>

             <div className="space-y-3">
                {steps.length > 0 ? (
                  steps.sort((a,b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).map(step => {
                    const status = getStepStatus(step);
                    return (
                      <div key={step.id} className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                        step.completed ? 'bg-stone-50 border-stone-100 opacity-60' :
                        status === 'overdue' ? 'bg-red-50 border-red-100' :
                        status === 'upcoming' ? 'bg-amber-50 border-amber-100' : 'bg-white border-stone-100'
                      }`}>
                        <div className="flex items-center gap-4">
                           <button onClick={() => toggleStep(step.id)} className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${step.completed ? 'bg-emerald-600 border-emerald-600 text-white' : 'border-stone-300 bg-white'}`}>
                             {step.completed && <Check size={14} />}
                           </button>
                           <div>
                              <p className={`text-sm font-bold ${step.completed ? 'line-through text-stone-400' : 'text-stone-800'}`}>{step.description}</p>
                              <div className="flex items-center gap-2 mt-0.5">
                                 <span className={`text-[10px] font-bold flex items-center gap-1 uppercase ${status === 'overdue' ? 'text-red-500' : 'text-stone-400'}`}>
                                   <Calendar size={10} /> {new Date(step.deadline).toLocaleDateString('fr-FR')}
                                 </span>
                                 {status === 'overdue' && !step.completed && <span className="text-[8px] font-black bg-red-600 text-white px-1.5 py-0.5 rounded uppercase animate-pulse">Retard</span>}
                                 {status === 'upcoming' && !step.completed && <span className="text-[8px] font-black bg-amber-500 text-white px-1.5 py-0.5 rounded uppercase">Urgent</span>}
                              </div>
                           </div>
                        </div>
                        <button onClick={() => removeStep(step.id)} className="text-stone-300 hover:text-red-500 p-1"><Trash2 size={16} /></button>
                      </div>
                    );
                  })
                ) : (
                  <div className="py-12 text-center border-2 border-dashed border-stone-100 rounded-3xl">
                     <ClipboardList className="mx-auto text-stone-200 mb-2" size={32} />
                     <p className="text-xs text-stone-400 font-bold uppercase tracking-widest">Aucun plan enregistré localement</p>
                  </div>
                )}
             </div>
          </div>
        )}
      </div>

      <p className="text-[8px] text-center text-stone-300 font-bold uppercase tracking-[0.2em] py-2">
        AgroExpert Afrique • Sécurité & Sauvegarde Locale Active
      </p>
    </div>
  );
};

export default AgroExpert;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Camera, Sparkles, Loader2, Image as ImageIcon, X, RotateCcw, Copy, Check, Calendar, Plus, Trash2, ClipboardList, User, Wand2, AlertCircle, BellRing, WifiOff, Wifi, Save, Share2, Mail, Link } from 'lucide-react';
import { getAgroAdvice, diagnosePlant, generateCropItinerary } from '../services/geminiService';

interface Message {
  role: 'user' | 'bot';
  text: string;
  image?: string;
}

interface ItineraryStep {
  id: string;
  description: string;
  deadline: string;
  completed: boolean;
  daysFromStart?: number;
}

const STORAGE_KEYS = {
  CHAT: 'agroexpert_chat_history',
  ITINERARY: 'agroexpert_itinerary_data',
  AVATAR: 'agroexpert_user_avatar',
  EMAIL: 'agroexpert_user_email'
};

const AgroExpert: React.FC = () => {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [input, setInput] = useState('');
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Initialize states from localStorage
  const [messages, setMessages] = useState<Message[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CHAT);
    return saved ? JSON.parse(saved) : [
      { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
    ];
  });

  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);
  const [showShareSuccess, setShowShareSuccess] = useState<string | null>(null);

  // Profile states
  const [userAvatar, setUserAvatar] = useState<string | null>(() => {
    return localStorage.getItem(STORAGE_KEYS.AVATAR);
  });
  const [userEmail, setUserEmail] = useState<string>(() => {
    return localStorage.getItem(STORAGE_KEYS.EMAIL) || '';
  });
  const avatarInputRef = useRef<HTMLInputElement>(null);

  // Itinerary states
  const [itineraryData, setItineraryData] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ITINERARY);
    return saved ? JSON.parse(saved) : {
      cropName: '',
      scientificName: '',
      startDate: new Date().toISOString().split('T')[0],
      steps: [] as ItineraryStep[]
    };
  });

  const [cropName, setCropName] = useState(itineraryData.cropName);
  const [scientificName, setScientificName] = useState(itineraryData.scientificName);
  const [startDate, setStartDate] = useState(itineraryData.startDate);
  const [steps, setSteps] = useState<ItineraryStep[]>(itineraryData.steps);

  const [newStepDesc, setNewStepDesc] = useState('');
  const [newStepDate, setNewStepDate] = useState('');
  const [isItineraryOpen, setIsItineraryOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Connection listeners
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Sync state and Save to localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.CHAT, JSON.stringify(messages));
    setLastSaved(new Date());
  }, [messages]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AVATAR, userAvatar || '');
  }, [userAvatar]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.EMAIL, userEmail);
  }, [userEmail]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.ITINERARY, JSON.stringify({
      cropName,
      scientificName,
      startDate,
      steps
    }));
    setLastSaved(new Date());
  }, [cropName, scientificName, startDate, steps]);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    if (!isOnline) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const botResponse = await getAgroAdvice(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setLoading(false);
  };

  const handleReset = () => {
    if (window.confirm("Effacer l'historique ? (Les données de l'itinéraire seront conservées)")) {
      const initialMessage: Message[] = [
        { role: 'bot', text: 'Historique effacé. Comment puis-je vous aider ?' }
      ];
      setMessages(initialMessage);
    }
  };

  const getItineraryAsText = () => {
    let text = `📋 ITINÉRAIRE TECHNIQUE : ${cropName.toUpperCase() || 'Sans titre'}\n`;
    if (scientificName) text += `🧬 Nom Scientifique : ${scientificName}\n`;
    if (userEmail) text += `✉️ Contact : ${userEmail}\n`;
    text += `📅 Date de début : ${new Date(startDate).toLocaleDateString('fr-FR')}\n\n`;
    text += `ÉTAPES PRÉVUES :\n`;

    steps.slice().sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).forEach((s, i) => {
      text += `${i + 1}. [${new Date(s.deadline).toLocaleDateString('fr-FR')}] ${s.description}${s.completed ? ' ✅' : ''}\n`;
    });

    text += `\nExporté depuis AgroExpert Afrique`;
    return text;
  };

  const copyItineraryToClipboard = () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    navigator.clipboard.writeText(text).then(() => {
      setShowShareSuccess('copy');
      setTimeout(() => setShowShareSuccess(null), 3000);
    });
  };

  const shareViaEmail = () => {
    if (steps.length === 0) return;
    const subject = encodeURIComponent(`Mon Itinéraire Technique : ${cropName}`);
    const body = encodeURIComponent(getItineraryAsText());
    window.location.href = `mailto:?subject=${subject}&body=${body}`;
    setShowShareSuccess('email');
    setTimeout(() => setShowShareSuccess(null), 3000);
  };

  const shareViaNative = async () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Itinéraire ${cropName}`,
          text: text,
        });
        setShowShareSuccess('share');
        setTimeout(() => setShowShareSuccess(null), 3000);
      } catch (err) {
        copyItineraryToClipboard();
      }
    } else {
      copyItineraryToClipboard();
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !isOnline) return;

    const reader = new FileReader();
    reader.onloadstart = () => setLoading(true);
    reader.onloadend = async () => {
      const dataUrl = reader.result as string;
      const base64 = dataUrl.split(',')[1];
      setMessages(prev => [...prev, { role: 'user', text: "Diagnostic photo en cours...", image: dataUrl }]);
      const diagnosis = await diagnosePlant(base64);
      setMessages(prev => [...prev, { role: 'bot', text: diagnosis }]);
      setLoading(false);
    };
    reader.readAsDataURL(file);
  };

  const addStep = () => {
    if (!newStepDesc || !newStepDate) return;
    const newStep: ItineraryStep = {
      id: Date.now().toString(),
      description: newStepDesc,
      deadline: newStepDate,
      completed: false,
    };
    setSteps([...steps, newStep]);
    setNewStepDesc('');
    setNewStepDate('');
  };

  const handleAiSuggest = async () => {
    if (!cropName || !isOnline) return;
    setSuggesting(true);
    const suggestedSteps = await generateCropItinerary(cropName);
    if (suggestedSteps) {
      const start = new Date(startDate);
      const newSteps: ItineraryStep[] = suggestedSteps.map((s: any, idx: number) => {
        const deadlineDate = new Date(start);
        deadlineDate.setDate(start.getDate() + s.daysFromStart);
        return {
          id: `ai-${Date.now()}-${idx}`,
          description: s.description,
          deadline: deadlineDate.toISOString().split('T')[0],
          completed: false,
          daysFromStart: s.daysFromStart
        };
      });
      setSteps(newSteps);
    }
    setSuggesting(false);
  };

  const toggleStep = (id: string) => {
    setSteps(steps.map(s => s.id === id ? { ...s, completed: !s.completed } : s));
  };

  const removeStep = (id: string) => {
    setSteps(steps.filter(s => s.id !== id));
  };

  const getStepStatus = (step: ItineraryStep) => {
    if (step.completed) return 'completed';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const deadlineDate = new Date(step.deadline);
    if (deadlineDate < today) return 'overdue';
    const diffDays = Math.ceil((deadlineDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    return diffDays <= 3 ? 'upcoming' : 'pending';
  };

  const counts = useMemo(() => {
    const today = new Date();
    today.setHours(0,0,0,0);
    return steps.reduce((acc, s) => {
      if (!s.completed) {
        const d = new Date(s.deadline);
        if (d < today) acc.overdue++;
        else if (Math.ceil((d.getTime() - today.getTime())/(86400000)) <= 3) acc.upcoming++;
      }
      return acc;
    }, { overdue: 0, upcoming: 0 });
  }, [steps]);

  return (
    <div className="flex flex-col space-y-4">
      {/* Header Statut & Profil */}
      <div className="bg-white rounded-[2rem] p-4 border border-stone-200 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4 flex-1">
          <div className="relative group cursor-pointer shrink-0" onClick={() => avatarInputRef.current?.click()}>
            <div className="w-[48px] h-[48px] rounded-full overflow-hidden border-2 border-emerald-100 flex items-center justify-center bg-stone-100 shadow-inner">
              {userAvatar ? <img src={userAvatar} className="w-full h-full object-cover" /> : <User size={24} className="text-stone-400" />}
            </div>
            <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 rounded-full transition-opacity flex items-center justify-center">
              <Camera size={14} className="text-white" />
            </div>
            <input type="file" ref={avatarInputRef} className="hidden" accept="image/*" onChange={(e) => {
               const file = e.target.files?.[0];
               if (file) {
                 const reader = new FileReader();
                 reader.onloadend = () => setUserAvatar(reader.result as string);
                 reader.readAsDataURL(file);
               }
            }} />
          </div>
          <div className="flex-1">
            <h4 className="text-sm font-bold text-stone-900 leading-tight">Mon Espace Agricole</h4>
            <div className="flex flex-col gap-1 mt-1">
              <div className="flex items-center gap-2">
                <span className={`flex items-center gap-1 text-[9px] font-black uppercase tracking-widest ${isOnline ? 'text-emerald-600' : 'text-amber-600'}`}>
                  {isOnline ? <Wifi size={10} /> : <WifiOff size={10} />}
                  {isOnline ? 'En ligne' : 'Hors ligne'}
                </span>
                {lastSaved && (
                  <span className="text-[8px] text-stone-300 font-bold uppercase flex items-center gap-1">
                    <Save size={8} /> {lastSaved.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                  </span>
                )}
              </div>
              <input 
                type="email" 
                value={userEmail} 
                onChange={(e) => setUserEmail(e.target.value)}
                placeholder="votre@email.com"
                className="text-[10px] font-medium text-stone-600 bg-stone-50 border border-stone-100 rounded-lg px-2 py-1 outline-none focus:ring-1 focus:ring-emerald-500 w-full max-w-[180px]"
              />
            </div>
          </div>
        </div>
      </div>

      {/* Chat IA */}
      <div className="flex flex-col h-[55vh] bg-white rounded-[2rem] shadow-sm border border-stone-200 overflow-hidden relative">
        <div className="bg-emerald-600 px-6 py-4 text-white flex items-center justify-between shadow-lg relative z-10">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl"><Sparkles size={20} /></div>
            <div>
              <span className="font-bold block leading-tight">Assistant IA</span>
              <span className="text-[10px] uppercase font-black tracking-widest opacity-80 italic">Contextualisé Afrique</span>
            </div>
          </div>
          <button onClick={handleReset} className="p-2 hover:bg-white/10 rounded-xl transition-colors"><RotateCcw size={18} /></button>
        </div>

        {!isOnline && (
          <div className="bg-amber-50 px-4 py-2 border-b border-amber-100 flex items-center gap-2 animate-pulse">
            <AlertCircle size={14} className="text-amber-600" />
            <span className="text-[9px] font-black text-amber-700 uppercase tracking-widest">Connexion perdue. IA indisponible.</span>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-stone-50/50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
               <div className={`max-w-[85%] rounded-3xl p-4 shadow-sm ${
                 m.role === 'user' ? 'bg-emerald-600 text-white rounded-tr-none' : 'bg-white border border-stone-200 text-stone-800 rounded-tl-none'
               }`}>
                 {m.image && <img src={m.image} className="rounded-xl mb-2 max-h-48 w-full object-cover" />}
                 <p className="text-sm leading-relaxed">{m.text}</p>
               </div>
            </div>
          ))}
          {loading && <div className="flex gap-2 p-2"><Loader2 size={16} className="animate-spin text-emerald-600" /><span className="text-xs italic text-stone-400">L'IA réfléchit...</span></div>}
          <div ref={chatEndRef} />
        </div>

        <div className="p-4 bg-white border-t border-stone-100">
           <div className="flex items-center gap-2">
             <button onClick={() => fileInputRef.current?.click()} disabled={!isOnline} className={`p-3 rounded-2xl ${isOnline ? 'text-emerald-600 hover:bg-emerald-50' : 'text-stone-300 cursor-not-allowed'}`}><ImageIcon size={20} /></button>
             <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
             <input value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleSend()} disabled={!isOnline} placeholder={isOnline ? "Votre question..." : "Reconnectez-vous pour parler à l'IA"} className="flex-1 bg-stone-100 rounded-2xl px-4 py-3 text-sm outline-none disabled:opacity-50" />
             <button onClick={handleSend} disabled={!isOnline || !input.trim()} className="p-3.5 bg-emerald-600 text-white rounded-2xl shadow-lg disabled:bg-stone-200 transition-all active:scale-95"><Send size={18} /></button>
           </div>
        </div>
      </div>

      {/* Itinéraire Technique */}
      <div className="bg-white rounded-[2rem] border border-stone-200 shadow-sm overflow-hidden">
        <div className="p-6 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
             <div className="bg-amber-100 p-2.5 rounded-xl text-amber-600 relative">
               <ClipboardList size={22} />
               {(counts.overdue > 0 || counts.upcoming > 0) && <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>}
             </div>
             <div>
               <h3 className="font-bold text-stone-900 leading-tight">Itinéraire Technique</h3>
               <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest">Disponible Hors Ligne</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             {/* Share Button Group */}
             <div className="flex items-center bg-stone-50 rounded-2xl p-1 border border-stone-100">
               <button 
                onClick={shareViaEmail} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'email' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Partager par Email"
               >
                 <Mail size={18} />
               </button>
               <button 
                onClick={shareViaNative} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'share' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Partager un lien ou via application"
               >
                 <Share2 size={18} />
               </button>
               <button 
                onClick={copyItineraryToClipboard} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'copy' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Copier en texte (Lien)"
               >
                 {showShareSuccess === 'copy' ? <Check size={18} /> : <Link size={18} />}
               </button>
             </div>
             <button onClick={() => setIsItineraryOpen(!isItineraryOpen)} className="p-2.5 bg-emerald-600 text-white rounded-xl shadow-lg active:scale-95 transition-all"><Plus size={18} className={`transition-transform ${isItineraryOpen ? 'rotate-45' : ''}`} /></button>
          </div>
        </div>

        {isItineraryOpen && (
          <div className="px-6 pb-6 space-y-6 animate-in slide-in-from-top-4">
             <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Culture</label>
                  <div className="flex gap-1">
                    <input value={cropName} onChange={e => setCropName(e.target.value)} placeholder="Ex: Mil" className="flex-1 bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                    <button onClick={handleAiSuggest} disabled={!isOnline || !cropName || suggesting} className="p-2.5 bg-amber-500 text-white rounded-xl disabled:opacity-50 transition-all active:scale-90 shadow-sm">
                      {suggesting ? <Loader2 size={16} className="animate-spin" /> : <Wand2 size={16} />}
                    </button>
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Nom Scientifique</label>
                  <input value={scientificName} onChange={e => setScientificName(e.target.value)} placeholder="Ex: Pennisetum glaucum" className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm italic font-medium" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Date du Semis</label>
                  <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                </div>
             </div>

             <div className="bg-emerald-50/50 p-4 rounded-2xl border border-emerald-100/50 space-y-3">
                <span className="text-[9px] font-black text-emerald-700 uppercase tracking-widest block">Ajouter une tâche manuelle</span>
                <div className="flex flex-col sm:flex-row gap-2">
                  <input value={newStepDesc} onChange={e => setNewStepDesc(e.target.value)} placeholder="Ex: Sarclage n°1" className="flex-1 bg-white border border-stone-200 rounded-xl px-4 py-2 text-sm outline-none focus:ring-1 focus:ring-emerald-500" />
                  <div className="flex gap-2">
                    <input type="date" value={newStepDate} onChange={e => setNewStepDate(e.target.value)} className="bg-white border border-stone-200 rounded-xl px-3 py-2 text-xs font-bold" />
                    <button onClick={addStep} className="bg-emerald-600 text-white px-4 rounded-xl shadow-sm"><Plus size={18} /></button>
                  </div>
                </div>
             </div>

             <div className="space-y-3">
                {steps.length > 0 ? (
                  steps.sort((a,b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).map(step => {
                    const status = getStepStatus(step);
                    return (
                      <div key={step.id} className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                        step.completed ? 'bg-stone-50 border-stone-100 opacity-60' :
                        status === 'overdue' ? 'bg-red-50 border-red-100' :
                        status === 'upcoming' ? 'bg-amber-50 border-amber-100' : 'bg-white border-stone-100'
                      }`}>
                        <div className="flex items-center gap-4">
                           <button onClick={() => toggleStep(step.id)} className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${step.completed ? 'bg-emerald-600 border-emerald-600 text-white' : 'border-stone-300 bg-white'}`}>
                             {step.completed && <Check size={14} />}
                           </button>
                           <div>
                              <p className={`text-sm font-bold ${step.completed ? 'line-through text-stone-400' : 'text-stone-800'}`}>{step.description}</p>
                              <div className="flex items-center gap-2 mt-0.5">
                                 <span className={`text-[10px] font-bold flex items-center gap-1 uppercase ${status === 'overdue' ? 'text-red-500' : 'text-stone-400'}`}>
                                   <Calendar size={10} /> {new Date(step.deadline).toLocaleDateString('fr-FR')}
                                 </span>
                                 {status === 'overdue' && !step.completed && <span className="text-[8px] font-black bg-red-600 text-white px-1.5 py-0.5 rounded uppercase animate-pulse">Retard</span>}
                                 {status === 'upcoming' && !step.completed && <span className="text-[8px] font-black bg-amber-500 text-white px-1.5 py-0.5 rounded uppercase">Urgent</span>}
                              </div>
                           </div>
                        </div>
                        <button onClick={() => removeStep(step.id)} className="text-stone-300 hover:text-red-500 p-1"><Trash2 size={16} /></button>
                      </div>
                    );
                  })
                ) : (
                  <div className="py-12 text-center border-2 border-dashed border-stone-100 rounded-3xl">
                     <ClipboardList className="mx-auto text-stone-200 mb-2" size={32} />
                     <p className="text-xs text-stone-400 font-bold uppercase tracking-widest">Aucun plan enregistré localement</p>
                  </div>
                )}
             </div>
          </div>
        )}
      </div>

      <p className="text-[8px] text-center text-stone-300 font-bold uppercase tracking-[0.2em] py-2">
        AgroExpert Afrique • Sécurité & Sauvegarde Locale Active
      </p>
    </div>
  );
};

export default AgroExpert;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getAgroAdvice = async (prompt: string, context?: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Tu es un expert agronome africain senior. Réponds de manière précise, adaptée au contexte africain (climat, types de sols, moyens financiers).

      Question de l'utilisateur: ${prompt}
      ${context ? `Contexte supplémentaire: ${context}` : ''}`,
      config: {
        temperature: 0.7,
        topP: 0.95,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Désolé, je rencontre une difficulté technique. Veuillez réessayer plus tard.";
  }
};

export const diagnosePlant = async (imageBase64: string, mimeType: string = 'image/jpeg') => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: imageBase64 } },
          { text: "Diagnostique cette plante. Donne le nom de la maladie, les symptômes, et surtout les solutions bio et chimiques adaptées au contexte africain." }
        ]
      }
    });
    return response.text;
  } catch (error) {
    console.error("Diagnosis Error:", error);
    return "Échec du diagnostic. Assurez-vous qu'elle est bien éclairée.";
  }
};

export const generateCropItinerary = async (crop: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Génère un itinéraire technique complet et chronologique pour la culture de: ${crop} en Afrique.
      Inclus les étapes clés : préparation du sol, semis, fertilisation (N-P-K), sarclage, traitement phytosanitaire et récolte.
      Pour chaque étape, donne une description précise et le nombre de jours recommandés APRÈS le semis (J+X).

      Réponds uniquement en format JSON structuré.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              description: { type: Type.STRING },
              daysFromStart: { type: Type.NUMBER }
            },
            required: ["description", "daysFromStart"]
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Itinerary Generation Error:", error);
    return null;
  }
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Camera, Sparkles, Loader2, Image as ImageIcon, X, RotateCcw, Copy, Check, Calendar, Plus, Trash2, ClipboardList, User, Wand2, AlertCircle, BellRing, WifiOff, Wifi, Save, Share2, Mail, Link } from 'lucide-react';
import { getAgroAdvice, diagnosePlant, generateCropItinerary } from '../services/geminiService';

interface Message {
  role: 'user' | 'bot';
  text: string;
  image?: string;
}

interface ItineraryStep {
  id: string;
  description: string;
  deadline: string;
  completed: boolean;
  daysFromStart?: number;
}

const STORAGE_KEYS = {
  CHAT: 'agroexpert_chat_history',
  ITINERARY: 'agroexpert_itinerary_data',
  AVATAR: 'agroexpert_user_avatar',
  EMAIL: 'agroexpert_user_email'
};

const AgroExpert: React.FC = () => {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [input, setInput] = useState('');
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Initialize states from localStorage
  const [messages, setMessages] = useState<Message[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CHAT);
    return saved ? JSON.parse(saved) : [
      { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
    ];
  });

  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);
  const [showShareSuccess, setShowShareSuccess] = useState<string | null>(null);

  // Profile states
  const [userAvatar, setUserAvatar] = useState<string | null>(() => {
    return localStorage.getItem(STORAGE_KEYS.AVATAR);
  });
  const [userEmail, setUserEmail] = useState<string>(() => {
    return localStorage.getItem(STORAGE_KEYS.EMAIL) || '';
  });
  const avatarInputRef = useRef<HTMLInputElement>(null);

  // Itinerary states
  const [itineraryData, setItineraryData] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ITINERARY);
    return saved ? JSON.parse(saved) : {
      cropName: '',
      scientificName: '',
      startDate: new Date().toISOString().split('T')[0],
      steps: [] as ItineraryStep[]
    };
  });

  const [cropName, setCropName] = useState(itineraryData.cropName);
  const [scientificName, setScientificName] = useState(itineraryData.scientificName);
  const [startDate, setStartDate] = useState(itineraryData.startDate);
  const [steps, setSteps] = useState<ItineraryStep[]>(itineraryData.steps);

  const [newStepDesc, setNewStepDesc] = useState('');
  const [newStepDate, setNewStepDate] = useState('');
  const [isItineraryOpen, setIsItineraryOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Connection listeners
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Sync state and Save to localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.CHAT, JSON.stringify(messages));
    setLastSaved(new Date());
  }, [messages]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AVATAR, userAvatar || '');
  }, [userAvatar]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.EMAIL, userEmail);
  }, [userEmail]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.ITINERARY, JSON.stringify({
      cropName,
      scientificName,
      startDate,
      steps
    }));
    setLastSaved(new Date());
  }, [cropName, scientificName, startDate, steps]);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    if (!isOnline) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const botResponse = await getAgroAdvice(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setLoading(false);
  };

  const handleReset = () => {
    if (window.confirm("Effacer l'historique ? (Les données de l'itinéraire seront conservées)")) {
      const initialMessage: Message[] = [
        { role: 'bot', text: 'Historique effacé. Comment puis-je vous aider ?' }
      ];
      setMessages(initialMessage);
    }
  };

  const getItineraryAsText = () => {
    let text = `📋 ITINÉRAIRE TECHNIQUE : ${cropName.toUpperCase() || 'Sans titre'}\n`;
    if (scientificName) text += `🧬 Nom Scientifique : ${scientificName}\n`;
    if (userEmail) text += `✉️ Contact : ${userEmail}\n`;
    text += `📅 Date de début : ${new Date(startDate).toLocaleDateString('fr-FR')}\n\n`;
    text += `ÉTAPES PRÉVUES :\n`;

    steps.slice().sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).forEach((s, i) => {
      text += `${i + 1}. [${new Date(s.deadline).toLocaleDateString('fr-FR')}] ${s.description}${s.completed ? ' ✅' : ''}\n`;
    });

    text += `\nExporté depuis AgroExpert Afrique`;
    return text;
  };

  const copyItineraryToClipboard = () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    navigator.clipboard.writeText(text).then(() => {
      setShowShareSuccess('copy');
      setTimeout(() => setShowShareSuccess(null), 3000);
    });
  };

  const shareViaEmail = () => {
    if (steps.length === 0) return;
    const subject = encodeURIComponent(`Mon Itinéraire Technique : ${cropName}`);
    const body = encodeURIComponent(getItineraryAsText());
    window.location.href = `mailto:?subject=${subject}&body=${body}`;
    setShowShareSuccess('email');
    setTimeout(() => setShowShareSuccess(null), 3000);
  };

  const shareViaNative = async () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Itinéraire ${cropName}`,
          text: text,
        });
        setShowShareSuccess('share');
        setTimeout(() => setShowShareSuccess(null), 3000);
      } catch (err) {
        copyItineraryToClipboard();
      }
    } else {
      copyItineraryToClipboard();
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !isOnline) return;
    const mimeType = file.type;

    const reader = new FileReader();
    reader.onloadstart = () => setLoading(true);
    reader.onloadend = async () => {
      const dataUrl = reader.result as string;
      const base64 = dataUrl.split(',')[1];
      setMessages(prev => [...prev, { role: 'user', text: "Diagnostic photo en cours...", image: dataUrl }]);
      const diagnosis = await diagnosePlant(base64, mimeType);
      setMessages(prev => [...prev, { role: 'bot', text: diagnosis }]);
      setLoading(false);
    };
    reader.readAsDataURL(file);
  };

  const addStep = () => {
    if (!newStepDesc || !newStepDate) return;
    const newStep: ItineraryStep = {
      id: Date.now().toString(),
      description: newStepDesc,
      deadline: newStepDate,
      completed: false,
    };
    setSteps([...steps, newStep]);
    setNewStepDesc('');
    setNewStepDate('');
  };

  const handleAiSuggest = async () => {
    if (!cropName || !isOnline) return;
    setSuggesting(true);
    const suggestedSteps = await generateCropItinerary(cropName);
    if (suggestedSteps) {
      const start = new Date(startDate);
      const newSteps: ItineraryStep[] = suggestedSteps.map((s: any, idx: number) => {
        const deadlineDate = new Date(start);
        deadlineDate.setDate(start.getDate() + s.daysFromStart);
        return {
          id: `ai-${Date.now()}-${idx}`,
          description: s.description,
          deadline: deadlineDate.toISOString().split('T')[0],
          completed: false,
          daysFromStart: s.daysFromStart
        };
      });
      setSteps(newSteps);
    }
    setSuggesting(false);
  };

  const toggleStep = (id: string) => {
    setSteps(steps.map(s => s.id === id ? { ...s, completed: !s.completed } : s));
  };

  const removeStep = (id: string) => {
    setSteps(steps.filter(s => s.id !== id));
  };

  const getStepStatus = (step: ItineraryStep) => {
    if (step.completed) return 'completed';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const deadlineDate = new Date(step.deadline);
    if (deadlineDate < today) return 'overdue';
    const diffDays = Math.ceil((deadlineDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    return diffDays <= 3 ? 'upcoming' : 'pending';
  };

  const counts = useMemo(() => {
    const today = new Date();
    today.setHours(0,0,0,0);
    return steps.reduce((acc, s) => {
      if (!s.completed) {
        const d = new Date(s.deadline);
        if (d < today) acc.overdue++;
        else if (Math.ceil((d.getTime() - today.getTime())/(86400000)) <= 3) acc.upcoming++;
      }
      return acc;
    }, { overdue: 0, upcoming: 0 });
  }, [steps]);

  return (
    <div className="flex flex-col space-y-4">
      {/* Header Statut & Profil */}
      <div className="bg-white rounded-[2rem] p-4 border border-stone-200 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4 flex-1">
          <div className="relative group cursor-pointer shrink-0" onClick={() => avatarInputRef.current?.click()}>
            <div className="w-[48px] h-[48px] rounded-full overflow-hidden border-2 border-emerald-100 flex items-center justify-center bg-stone-100 shadow-inner">
              {userAvatar ? <img src={userAvatar} className="w-full h-full object-cover" /> : <User size={24} className="text-stone-400" />}
            </div>
            <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 rounded-full transition-opacity flex items-center justify-center">
              <Camera size={14} className="text-white" />
            </div>
            <input 
              type="file" 
              ref={avatarInputRef} 
              className="hidden" 
              accept="image/png, image/gif, image/jpeg, image/jpg" 
              onChange={(e) => {
               const file = e.target.files?.[0];
               if (file) {
                 const reader = new FileReader();
                 reader.onloadend = () => setUserAvatar(reader.result as string);
                 reader.readAsDataURL(file);
               }
            }} />
          </div>
          <div className="flex-1">
            <h4 className="text-sm font-bold text-stone-900 leading-tight">Mon Espace Agricole</h4>
            <div className="flex flex-col gap-1 mt-1">
              <div className="flex items-center gap-2">
                <span className={`flex items-center gap-1 text-[9px] font-black uppercase tracking-widest ${isOnline ? 'text-emerald-600' : 'text-amber-600'}`}>
                  {isOnline ? <Wifi size={10} /> : <WifiOff size={10} />}
                  {isOnline ? 'En ligne' : 'Hors ligne'}
                </span>
                {lastSaved && (
                  <span className="text-[8px] text-stone-300 font-bold uppercase flex items-center gap-1">
                    <Save size={8} /> {lastSaved.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                  </span>
                )}
              </div>
              <input 
                type="email" 
                value={userEmail} 
                onChange={(e) => setUserEmail(e.target.value)}
                placeholder="votre@email.com"
                className="text-[10px] font-medium text-stone-600 bg-stone-50 border border-stone-100 rounded-lg px-2 py-1 outline-none focus:ring-1 focus:ring-emerald-500 w-full max-w-[180px]"
              />
            </div>
          </div>
        </div>
      </div>

      {/* Chat IA */}
      <div className="flex flex-col h-[55vh] bg-white rounded-[2rem] shadow-sm border border-stone-200 overflow-hidden relative">
        <div className="bg-emerald-600 px-6 py-4 text-white flex items-center justify-between shadow-lg relative z-10">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl"><Sparkles size={20} /></div>
            <div>
              <span className="font-bold block leading-tight">Assistant IA</span>
              <span className="text-[10px] uppercase font-black tracking-widest opacity-80 italic">Contextualisé Afrique</span>
            </div>
          </div>
          <button onClick={handleReset} className="p-2 hover:bg-white/10 rounded-xl transition-colors"><RotateCcw size={18} /></button>
        </div>

        {!isOnline && (
          <div className="bg-amber-50 px-4 py-2 border-b border-amber-100 flex items-center gap-2 animate-pulse">
            <AlertCircle size={14} className="text-amber-600" />
            <span className="text-[9px] font-black text-amber-700 uppercase tracking-widest">Connexion perdue. IA indisponible.</span>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-stone-50/50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
               <div className={`max-w-[85%] rounded-3xl p-4 shadow-sm ${
                 m.role === 'user' ? 'bg-emerald-600 text-white rounded-tr-none' : 'bg-white border border-stone-200 text-stone-800 rounded-tl-none'
               }`}>
                 {m.image && <img src={m.image} className="rounded-xl mb-2 max-h-48 w-full object-cover" />}
                 <p className="text-sm leading-relaxed">{m.text}</p>
               </div>
            </div>
          ))}
          {loading && <div className="flex gap-2 p-2"><Loader2 size={16} className="animate-spin text-emerald-600" /><span className="text-xs italic text-stone-400">L'IA réfléchit...</span></div>}
          <div ref={chatEndRef} />
        </div>

        <div className="p-4 bg-white border-t border-stone-100">
           <div className="flex items-center gap-2">
             <button onClick={() => fileInputRef.current?.click()} disabled={!isOnline} className={`p-3 rounded-2xl ${isOnline ? 'text-emerald-600 hover:bg-emerald-50' : 'text-stone-300 cursor-not-allowed'}`}><ImageIcon size={20} /></button>
             <input type="file" ref={fileInputRef} className="hidden" accept="image/png, image/gif, image/jpeg, image/jpg" onChange={handleFileUpload} />
             <input value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleSend()} disabled={!isOnline} placeholder={isOnline ? "Votre question..." : "Reconnectez-vous pour parler à l'IA"} className="flex-1 bg-stone-100 rounded-2xl px-4 py-3 text-sm outline-none disabled:opacity-50" />
             <button onClick={handleSend} disabled={!isOnline || !input.trim()} className="p-3.5 bg-emerald-600 text-white rounded-2xl shadow-lg disabled:bg-stone-200 transition-all active:scale-95"><Send size={18} /></button>
           </div>
        </div>
      </div>

      {/* Itinéraire Technique */}
      <div className="bg-white rounded-[2rem] border border-stone-200 shadow-sm overflow-hidden">
        <div className="p-6 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
             <div className="bg-amber-100 p-2.5 rounded-xl text-amber-600 relative">
               <ClipboardList size={22} />
               {(counts.overdue > 0 || counts.upcoming > 0) && <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>}
             </div>
             <div>
               <h3 className="font-bold text-stone-900 leading-tight">Itinéraire Technique</h3>
               <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest">Disponible Hors Ligne</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             {/* Share Button Group */}
             <div className="flex items-center bg-stone-50 rounded-2xl p-1 border border-stone-100">
               <button 
                onClick={shareViaEmail} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'email' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Partager par Email"
               >
                 <Mail size={18} />
               </button>
               <button 
                onClick={shareViaNative} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'share' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Partager un lien ou via application"
               >
                 <Share2 size={18} />
               </button>
               <button 
                onClick={copyItineraryToClipboard} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'copy' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Copier en texte (Lien)"
               >
                 {showShareSuccess === 'copy' ? <Check size={18} /> : <Link size={18} />}
               </button>
             </div>
             <button onClick={() => setIsItineraryOpen(!isItineraryOpen)} className="p-2.5 bg-emerald-600 text-white rounded-xl shadow-lg active:scale-95 transition-all"><Plus size={18} className={`transition-transform ${isItineraryOpen ? 'rotate-45' : ''}`} /></button>
          </div>
        </div>

        {isItineraryOpen && (
          <div className="px-6 pb-6 space-y-6 animate-in slide-in-from-top-4">
             <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Culture</label>
                  <div className="flex gap-1">
                    <input value={cropName} onChange={e => setCropName(e.target.value)} placeholder="Ex: Mil" className="flex-1 bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                    <button onClick={handleAiSuggest} disabled={!isOnline || !cropName || suggesting} className="p-2.5 bg-amber-500 text-white rounded-xl disabled:opacity-50 transition-all active:scale-90 shadow-sm">
                      {suggesting ? <Loader2 size={16} className="animate-spin" /> : <Wand2 size={16} />}
                    </button>
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Nom Scientifique</label>
                  <input value={scientificName} onChange={e => setScientificName(e.target.value)} placeholder="Ex: Pennisetum glaucum" className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm italic font-medium" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Date du Semis</label>
                  <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                </div>
             </div>

             <div className="bg-emerald-50/50 p-4 rounded-2xl border border-emerald-100/50 space-y-3">
                <span className="text-[9px] font-black text-emerald-700 uppercase tracking-widest block">Ajouter une tâche manuelle</span>
                <div className="flex flex-col sm:flex-row gap-2">
                  <input value={newStepDesc} onChange={e => setNewStepDesc(e.target.value)} placeholder="Ex: Sarclage n°1" className="flex-1 bg-white border border-stone-200 rounded-xl px-4 py-2 text-sm outline-none focus:ring-1 focus:ring-emerald-500" />
                  <div className="flex gap-2">
                    <input type="date" value={newStepDate} onChange={e => setNewStepDate(e.target.value)} className="bg-white border border-stone-200 rounded-xl px-3 py-2 text-xs font-bold" />
                    <button onClick={addStep} className="bg-emerald-600 text-white px-4 rounded-xl shadow-sm"><Plus size={18} /></button>
                  </div>
                </div>
             </div>

             <div className="space-y-3">
                {steps.length > 0 ? (
                  steps.sort((a,b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).map(step => {
                    const status = getStepStatus(step);
                    return (
                      <div key={step.id} className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                        step.completed ? 'bg-stone-50 border-stone-100 opacity-60' :
                        status === 'overdue' ? 'bg-red-50 border-red-100' :
                        status === 'upcoming' ? 'bg-amber-50 border-amber-100' : 'bg-white border-stone-100'
                      }`}>
                        <div className="flex items-center gap-4">
                           <button onClick={() => toggleStep(step.id)} className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${step.completed ? 'bg-emerald-600 border-emerald-600 text-white' : 'border-stone-300 bg-white'}`}>
                             {step.completed && <Check size={14} />}
                           </button>
                           <div>
                              <p className={`text-sm font-bold ${step.completed ? 'line-through text-stone-400' : 'text-stone-800'}`}>{step.description}</p>
                              <div className="flex items-center gap-2 mt-0.5">
                                 <span className={`text-[10px] font-bold flex items-center gap-1 uppercase ${status === 'overdue' ? 'text-red-500' : 'text-stone-400'}`}>
                                   <Calendar size={10} /> {new Date(step.deadline).toLocaleDateString('fr-FR')}
                                 </span>
                                 {status === 'overdue' && !step.completed && <span className="text-[8px] font-black bg-red-600 text-white px-1.5 py-0.5 rounded uppercase animate-pulse">Retard</span>}
                                 {status === 'upcoming' && !step.completed && <span className="text-[8px] font-black bg-amber-500 text-white px-1.5 py-0.5 rounded uppercase">Urgent</span>}
                              </div>
                           </div>
                        </div>
                        <button onClick={() => removeStep(step.id)} className="text-stone-300 hover:text-red-500 p-1"><Trash2 size={16} /></button>
                      </div>
                    );
                  })
                ) : (
                  <div className="py-12 text-center border-2 border-dashed border-stone-100 rounded-3xl">
                     <ClipboardList className="mx-auto text-stone-200 mb-2" size={32} />
                     <p className="text-xs text-stone-400 font-bold uppercase tracking-widest">Aucun plan enregistré localement</p>
                  </div>
                )}
             </div>
          </div>
        )}
      </div>

      <p className="text-[8px] text-center text-stone-300 font-bold uppercase tracking-[0.2em] py-2">
        AgroExpert Afrique • Sécurité & Sauvegarde Locale Active
      </p>
    </div>
  );
};

export default AgroExpert;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getAgroAdvice = async (prompt: string, context?: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Tu es un expert agronome africain senior. Réponds de manière précise, adaptée au contexte africain (climat, types de sols, moyens financiers).

      Question de l'utilisateur: ${prompt}
      ${context ? `Contexte supplémentaire: ${context}` : ''}`,
      config: {
        temperature: 0.7,
        topP: 0.95,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Désolé, je rencontre une difficulté technique. Veuillez réessayer plus tard.";
  }
};

export const diagnosePlant = async (imageBase64: string, mimeType: string = 'image/jpeg') => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: imageBase64 } },
          { text: "Diagnostique cette plante. Donne le nom de la maladie, les symptômes, et surtout les solutions bio et chimiques adaptées au contexte africain." }
        ]
      }
    });
    return response.text;
  } catch (error) {
    console.error("Diagnosis Error:", error);
    return "Échec du diagnostic. Assurez-vous qu'elle est bien éclairée.";
  }
};

export const generateCropItinerary = async (crop: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Génère un itinéraire technique complet et chronologique pour la culture de: ${crop} en Afrique.
      Inclus les étapes clés : préparation du sol, semis, fertilisation (N-P-K), sarclage, traitement phytosanitaire et récolte.
      Pour chaque étape, donne une description précise et le nombre de jours recommandés APRÈS le semis (J+X).

      Réponds uniquement en format JSON structuré.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              description: { type: Type.STRING },
              daysFromStart: { type: Type.NUMBER }
            },
            required: ["description", "daysFromStart"]
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Itinerary Generation Error:", error);
    return null;
  }
};

export const getFertilizerAdvice = async (crop: string, step: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `En tant qu'expert agronome africain, suggère les types d'engrais (NPK, urée, fumure organique, compost, engrais foliaire, etc.) les plus adaptés pour la culture de "${crop}" spécifiquement pour l'étape : "${step}".
      Réponds avec des dosages indicatifs (ex: kg/ha) adaptés aux réalités du terrain en Afrique.
      Format de réponse : Court, structuré en points, maximum 100 mots.`,
      config: {
        temperature: 0.5,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Fertilizer Advice Error:", error);
    return "Erreur lors de la récupération des conseils d'engrais.";
  }
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Camera, Sparkles, Loader2, Image as ImageIcon, X, RotateCcw, Copy, Check, Calendar, Plus, Trash2, ClipboardList, User, Wand2, AlertCircle, BellRing, WifiOff, Wifi, Save, Share2, Mail, Link, FlaskConical } from 'lucide-react';
import { getAgroAdvice, diagnosePlant, generateCropItinerary, getFertilizerAdvice } from '../services/geminiService';

interface Message {
  role: 'user' | 'bot';
  text: string;
  image?: string;
}

interface ItineraryStep {
  id: string;
  description: string;
  deadline: string;
  completed: boolean;
  daysFromStart?: number;
}

const STORAGE_KEYS = {
  CHAT: 'agroexpert_chat_history',
  ITINERARY: 'agroexpert_itinerary_data',
  AVATAR: 'agroexpert_user_avatar',
  EMAIL: 'agroexpert_user_email'
};

const AgroExpert: React.FC = () => {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [input, setInput] = useState('');
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Initialize states from localStorage
  const [messages, setMessages] = useState<Message[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CHAT);
    return saved ? JSON.parse(saved) : [
      { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
    ];
  });

  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [showShareSuccess, setShowShareSuccess] = useState<string | null>(null);

  // Profile states
  const [userAvatar, setUserAvatar] = useState<string | null>(() => {
    return localStorage.getItem(STORAGE_KEYS.AVATAR);
  });
  const [userEmail, setUserEmail] = useState<string>(() => {
    return localStorage.getItem(STORAGE_KEYS.EMAIL) || '';
  });
  const avatarInputRef = useRef<HTMLInputElement>(null);

  // Itinerary states
  const [itineraryData, setItineraryData] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ITINERARY);
    return saved ? JSON.parse(saved) : {
      cropName: '',
      scientificName: '',
      startDate: new Date().toISOString().split('T')[0],
      steps: [] as ItineraryStep[]
    };
  });

  const [cropName, setCropName] = useState(itineraryData.cropName);
  const [scientificName, setScientificName] = useState(itineraryData.scientificName);
  const [startDate, setStartDate] = useState(itineraryData.startDate);
  const [steps, setSteps] = useState<ItineraryStep[]>(itineraryData.steps);
  const [stepAdvice, setStepAdvice] = useState<Record<string, { text: string; loading: boolean }>>({});

  const [newStepDesc, setNewStepDesc] = useState('');
  const [newStepDate, setNewStepDate] = useState('');
  const [isItineraryOpen, setIsItineraryOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Connection listeners
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Sync state and Save to localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.CHAT, JSON.stringify(messages));
    setLastSaved(new Date());
  }, [messages]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AVATAR, userAvatar || '');
  }, [userAvatar]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.EMAIL, userEmail);
  }, [userEmail]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.ITINERARY, JSON.stringify({
      cropName,
      scientificName,
      startDate,
      steps
    }));
    setLastSaved(new Date());
  }, [cropName, scientificName, startDate, steps]);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    if (!isOnline) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const botResponse = await getAgroAdvice(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setLoading(false);
  };

  const handleReset = () => {
    if (window.confirm("Effacer l'historique ? (Les données de l'itinéraire seront conservées)")) {
      const initialMessage: Message[] = [
        { role: 'bot', text: 'Historique effacé. Comment puis-je vous aider ?' }
      ];
      setMessages(initialMessage);
    }
  };

  const getItineraryAsText = () => {
    let text = `📋 ITINÉRAIRE TECHNIQUE : ${cropName.toUpperCase() || 'Sans titre'}\n`;
    if (scientificName) text += `🧬 Nom Scientifique : ${scientificName}\n`;
    if (userEmail) text += `✉️ Contact : ${userEmail}\n`;
    text += `📅 Date de début : ${new Date(startDate).toLocaleDateString('fr-FR')}\n\n`;
    text += `ÉTAPES PRÉVUES :\n`;

    steps.slice().sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).forEach((s, i) => {
      text += `${i + 1}. [${new Date(s.deadline).toLocaleDateString('fr-FR')}] ${s.description}${s.completed ? ' ✅' : ''}\n`;
    });

    text += `\nExporté depuis AgroExpert Afrique`;
    return text;
  };

  const copyItineraryToClipboard = () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    navigator.clipboard.writeText(text).then(() => {
      setShowShareSuccess('copy');
      setTimeout(() => setShowShareSuccess(null), 3000);
    });
  };

  const shareViaEmail = () => {
    if (steps.length === 0) return;
    const subject = encodeURIComponent(`Mon Itinéraire Technique : ${cropName}`);
    const body = encodeURIComponent(getItineraryAsText());
    window.location.href = `mailto:?subject=${subject}&body=${body}`;
    setShowShareSuccess('email');
    setTimeout(() => setShowShareSuccess(null), 3000);
  };

  const shareViaNative = async () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Itinéraire ${cropName}`,
          text: text,
        });
        setShowShareSuccess('share');
        setTimeout(() => setShowShareSuccess(null), 3000);
      } catch (err) {
        copyItineraryToClipboard();
      }
    } else {
      copyItineraryToClipboard();
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !isOnline) return;
    const mimeType = file.type;

    const reader = new FileReader();
    reader.onloadstart = () => setLoading(true);
    reader.onloadend = async () => {
      const dataUrl = reader.result as string;
      const base64 = dataUrl.split(',')[1];
      setMessages(prev => [...prev, { role: 'user', text: "Diagnostic photo en cours...", image: dataUrl }]);
      const diagnosis = await diagnosePlant(base64, mimeType);
      setMessages(prev => [...prev, { role: 'bot', text: diagnosis }]);
      setLoading(false);
    };
    reader.readAsDataURL(file);
  };

  const addStep = () => {
    if (!newStepDesc || !newStepDate) return;
    const newStep: ItineraryStep = {
      id: Date.now().toString(),
      description: newStepDesc,
      deadline: newStepDate,
      completed: false,
    };
    setSteps([...steps, newStep]);
    setNewStepDesc('');
    setNewStepDate('');
  };

  const handleAiSuggest = async () => {
    if (!cropName || !isOnline) return;
    setSuggesting(true);
    const suggestedSteps = await generateCropItinerary(cropName);
    if (suggestedSteps) {
      const start = new Date(startDate);
      const newSteps: ItineraryStep[] = suggestedSteps.map((s: any, idx: number) => {
        const deadlineDate = new Date(start);
        deadlineDate.setDate(start.getDate() + s.daysFromStart);
        return {
          id: `ai-${Date.now()}-${idx}`,
          description: s.description,
          deadline: deadlineDate.toISOString().split('T')[0],
          completed: false,
          daysFromStart: s.daysFromStart
        };
      });
      setSteps(newSteps);
    }
    setSuggesting(false);
  };

  const toggleStep = (id: string) => {
    setSteps(steps.map(s => s.id === id ? { ...s, completed: !s.completed } : s));
  };

  const removeStep = (id: string) => {
    setSteps(steps.filter(s => s.id !== id));
  };

  const fetchFertilizerAdviceForStep = async (stepId: string, description: string) => {
    if (!cropName || !isOnline) return;

    // Toggle off if already showing
    if (stepAdvice[stepId] && !stepAdvice[stepId].loading) {
      const newAdvice = { ...stepAdvice };
      delete newAdvice[stepId];
      setStepAdvice(newAdvice);
      return;
    }

    setStepAdvice(prev => ({ ...prev, [stepId]: { text: '', loading: true } }));
    const advice = await getFertilizerAdvice(cropName, description);
    setStepAdvice(prev => ({ ...prev, [stepId]: { text: advice, loading: false } }));
  };

  const getStepStatus = (step: ItineraryStep) => {
    if (step.completed) return 'completed';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const deadlineDate = new Date(step.deadline);
    if (deadlineDate < today) return 'overdue';
    const diffDays = Math.ceil((deadlineDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    return diffDays <= 3 ? 'upcoming' : 'pending';
  };

  const counts = useMemo(() => {
    const today = new Date();
    today.setHours(0,0,0,0);
    return steps.reduce((acc, s) => {
      if (!s.completed) {
        const d = new Date(s.deadline);
        if (d < today) acc.overdue++;
        else if (Math.ceil((d.getTime() - today.getTime())/(86400000)) <= 3) acc.upcoming++;
      }
      return acc;
    }, { overdue: 0, upcoming: 0 });
  }, [steps]);

  return (
    <div className="flex flex-col space-y-4">
      {/* Header Statut & Profil */}
      <div className="bg-white rounded-[2rem] p-4 border border-stone-200 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4 flex-1">
          <div className="relative group cursor-pointer shrink-0" onClick={() => avatarInputRef.current?.click()}>
            <div className="w-[48px] h-[48px] rounded-full overflow-hidden border-2 border-emerald-100 flex items-center justify-center bg-stone-100 shadow-inner">
              {userAvatar ? <img src={userAvatar} className="w-full h-full object-cover" /> : <User size={24} className="text-stone-400" />}
            </div>
            <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 rounded-full transition-opacity flex items-center justify-center">
              <Camera size={14} className="text-white" />
            </div>
            <input 
              type="file" 
              ref={avatarInputRef} 
              className="hidden" 
              accept="image/png, image/gif, image/jpeg, image/jpg" 
              onChange={(e) => {
               const file = e.target.files?.[0];
               if (file) {
                 const reader = new FileReader();
                 reader.onloadend = () => setUserAvatar(reader.result as string);
                 reader.readAsDataURL(file);
               }
            }} />
          </div>
          <div className="flex-1">
            <h4 className="text-sm font-bold text-stone-900 leading-tight">Mon Espace Agricole</h4>
            <div className="flex flex-col gap-1 mt-1">
              <div className="flex items-center gap-2">
                <span className={`flex items-center gap-1 text-[9px] font-black uppercase tracking-widest ${isOnline ? 'text-emerald-600' : 'text-amber-600'}`}>
                  {isOnline ? <Wifi size={10} /> : <WifiOff size={10} />}
                  {isOnline ? 'En ligne' : 'Hors ligne'}
                </span>
                {lastSaved && (
                  <span className="text-[8px] text-stone-300 font-bold uppercase flex items-center gap-1">
                    <Save size={8} /> {lastSaved.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                  </span>
                )}
              </div>
              <input 
                type="email" 
                value={userEmail} 
                onChange={(e) => setUserEmail(e.target.value)}
                placeholder="votre@email.com"
                className="text-[10px] font-medium text-stone-600 bg-stone-50 border border-stone-100 rounded-lg px-2 py-1 outline-none focus:ring-1 focus:ring-emerald-500 w-full max-w-[180px]"
              />
            </div>
          </div>
        </div>
      </div>

      {/* Chat IA */}
      <div className="flex flex-col h-[55vh] bg-white rounded-[2rem] shadow-sm border border-stone-200 overflow-hidden relative">
        <div className="bg-emerald-600 px-6 py-4 text-white flex items-center justify-between shadow-lg relative z-10">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl"><Sparkles size={20} /></div>
            <div>
              <span className="font-bold block leading-tight">Assistant IA</span>
              <span className="text-[10px] uppercase font-black tracking-widest opacity-80 italic">Contextualisé Afrique</span>
            </div>
          </div>
          <button onClick={handleReset} className="p-2 hover:bg-white/10 rounded-xl transition-colors"><RotateCcw size={18} /></button>
        </div>

        {!isOnline && (
          <div className="bg-amber-50 px-4 py-2 border-b border-amber-100 flex items-center gap-2 animate-pulse">
            <AlertCircle size={14} className="text-amber-600" />
            <span className="text-[9px] font-black text-amber-700 uppercase tracking-widest">Connexion perdue. IA indisponible.</span>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-stone-50/50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
               <div className={`max-w-[85%] rounded-3xl p-4 shadow-sm ${
                 m.role === 'user' ? 'bg-emerald-600 text-white rounded-tr-none' : 'bg-white border border-stone-200 text-stone-800 rounded-tl-none'
               }`}>
                 {m.image && <img src={m.image} className="rounded-xl mb-2 max-h-48 w-full object-cover" />}
                 <p className="text-sm leading-relaxed">{m.text}</p>
               </div>
            </div>
          ))}
          {loading && <div className="flex gap-2 p-2"><Loader2 size={16} className="animate-spin text-emerald-600" /><span className="text-xs italic text-stone-400">L'IA réfléchit...</span></div>}
          <div ref={chatEndRef} />
        </div>

        <div className="p-4 bg-white border-t border-stone-100">
           <div className="flex items-center gap-2">
             <button onClick={() => fileInputRef.current?.click()} disabled={!isOnline} className={`p-3 rounded-2xl ${isOnline ? 'text-emerald-600 hover:bg-emerald-50' : 'text-stone-300 cursor-not-allowed'}`}><ImageIcon size={20} /></button>
             <input type="file" ref={fileInputRef} className="hidden" accept="image/png, image/gif, image/jpeg, image/jpg" onChange={handleFileUpload} />
             <input value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleSend()} disabled={!isOnline} placeholder={isOnline ? "Votre question..." : "Reconnectez-vous pour parler à l'IA"} className="flex-1 bg-stone-100 rounded-2xl px-4 py-3 text-sm outline-none disabled:opacity-50" />
             <button onClick={handleSend} disabled={!isOnline || !input.trim()} className="p-3.5 bg-emerald-600 text-white rounded-2xl shadow-lg disabled:bg-stone-200 transition-all active:scale-95"><Send size={18} /></button>
           </div>
        </div>
      </div>

      {/* Itinéraire Technique */}
      <div className="bg-white rounded-[2rem] border border-stone-200 shadow-sm overflow-hidden">
        <div className="p-6 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
             <div className="bg-amber-100 p-2.5 rounded-xl text-amber-600 relative">
               <ClipboardList size={22} />
               {(counts.overdue > 0 || counts.upcoming > 0) && <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>}
             </div>
             <div>
               <h3 className="font-bold text-stone-900 leading-tight">Itinéraire Technique</h3>
               <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest">Disponible Hors Ligne</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             {/* Share Button Group */}
             <div className="flex items-center bg-stone-50 rounded-2xl p-1 border border-stone-100">
               <button 
                onClick={shareViaEmail} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'email' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Partager par Email"
               >
                 <Mail size={18} />
               </button>
               <button 
                onClick={shareViaNative} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'share' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Partager un lien ou via application"
               >
                 <Share2 size={18} />
               </button>
               <button 
                onClick={copyItineraryToClipboard} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'copy' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Copier en texte (Lien)"
               >
                 {showShareSuccess === 'copy' ? <Check size={18} /> : <Link size={18} />}
               </button>
             </div>
             <button onClick={() => setIsItineraryOpen(!isItineraryOpen)} className="p-2.5 bg-emerald-600 text-white rounded-xl shadow-lg active:scale-95 transition-all"><Plus size={18} className={`transition-transform ${isItineraryOpen ? 'rotate-45' : ''}`} /></button>
          </div>
        </div>

        {isItineraryOpen && (
          <div className="px-6 pb-6 space-y-6 animate-in slide-in-from-top-4">
             <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Culture</label>
                  <div className="flex gap-1">
                    <input value={cropName} onChange={e => setCropName(e.target.value)} placeholder="Ex: Mil" className="flex-1 bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                    <button onClick={handleAiSuggest} disabled={!isOnline || !cropName || suggesting} className="p-2.5 bg-amber-500 text-white rounded-xl disabled:opacity-50 transition-all active:scale-90 shadow-sm">
                      {suggesting ? <Loader2 size={16} className="animate-spin" /> : <Wand2 size={16} />}
                    </button>
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Nom Scientifique</label>
                  <input value={scientificName} onChange={e => setScientificName(e.target.value)} placeholder="Ex: Pennisetum glaucum" className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm italic font-medium" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Date du Semis</label>
                  <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                </div>
             </div>

             <div className="bg-emerald-50/50 p-4 rounded-2xl border border-emerald-100/50 space-y-3">
                <span className="text-[9px] font-black text-emerald-700 uppercase tracking-widest block">Ajouter une tâche manuelle</span>
                <div className="flex flex-col sm:flex-row gap-2">
                  <input value={newStepDesc} onChange={e => setNewStepDesc(e.target.value)} placeholder="Ex: Sarclage n°1" className="flex-1 bg-white border border-stone-200 rounded-xl px-4 py-2 text-sm outline-none focus:ring-1 focus:ring-emerald-500" />
                  <div className="flex gap-2">
                    <input type="date" value={newStepDate} onChange={e => setNewStepDate(e.target.value)} className="bg-white border border-stone-200 rounded-xl px-3 py-2 text-xs font-bold" />
                    <button onClick={addStep} className="bg-emerald-600 text-white px-4 rounded-xl shadow-sm"><Plus size={18} /></button>
                  </div>
                </div>
             </div>

             <div className="space-y-3">
                {steps.length > 0 ? (
                  steps.sort((a,b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).map(step => {
                    const status = getStepStatus(step);
                    const currentAdvice = stepAdvice[step.id];

                    return (
                      <div key={step.id} className="space-y-2">
                        <div className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                          step.completed ? 'bg-stone-50 border-stone-100 opacity-60' :
                          status === 'overdue' ? 'bg-red-50 border-red-100' :
                          status === 'upcoming' ? 'bg-amber-50 border-amber-100' : 'bg-white border-stone-100'
                        }`}>
                          <div className="flex items-center gap-4 flex-1">
                             <button onClick={() => toggleStep(step.id)} className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${step.completed ? 'bg-emerald-600 border-emerald-600 text-white' : 'border-stone-300 bg-white'}`}>
                               {step.completed && <Check size={14} />}
                             </button>
                             <div className="flex-1">
                                <p className={`text-sm font-bold ${step.completed ? 'line-through text-stone-400' : 'text-stone-800'}`}>{step.description}</p>
                                <div className="flex items-center gap-2 mt-0.5">
                                   <span className={`text-[10px] font-bold flex items-center gap-1 uppercase ${status === 'overdue' ? 'text-red-500' : 'text-stone-400'}`}>
                                     <Calendar size={10} /> {new Date(step.deadline).toLocaleDateString('fr-FR')}
                                   </span>
                                   {status === 'overdue' && !step.completed && <span className="text-[8px] font-black bg-red-600 text-white px-1.5 py-0.5 rounded uppercase animate-pulse">Retard</span>}
                                   {status === 'upcoming' && !step.completed && <span className="text-[8px] font-black bg-amber-500 text-white px-1.5 py-0.5 rounded uppercase">Urgent</span>}
                                </div>
                             </div>
                          </div>

                          <div className="flex items-center gap-2">
                            <button 
                              onClick={() => fetchFertilizerAdviceForStep(step.id, step.description)} 
                              disabled={!isOnline || !cropName}
                              className={`p-2 rounded-xl transition-all ${currentAdvice ? 'bg-emerald-600 text-white' : 'text-emerald-600 bg-emerald-50 hover:bg-emerald-100 disabled:opacity-30'}`}
                              title="Conseils Engrais IA"
                            >
                              {currentAdvice?.loading ? <Loader2 size={16} className="animate-spin" /> : <FlaskConical size={16} />}
                            </button>
                            <button onClick={() => removeStep(step.id)} className="text-stone-300 hover:text-red-500 p-1"><Trash2 size={16} /></button>
                          </div>
                        </div>

                        {/* Fertilizer Advice Dropdown */}
                        {currentAdvice && !currentAdvice.loading && (
                          <div className="bg-emerald-900 text-emerald-50 p-4 rounded-2xl text-xs leading-relaxed border border-emerald-800 animate-in slide-in-from-top-2">
                            <div className="flex items-center gap-2 mb-2 text-emerald-400">
                              <Sparkles size={14} />
                              <span className="font-black uppercase tracking-widest text-[9px]">Recommandations Fertilisation</span>
                            </div>
                            <div className="whitespace-pre-wrap font-medium">{currentAdvice.text}</div>
                          </div>
                        )}
                      </div>
                    );
                  })
                ) : (
                  <div className="py-12 text-center border-2 border-dashed border-stone-100 rounded-3xl">
                     <ClipboardList className="mx-auto text-stone-200 mb-2" size={32} />
                     <p className="text-xs text-stone-400 font-bold uppercase tracking-widest">Aucun plan enregistré localement</p>
                  </div>
                )}
             </div>
          </div>
        )}
      </div>

      <p className="text-[8px] text-center text-stone-300 font-bold uppercase tracking-[0.2em] py-2">
        AgroExpert Afrique • Sécurité & Sauvegarde Locale Active
      </p>
    </div>
  );
};

