        </div>
      );
    }

    switch (activeTab) {
      case 'home':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            {/* Weather Section */}
            <section className="bg-white rounded-3xl p-6 shadow-sm border border-stone-100 overflow-hidden relative">
              <div className="flex items-center justify-between mb-6 relative z-10">
                <div className="flex items-center gap-3">
                  <div className={`p-2.5 rounded-2xl flex items-center justify-center ${weatherData?.condition.toLowerCase().includes('soleil') ? 'bg-amber-100' : 'bg-stone-100'}`}>
                    {weatherLoading ? <Loader2 size={24} className="animate-spin text-stone-300" /> : getWeatherIcon(weatherData?.condition, 28)}
                  </div>
                  <div>
                    <h2 className="text-lg font-bold text-stone-900 leading-tight">Météo Locale</h2>
                    <div className="flex items-center gap-1 text-stone-400">
                      <MapPin size={12} />
                      <span className="text-[10px] font-bold uppercase tracking-wider">
                        {weatherLoading ? "Localisation..." : weatherData?.location || "N'Djamena (Par défaut)"}
