export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Camera, Sparkles, Loader2, Image as ImageIcon, X, RotateCcw, Copy, Check, Calendar, Plus, Trash2, ClipboardList, User, Wand2, AlertCircle, BellRing, WifiOff, Wifi, Save, Share2, Mail, Link, FlaskConical, Beaker, Sprout, Bug, Droplets, Mountain, Scissors, CheckCircle2, Lightbulb } from 'lucide-react';
import { getAgroAdvice, diagnosePlant, generateCropItinerary, getFertilizerAdvice, getCropFertilizationPlan } from '../services/geminiService';

interface Message {
  role: 'user' | 'bot';
  text: string;
  image?: string;
}

interface ItineraryStep {
  id: string;
  description: string;
  deadline: string;
  completed: boolean;
  daysFromStart?: number;
}

const STORAGE_KEYS = {
  CHAT: 'agroexpert_chat_history',
  ITINERARY: 'agroexpert_itinerary_data',
  AVATAR: 'agroexpert_user_avatar',
  EMAIL: 'agroexpert_user_email'
};

const AgroExpert: React.FC = () => {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [input, setInput] = useState('');
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Initialize states from localStorage
  const [messages, setMessages] = useState<Message[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CHAT);
    return saved ? JSON.parse(saved) : [
      { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
    ];
  });

  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [fetchingGlobalFert, setFetchingGlobalFert] = useState(false);
  const [showShareSuccess, setShowShareSuccess] = useState<string | null>(null);

  // Profile states
  const [userAvatar, setUserAvatar] = useState<string | null>(() => {
    return localStorage.getItem(STORAGE_KEYS.AVATAR);
  });
  const [userEmail, setUserEmail] = useState<string>(() => {
    return localStorage.getItem(STORAGE_KEYS.EMAIL) || '';
  });
  const avatarInputRef = useRef<HTMLInputElement>(null);

  // Itinerary states
  const [itineraryData, setItineraryData] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ITINERARY);
    return saved ? JSON.parse(saved) : {
      cropName: '',
      scientificName: '',
      startDate: new Date().toISOString().split('T')[0],
      steps: [] as ItineraryStep[]
    };
  });

  const [cropName, setCropName] = useState(itineraryData.cropName);
  const [scientificName, setScientificName] = useState(itineraryData.scientificName);
  const [startDate, setStartDate] = useState(itineraryData.startDate);
  const [steps, setSteps] = useState<ItineraryStep[]>(itineraryData.steps);
  const [stepAdvice, setStepAdvice] = useState<Record<string, { text: string; loading: boolean }>>({});
  const [globalFertPlan, setGlobalFertPlan] = useState<string | null>(null);

  const [newStepDesc, setNewStepDesc] = useState('');
  const [newStepDate, setNewStepDate] = useState('');
  const [isItineraryOpen, setIsItineraryOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Helper to get thematic icon for steps
  const getStepIconWithContext = (description: string) => {
    const desc = description.toLowerCase();
    let icon = <ClipboardList size={16} />;
    let colorClass = "bg-stone-100 text-stone-600";

    if (desc.includes('semis') || desc.includes('plant')) {
      icon = <Sprout size={16} />;
      colorClass = "bg-emerald-100 text-emerald-600";
    } else if (desc.includes('fertili') || desc.includes('engrais') || desc.includes('npk') || desc.includes('urée')) {
      icon = <FlaskConical size={16} />;
      colorClass = "bg-purple-100 text-purple-600";
    } else if (desc.includes('traitement') || desc.includes('phyto') || desc.includes('pulv') || desc.includes('insect') || desc.includes('maladie')) {
      icon = <Bug size={16} />;
      colorClass = "bg-red-100 text-red-600";
    } else if (desc.includes('arrosage') || desc.includes('irrigation')) {
      icon = <Droplets size={16} />;
      colorClass = "bg-blue-100 text-blue-600";
    } else if (desc.includes('sarclage') || desc.includes('désherb') || desc.includes('nettoyage')) {
      icon = <Scissors size={16} />;
      colorClass = "bg-amber-100 text-amber-600";
    } else if (desc.includes('récolte')) {
      icon = <CheckCircle2 size={16} />;
      colorClass = "bg-emerald-600 text-white";
    } else if (desc.includes('labour') || desc.includes('sol') || desc.includes('prépar')) {
      icon = <Mountain size={16} />;
      colorClass = "bg-orange-100 text-orange-700";
    }

    return { icon, colorClass };
  };

  const isFertilizationStep = (description: string) => {
    const desc = description.toLowerCase();
    return desc.includes('fertili') || desc.includes('engrais') || desc.includes('npk') || desc.includes('urée') || desc.includes('fumure');
  };

  // Connection listeners
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Sync state and Save to localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.CHAT, JSON.stringify(messages));
    setLastSaved(new Date());
  }, [messages]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AVATAR, userAvatar || '');
  }, [userAvatar]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.EMAIL, userEmail);
  }, [userEmail]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.ITINERARY, JSON.stringify({
      cropName,
      scientificName,
      startDate,
      steps
    }));
    setLastSaved(new Date());
  }, [cropName, scientificName, startDate, steps]);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    if (!isOnline) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const botResponse = await getAgroAdvice(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setLoading(false);
  };

  const handleReset = () => {
    if (window.confirm("Effacer l'historique ? (Les données de l'itinéraire seront conservées)")) {
      const initialMessage: Message[] = [
        { role: 'bot', text: 'Historique effacé. Comment puis-je vous aider ?' }
      ];
      setMessages(initialMessage);
    }
  };

  const getItineraryAsText = () => {
    let text = `📋 ITINÉRAIRE TECHNIQUE : ${cropName.toUpperCase() || 'Sans titre'}\n`;
    if (scientificName) text += `🧬 Nom Scientifique : ${scientificName}\n`;
    if (userEmail) text += `✉️ Contact : ${userEmail}\n`;
    text += `📅 Date de début : ${new Date(startDate).toLocaleDateString('fr-FR')}\n\n`;
    text += `ÉTAPES PRÉVUES :\n`;

    steps.slice().sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).forEach((s, i) => {
      text += `${i + 1}. [${new Date(s.deadline).toLocaleDateString('fr-FR')}] ${s.description}${s.completed ? ' ✅' : ''}\n`;
    });

    if (globalFertPlan) {
      text += `\n🧪 PLAN DE FERTILISATION :\n${globalFertPlan}\n`;
    }

    text += `\nExporté depuis AgroExpert Afrique`;
    return text;
  };

  const copyItineraryToClipboard = () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    navigator.clipboard.writeText(text).then(() => {
      setShowShareSuccess('copy');
      setTimeout(() => setShowShareSuccess(null), 3000);
    });
  };

  const shareViaEmail = () => {
    if (steps.length === 0) return;
    const subject = encodeURIComponent(`Mon Itinéraire Technique : ${cropName}`);
    const body = encodeURIComponent(getItineraryAsText());
    window.location.href = `mailto:?subject=${subject}&body=${body}`;
    setShowShareSuccess('email');
    setTimeout(() => setShowShareSuccess(null), 3000);
  };

  const shareViaNative = async () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Itinéraire ${cropName}`,
          text: text,
        });
        setShowShareSuccess('share');
        setTimeout(() => setShowShareSuccess(null), 3000);
      } catch (err) {
        copyItineraryToClipboard();
      }
    } else {
      copyItineraryToClipboard();
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !isOnline) return;
    const mimeType = file.type;

    const reader = new FileReader();
    reader.onloadstart = () => setLoading(true);
    reader.onloadend = async () => {
      const dataUrl = reader.result as string;
      const base64 = dataUrl.split(',')[1];
      setMessages(prev => [...prev, { role: 'user', text: "Diagnostic photo en cours...", image: dataUrl }]);
      const diagnosis = await diagnosePlant(base64, mimeType);
      setMessages(prev => [...prev, { role: 'bot', text: diagnosis }]);
      setLoading(false);
    };
    reader.readAsDataURL(file);
  };

  const addStep = () => {
    if (!newStepDesc || !newStepDate) return;
    const newStep: ItineraryStep = {
      id: Date.now().toString(),
      description: newStepDesc,
      deadline: newStepDate,
      completed: false,
    };
    setSteps([...steps, newStep]);
    setNewStepDesc('');
    setNewStepDate('');
  };

  const handleAiSuggest = async () => {
    if (!cropName || !isOnline) return;
    setSuggesting(true);
    const suggestedSteps = await generateCropItinerary(cropName);
    if (suggestedSteps) {
      const start = new Date(startDate);
      const newSteps: ItineraryStep[] = suggestedSteps.map((s: any, idx: number) => {
        const deadlineDate = new Date(start);
        deadlineDate.setDate(start.getDate() + s.daysFromStart);
        return {
          id: `ai-${Date.now()}-${idx}`,
          description: s.description,
          deadline: deadlineDate.toISOString().split('T')[0],
          completed: false,
          daysFromStart: s.daysFromStart
        };
      });
      setSteps(newSteps);
    }
    setSuggesting(false);
  };

  const handleFetchGlobalFert = async () => {
    if (!cropName || !isOnline) return;
    setFetchingGlobalFert(true);
    const plan = await getCropFertilizationPlan(cropName);
    setGlobalFertPlan(plan);
    setFetchingGlobalFert(false);
  };

  const toggleStep = (id: string) => {
    setSteps(steps.map(s => s.id === id ? { ...s, completed: !s.completed } : s));
  };

  const removeStep = (id: string) => {
    setSteps(steps.filter(s => s.id !== id));
  };

  const fetchFertilizerAdviceForStep = async (stepId: string, description: string) => {
    if (!cropName || !isOnline) return;

    // Toggle off if already showing
    if (stepAdvice[stepId] && !stepAdvice[stepId].loading) {
      const newAdvice = { ...stepAdvice };
      delete newAdvice[stepId];
      setStepAdvice(newAdvice);
      return;
    }

    setStepAdvice(prev => ({ ...prev, [stepId]: { text: '', loading: true } }));
    const advice = await getFertilizerAdvice(cropName, description);
    setStepAdvice(prev => ({ ...prev, [stepId]: { text: advice, loading: false } }));
  };

  const getStepStatus = (step: ItineraryStep) => {
    if (step.completed) return 'completed';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const deadlineDate = new Date(step.deadline);
    if (deadlineDate < today) return 'overdue';
    const diffDays = Math.ceil((deadlineDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    return diffDays <= 3 ? 'upcoming' : 'pending';
  };

  const counts = useMemo(() => {
    const today = new Date();
    today.setHours(0,0,0,0);
    return steps.reduce((acc, s) => {
      if (!s.completed) {
        const d = new Date(s.deadline);
        if (d < today) acc.overdue++;
        else if (Math.ceil((d.getTime() - today.getTime())/(86400000)) <= 3) acc.upcoming++;
      }
      return acc;
    }, { overdue: 0, upcoming: 0 });
  }, [steps]);

  // Current stage logic
  const currentStageInfo = useMemo(() => {
    if (!cropName || steps.length === 0) return null;
    const today = new Date();
    today.setHours(0,0,0,0);
    const sorted = [...steps].sort((a,b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime());
    // Find the current active step (not completed and closest to today)
    const active = sorted.find(s => !s.completed && new Date(s.deadline) >= today);
    return active ? active.description : "Phase de récolte ou fin de cycle";
  }, [steps, cropName]);

  return (
    <div className="flex flex-col space-y-4">
      {/* Header Statut & Profil */}
      <div className="bg-white rounded-[2rem] p-4 border border-stone-200 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4 flex-1">
          <div className="relative group cursor-pointer shrink-0" onClick={() => avatarInputRef.current?.click()}>
            <div className="w-[48px] h-[48px] rounded-full overflow-hidden border-2 border-emerald-100 flex items-center justify-center bg-stone-100 shadow-inner">
              {userAvatar ? <img src={userAvatar} className="w-full h-full object-cover" /> : <User size={24} className="text-stone-400" />}
            </div>
            <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 rounded-full transition-opacity flex items-center justify-center">
              <Camera size={14} className="text-white" />
            </div>
            <input 
              type="file" 
              ref={avatarInputRef} 
              className="hidden" 
              accept="image/png, image/gif, image/jpeg, image/jpg" 
              onChange={(e) => {
               const file = e.target.files?.[0];
               if (file) {
                 const reader = new FileReader();
                 reader.onloadend = () => setUserAvatar(reader.result as string);
                 reader.readAsDataURL(file);
               }
            }} />
          </div>
          <div className="flex-1">
            <h4 className="text-sm font-bold text-stone-900 leading-tight">Mon Espace Agricole</h4>
            <div className="flex flex-col gap-1 mt-1">
              <div className="flex items-center gap-2">
                <span className={`flex items-center gap-1 text-[9px] font-black uppercase tracking-widest ${isOnline ? 'text-emerald-600' : 'text-amber-600'}`}>
                  {isOnline ? <Wifi size={10} /> : <WifiOff size={10} />}
                  {isOnline ? 'En ligne' : 'Hors ligne'}
                </span>
                {lastSaved && (
                  <span className="text-[8px] text-stone-300 font-bold uppercase flex items-center gap-1">
                    <Save size={8} /> {lastSaved.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                  </span>
                )}
              </div>
              <input 
                type="email" 
                value={userEmail} 
                onChange={(e) => setUserEmail(e.target.value)}
                placeholder="votre@email.com"
                className="text-[10px] font-medium text-stone-600 bg-stone-50 border border-stone-100 rounded-lg px-2 py-1 outline-none focus:ring-1 focus:ring-emerald-500 w-full max-w-[180px]"
              />
            </div>
          </div>
        </div>
      </div>

      {/* Chat IA */}
      <div className="flex flex-col h-[55vh] bg-white rounded-[2rem] shadow-sm border border-stone-200 overflow-hidden relative">
        <div className="bg-emerald-600 px-6 py-4 text-white flex items-center justify-between shadow-lg relative z-10">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl"><Sparkles size={20} /></div>
            <div>
              <span className="font-bold block leading-tight">Assistant IA</span>
              <span className="text-[10px] uppercase font-black tracking-widest opacity-80 italic">Contextualisé Afrique</span>
            </div>
          </div>
          <button onClick={handleReset} className="p-2 hover:bg-white/10 rounded-xl transition-colors"><RotateCcw size={18} /></button>
        </div>

        {!isOnline && (
          <div className="bg-amber-50 px-4 py-2 border-b border-amber-100 flex items-center gap-2 animate-pulse">
            <AlertCircle size={14} className="text-amber-600" />
            <span className="text-[9px] font-black text-amber-700 uppercase tracking-widest">Connexion perdue. IA indisponible.</span>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-stone-50/50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
               <div className={`max-w-[85%] rounded-3xl p-4 shadow-sm ${
                 m.role === 'user' ? 'bg-emerald-600 text-white rounded-tr-none' : 'bg-white border border-stone-200 text-stone-800 rounded-tl-none'
               }`}>
                 {m.image && <img src={m.image} className="rounded-xl mb-2 max-h-48 w-full object-cover" />}
                 <p className="text-sm leading-relaxed">{m.text}</p>
               </div>
            </div>
          ))}
          {loading && <div className="flex gap-2 p-2"><Loader2 size={16} className="animate-spin text-emerald-600" /><span className="text-xs italic text-stone-400">L'IA réfléchit...</span></div>}
          <div ref={chatEndRef} />
        </div>

        <div className="p-4 bg-white border-t border-stone-100">
           <div className="flex items-center gap-2">
             <button onClick={() => fileInputRef.current?.click()} disabled={!isOnline} className={`p-3 rounded-2xl ${isOnline ? 'text-emerald-600 hover:bg-emerald-50' : 'text-stone-300 cursor-not-allowed'}`}><ImageIcon size={20} /></button>
             <input type="file" ref={fileInputRef} className="hidden" accept="image/png, image/gif, image/jpeg, image/jpg" onChange={handleFileUpload} />
             <input value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleSend()} disabled={!isOnline} placeholder={isOnline ? "Votre question..." : "Reconnectez-vous pour parler à l'IA"} className="flex-1 bg-stone-100 rounded-2xl px-4 py-3 text-sm outline-none disabled:opacity-50" />
             <button onClick={handleSend} disabled={!isOnline || !input.trim()} className="p-3.5 bg-emerald-600 text-white rounded-2xl shadow-lg disabled:bg-stone-200 transition-all active:scale-95"><Send size={18} /></button>
           </div>
        </div>
      </div>

      {/* Itinéraire Technique */}
      <div className="bg-white rounded-[2rem] border border-stone-200 shadow-sm overflow-hidden">
        <div className="p-6 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
             <div className="bg-amber-100 p-2.5 rounded-xl text-amber-600 relative">
               <ClipboardList size={22} />
               {(counts.overdue > 0 || counts.upcoming > 0) && <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>}
             </div>
             <div>
               <h3 className="font-bold text-stone-900 leading-tight">Itinéraire Technique</h3>
               <p className="text-[10px] text-stone-400 font-black uppercase tracking-widest">Disponible Hors Ligne</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             {/* Share Button Group */}
             <div className="flex items-center bg-stone-50 rounded-2xl p-1 border border-stone-100">
               <button 
                onClick={shareViaEmail} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'email' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Partager par Email"
               >
                 <Mail size={18} />
               </button>
               <button 
                onClick={shareViaNative} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'share' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Partager un lien ou via application"
               >
                 <Share2 size={18} />
               </button>
               <button 
                onClick={copyItineraryToClipboard} 
                disabled={steps.length === 0} 
                className={`p-2 rounded-xl transition-all ${showShareSuccess === 'copy' ? 'bg-emerald-500 text-white' : 'text-stone-500 hover:bg-white hover:text-emerald-600'}`}
                title="Copier en texte (Lien)"
               >
                 {showShareSuccess === 'copy' ? <Check size={18} /> : <Link size={18} />}
               </button>
             </div>
             <button onClick={() => setIsItineraryOpen(!isItineraryOpen)} className="p-2.5 bg-emerald-600 text-white rounded-xl shadow-lg active:scale-95 transition-all"><Plus size={18} className={`transition-transform ${isItineraryOpen ? 'rotate-45' : ''}`} /></button>
          </div>
        </div>

        {isItineraryOpen && (
          <div className="px-6 pb-6 space-y-6 animate-in slide-in-from-top-4">
             <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Culture</label>
                  <div className="flex gap-1">
                    <input value={cropName} onChange={e => setCropName(e.target.value)} placeholder="Ex: Mil" className="flex-1 bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                    <button onClick={handleAiSuggest} disabled={!isOnline || !cropName || suggesting} className="p-2.5 bg-amber-500 text-white rounded-xl disabled:opacity-50 transition-all active:scale-90 shadow-sm">
                      {suggesting ? <Loader2 size={16} className="animate-spin" /> : <Wand2 size={16} />}
                    </button>
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Nom Scientifique</label>
                  <input value={scientificName} onChange={e => setScientificName(e.target.value)} placeholder="Ex: Pennisetum glaucum" className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm italic font-medium" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-stone-400 uppercase tracking-widest ml-1">Date du Semis</label>
                  <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl px-3 py-2.5 text-sm font-bold" />
                </div>
             </div>

             {/* Dynamic Fertilizer Section */}
             {cropName && (
               <div className="bg-stone-900 rounded-3xl p-5 border border-stone-800 text-white relative overflow-hidden group">
                  <div className="relative z-10">
                    <div className="flex items-center justify-between mb-4">
                      <div className="flex items-center gap-3">
                        <div className="bg-emerald-500/20 p-2.5 rounded-xl text-emerald-400">
                          <Beaker size={20} />
                        </div>
                        <div>
                          <span className="block text-[9px] font-black uppercase tracking-[0.2em] text-stone-400 mb-0.5">Focus Fertilisation</span>
                          <h4 className="text-sm font-bold">Suggestions pour : {cropName}</h4>
                        </div>
                      </div>
                      <button 
                        onClick={handleFetchGlobalFert}
                        disabled={!isOnline || fetchingGlobalFert}
                        className="bg-emerald-600 hover:bg-emerald-500 text-white text-[10px] font-black uppercase tracking-widest px-4 py-2 rounded-xl transition-all disabled:opacity-50"
                      >
                        {fetchingGlobalFert ? <Loader2 size={14} className="animate-spin" /> : "Générer Plan"}
                      </button>
                    </div>

                    {currentStageInfo && (
                      <div className="bg-stone-800/50 rounded-2xl p-3 border border-stone-700/50 mb-3">
                        <span className="text-[8px] font-black text-emerald-400 uppercase tracking-widest mb-1 block">Étape Actuelle (IA)</span>
                        <p className="text-xs font-bold italic">"{currentStageInfo}"</p>
                      </div>
                    )}

                    {globalFertPlan ? (
                      <div className="text-xs text-stone-300 leading-relaxed max-h-40 overflow-y-auto pr-2 custom-scrollbar whitespace-pre-wrap">
                        {globalFertPlan}
                      </div>
                    ) : (
                      <p className="text-[10px] text-stone-500 italic">Cliquez sur "Générer Plan" pour obtenir des recommandations d'engrais (NPK, Organique, Urée) adaptées au cycle complet.</p>
                    )}
                  </div>
                  {/* Background decoration */}
                  <div className="absolute top-0 right-0 w-24 h-24 bg-emerald-500/5 rounded-full blur-3xl group-hover:bg-emerald-500/10 transition-all"></div>
               </div>
             )}

             <div className="bg-emerald-50/50 p-4 rounded-2xl border border-emerald-100/50 space-y-3">
                <span className="text-[9px] font-black text-emerald-700 uppercase tracking-widest block">Ajouter une tâche manuelle</span>
                <div className="flex flex-col sm:flex-row gap-2">
                  <input value={newStepDesc} onChange={e => setNewStepDesc(e.target.value)} placeholder="Ex: Sarclage n°1" className="flex-1 bg-white border border-stone-200 rounded-xl px-4 py-2 text-sm outline-none focus:ring-1 focus:ring-emerald-500" />
                  <div className="flex gap-2">
                    <input type="date" value={newStepDate} onChange={e => setNewStepDate(e.target.value)} className="bg-white border border-stone-200 rounded-xl px-3 py-2 text-xs font-bold" />
                    <button onClick={addStep} className="bg-emerald-600 text-white px-4 rounded-xl shadow-sm"><Plus size={18} /></button>
                  </div>
                </div>
             </div>

             <div className="space-y-3">
                {steps.length > 0 ? (
                  steps.sort((a,b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).map(step => {
                    const status = getStepStatus(step);
                    const currentAdvice = stepAdvice[step.id];
                    const { icon, colorClass } = getStepIconWithContext(step.description);
                    const isFert = isFertilizationStep(step.description);

                    return (
                      <div key={step.id} className="space-y-2">
                        <div className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                          step.completed ? 'bg-stone-50 border-stone-100 opacity-60' :
                          status === 'overdue' ? 'bg-red-50 border-red-100' :
                          status === 'upcoming' ? 'bg-amber-50 border-amber-100' : 'bg-white border-stone-100 shadow-sm'
                        }`}>
                          <div className="flex items-center gap-4 flex-1">
                             <button onClick={() => toggleStep(step.id)} className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${step.completed ? 'bg-emerald-600 border-emerald-600 text-white' : 'border-stone-300 bg-white'}`}>
                               {step.completed && <Check size={14} />}
                             </button>
                             <div className="flex items-center gap-3 flex-1">
                                <div className={`p-2 rounded-xl shadow-sm shrink-0 ${colorClass}`}>
                                  {icon}
                                </div>
                                <div className="flex-1">
                                  <div className="flex items-center gap-2">
                                    <p className={`text-sm font-bold ${step.completed ? 'line-through text-stone-400' : 'text-stone-800'}`}>{step.description}</p>
                                    {isFert && !currentAdvice && !step.completed && (
                                      <span className="flex items-center gap-1 text-[8px] font-black bg-purple-100 text-purple-700 px-1.5 py-0.5 rounded uppercase animate-pulse">
                                        <Lightbulb size={10} /> Conseil dispo
                                      </span>
                                    )}
                                  </div>
                                  <div className="flex items-center gap-2 mt-0.5">
                                     <span className={`text-[10px] font-bold flex items-center gap-1 uppercase ${status === 'overdue' ? 'text-red-500' : 'text-stone-400'}`}>
                                       <Calendar size={10} /> {new Date(step.deadline).toLocaleDateString('fr-FR')}
                                     </span>
                                     {status === 'overdue' && !step.completed && <span className="text-[8px] font-black bg-red-600 text-white px-1.5 py-0.5 rounded uppercase animate-pulse">Retard</span>}
                                     {status === 'upcoming' && !step.completed && <span className="text-[8px] font-black bg-amber-500 text-white px-1.5 py-0.5 rounded uppercase">Urgent</span>}
                                  </div>
                                </div>
                             </div>
                          </div>

                          <div className="flex items-center gap-2">
                            <button 
                              onClick={() => fetchFertilizerAdviceForStep(step.id, step.description)} 
                              disabled={!isOnline || !cropName}
                              className={`p-2 rounded-xl transition-all shadow-sm ${currentAdvice ? 'bg-emerald-600 text-white rotate-12 scale-110' : 'text-emerald-600 bg-emerald-50 hover:bg-emerald-100 disabled:opacity-30'}`}
                              title="Conseils Engrais IA"
                            >
                              {currentAdvice?.loading ? <Loader2 size={16} className="animate-spin" /> : <FlaskConical size={16} />}
                            </button>
                            <button onClick={() => removeStep(step.id)} className="text-stone-300 hover:text-red-500 p-1 transition-colors"><Trash2 size={16} /></button>
                          </div>
                        </div>

                        {/* Fertilizer Advice Dropdown */}
                        {currentAdvice && !currentAdvice.loading && (
                          <div className="bg-emerald-900 text-emerald-50 p-5 rounded-3xl text-xs leading-relaxed border border-emerald-800 animate-in slide-in-from-top-2 ml-10 shadow-xl relative">
                            <div className="flex items-center justify-between mb-3">
                              <div className="flex items-center gap-2 text-emerald-400">
                                <Beaker size={14} />
                                <span className="font-black uppercase tracking-widest text-[9px]">Recommandations Fertilisation IA</span>
                              </div>
                              <button onClick={() => fetchFertilizerAdviceForStep(step.id, step.description)} className="text-emerald-400 hover:text-white transition-colors">
                                <X size={14} />
                              </button>
                            </div>
                            <div className="whitespace-pre-wrap font-medium text-stone-200 bg-emerald-950/40 p-3 rounded-2xl border border-emerald-800/50">
                              {currentAdvice.text}
                            </div>
                            <div className="mt-3 flex items-center gap-1.5 text-[8px] font-bold text-emerald-500 uppercase tracking-widest opacity-60">
                              <Sparkles size={8} /> Dosages indicatifs pour contexte local
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })
                ) : (
                  <div className="py-12 text-center border-2 border-dashed border-stone-100 rounded-3xl">
                     <ClipboardList className="mx-auto text-stone-200 mb-2" size={32} />
                     <p className="text-xs text-stone-400 font-bold uppercase tracking-widest">Aucun plan enregistré localement</p>
                  </div>
                )}
             </div>
          </div>
        )}
      </div>

      <p className="text-[8px] text-center text-stone-300 font-bold uppercase tracking-[0.2em] py-2">
        AgroExpert Afrique • Sécurité & Sauvegarde Locale Active
      </p>
    </div>
  );
};

export default AgroExpert;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Camera, Sparkles, Loader2, Image as ImageIcon, X, RotateCcw, Copy, Check, Calendar, Plus, Trash2, ClipboardList, User, Wand2, AlertCircle, BellRing, WifiOff, Wifi, Save, Share2, Mail, Link, FlaskConical, Beaker, Sprout, Bug, Droplets, Mountain, Scissors, CheckCircle2, Lightbulb, FileDown } from 'lucide-react';
import { getAgroAdvice, diagnosePlant, generateCropItinerary, getFertilizerAdvice, getCropFertilizationPlan } from '../services/geminiService';

interface Message {
  role: 'user' | 'bot';
  text: string;
  image?: string;
}

interface ItineraryStep {
  id: string;
  description: string;
  deadline: string;
  completed: boolean;
  daysFromStart?: number;
}

const STORAGE_KEYS = {
  CHAT: 'agroexpert_chat_history',
  ITINERARY: 'agroexpert_itinerary_data',
  AVATAR: 'agroexpert_user_avatar',
  EMAIL: 'agroexpert_user_email'
};

const AgroExpert: React.FC = () => {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [input, setInput] = useState('');
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Initialize states from localStorage
  const [messages, setMessages] = useState<Message[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CHAT);
    return saved ? JSON.parse(saved) : [
      { role: 'bot', text: 'Bonjour ! Je suis votre assistant agronome. Comment puis-je vous aider aujourd\'hui ? Vous pouvez me poser une question ou m\'envoyer une photo d\'une plante pour un diagnostic.' }
    ];
  });

  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [fetchingGlobalFert, setFetchingGlobalFert] = useState(false);
  const [showShareSuccess, setShowShareSuccess] = useState<string | null>(null);

  // Profile states
  const [userAvatar, setUserAvatar] = useState<string | null>(() => {
    return localStorage.getItem(STORAGE_KEYS.AVATAR);
  });
  const [userEmail, setUserEmail] = useState<string>(() => {
    return localStorage.getItem(STORAGE_KEYS.EMAIL) || '';
  });
  const avatarInputRef = useRef<HTMLInputElement>(null);

  // Itinerary states
  const [itineraryData, setItineraryData] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ITINERARY);
    return saved ? JSON.parse(saved) : {
      cropName: '',
      scientificName: '',
      startDate: new Date().toISOString().split('T')[0],
      steps: [] as ItineraryStep[]
    };
  });

  const [cropName, setCropName] = useState(itineraryData.cropName);
  const [scientificName, setScientificName] = useState(itineraryData.scientificName);
  const [startDate, setStartDate] = useState(itineraryData.startDate);
  const [steps, setSteps] = useState<ItineraryStep[]>(itineraryData.steps);
  const [stepAdvice, setStepAdvice] = useState<Record<string, { text: string; loading: boolean }>>({});
  const [globalFertPlan, setGlobalFertPlan] = useState<string | null>(null);

  const [newStepDesc, setNewStepDesc] = useState('');
  const [newStepDate, setNewStepDate] = useState('');
  const [isItineraryOpen, setIsItineraryOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Helper to get thematic icon for steps
  const getStepIconWithContext = (description: string) => {
    const desc = description.toLowerCase();
    let icon = <ClipboardList size={16} />;
    let colorClass = "bg-stone-100 text-stone-600";

    if (desc.includes('semis') || desc.includes('plant')) {
      icon = <Sprout size={16} />;
      colorClass = "bg-emerald-100 text-emerald-600";
    } else if (desc.includes('fertili') || desc.includes('engrais') || desc.includes('npk') || desc.includes('urée')) {
      icon = <FlaskConical size={16} />;
      colorClass = "bg-purple-100 text-purple-600";
    } else if (desc.includes('traitement') || desc.includes('phyto') || desc.includes('pulv') || desc.includes('insect') || desc.includes('maladie')) {
      icon = <Bug size={16} />;
      colorClass = "bg-red-100 text-red-600";
    } else if (desc.includes('arrosage') || desc.includes('irrigation')) {
      icon = <Droplets size={16} />;
      colorClass = "bg-blue-100 text-blue-600";
    } else if (desc.includes('sarclage') || desc.includes('désherb') || desc.includes('nettoyage')) {
      icon = <Scissors size={16} />;
      colorClass = "bg-amber-100 text-amber-600";
    } else if (desc.includes('récolte')) {
      icon = <CheckCircle2 size={16} />;
      colorClass = "bg-emerald-600 text-white";
    } else if (desc.includes('labour') || desc.includes('sol') || desc.includes('prépar')) {
      icon = <Mountain size={16} />;
      colorClass = "bg-orange-100 text-orange-700";
    }

    return { icon, colorClass };
  };

  const isFertilizationStep = (description: string) => {
    const desc = description.toLowerCase();
    return desc.includes('fertili') || desc.includes('engrais') || desc.includes('npk') || desc.includes('urée') || desc.includes('fumure');
  };

  // Connection listeners
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Sync state and Save to localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.CHAT, JSON.stringify(messages));
    setLastSaved(new Date());
  }, [messages]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AVATAR, userAvatar || '');
  }, [userAvatar]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.EMAIL, userEmail);
  }, [userEmail]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.ITINERARY, JSON.stringify({
      cropName,
      scientificName,
      startDate,
      steps
    }));
    setLastSaved(new Date());
  }, [cropName, scientificName, startDate, steps]);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    if (!isOnline) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const botResponse = await getAgroAdvice(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setLoading(false);
  };

  const handleReset = () => {
    if (window.confirm("Effacer l'historique ? (Les données de l'itinéraire seront conservées)")) {
      const initialMessage: Message[] = [
        { role: 'bot', text: 'Historique effacé. Comment puis-je vous aider ?' }
      ];
      setMessages(initialMessage);
    }
  };

  const getItineraryAsText = () => {
    let text = `📋 ITINÉRAIRE TECHNIQUE : ${cropName.toUpperCase() || 'Sans titre'}\n`;
    if (scientificName) text += `🧬 Nom Scientifique : ${scientificName}\n`;
    if (userEmail) text += `✉️ Contact : ${userEmail}\n`;
    text += `📅 Date de début : ${new Date(startDate).toLocaleDateString('fr-FR')}\n\n`;
    text += `ÉTAPES PRÉVUES :\n`;

    steps.slice().sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).forEach((s, i) => {
      text += `${i + 1}. [${new Date(s.deadline).toLocaleDateString('fr-FR')}] ${s.description}${s.completed ? ' ✅' : ''}\n`;
    });

    if (globalFertPlan) {
      text += `\n🧪 PLAN DE FERTILISATION :\n${globalFertPlan}\n`;
    }

    text += `\nExporté depuis AgroExpert Afrique`;
    return text;
  };

  const copyItineraryToClipboard = () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    navigator.clipboard.writeText(text).then(() => {
      setShowShareSuccess('copy');
      setTimeout(() => setShowShareSuccess(null), 3000);
    });
  };

  const shareViaEmail = () => {
    if (steps.length === 0) return;
    const subject = encodeURIComponent(`Mon Itinéraire Technique : ${cropName}`);
    const body = encodeURIComponent(getItineraryAsText());
    window.location.href = `mailto:?subject=${subject}&body=${body}`;
    setShowShareSuccess('email');
    setTimeout(() => setShowShareSuccess(null), 3000);
  };

  const shareViaNative = async () => {
    if (steps.length === 0) return;
    const text = getItineraryAsText();
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Itinéraire ${cropName}`,
          text: text,
        });
        setShowShareSuccess('share');
        setTimeout(() => setShowShareSuccess(null), 3000);
      } catch (err) {
        copyItineraryToClipboard();
      }
    } else {
      copyItineraryToClipboard();
    }
  };

  const exportToPdf = () => {
    if (steps.length === 0) return;

    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const content = `
      <!DOCTYPE html>
      <html lang="fr">
      <head>
          <meta charset="UTF-8">
          <title>Itinéraire Technique - ${cropName}</title>
          <script src="https://cdn.tailwindcss.com"></script>
          <link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;700&display=swap" rel="stylesheet">
          <style>
              body { font-family: 'Plus Jakarta Sans', sans-serif; padding: 40px; color: #1c1917; background: #fafaf9; }
              @media print {
                  body { padding: 0; background: white; }
                  .no-print { display: none; }
              }
              .step-number { min-width: 24px; height: 24px; }
          </style>
      </head>
      <body class="bg-stone-50">
          <div class="max-w-3xl mx-auto bg-white border border-stone-200 p-10 rounded-[2.5rem] shadow-sm">
              <div class="flex justify-between items-start border-b-2 border-emerald-600 pb-8 mb-8">
                  <div>
                      <div class="flex items-center gap-2 mb-2">
                        <div class="bg-emerald-600 p-1.5 rounded-lg">
                          <div class="w-4 h-4 border-2 border-white rounded-full flex items-center justify-center">
                             <div class="w-1 h-1 bg-white rounded-full"></div>
                          </div>
                        </div>
                        <span class="font-bold text-xl text-emerald-900">AgroExpert Afrique</span>
                      </div>
                      <h1 class="text-3xl font-black text-stone-900 uppercase tracking-tight">${cropName || 'Itinéraire sans nom'}</h1>
                      <p class="text-emerald-600 italic font-bold text-sm">${scientificName || ''}</p>
                  </div>
                  <div class="text-right">
                      <p class="text-xs font-black text-stone-400 uppercase tracking-widest mb-1">Détails du projet</p>
                      <p class="text-sm font-bold text-stone-700">Début : ${new Date(startDate).toLocaleDateString('fr-FR')}</p>
                      ${userEmail ? `<p class="text-sm font-medium text-stone-500">${userEmail}</p>` : ''}
                  </div>
              </div>

              <div class="mb-10">
                  <h2 class="text-lg font-black text-stone-900 mb-6 flex items-center gap-3 uppercase tracking-wider">
                      <span class="w-2 h-8 bg-emerald-600 rounded-full"></span>
                      Calendrier Cultural
                  </h2>
                  <div class="space-y-4">
                      ${steps.slice().sort((a, b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime()).map((s, i) => `
                          <div class="flex items-start gap-5 p-5 bg-stone-50 rounded-3xl border border-stone-100">
                              <div class="step-number bg-emerald-600 text-white rounded-xl flex items-center justify-center text-xs font-black shadow-sm mt-1">
                                  ${i + 1}
                              </div>
                              <div class="flex-1">
                                  <div class="flex justify-between items-center mb-1">
                                      <p class="font-black text-stone-800">${s.description}</p>
                                      <span class="text-[10px] font-black bg-stone-200 text-stone-600 px-2 py-1 rounded-lg uppercase tracking-widest">
                                        ${new Date(s.deadline).toLocaleDateString('fr-FR')}
                                      </span>
                                  </div>
                                  ${stepAdvice[s.id] ? `<div class="mt-3 p-3 bg-white rounded-2xl text-[11px] text-stone-600 italic border border-emerald-100">${stepAdvice[s.id].text}</div>` : ''}
                              </div>
                          </div>
                      `).join('')}
                  </div>
              </div>

              ${globalFertPlan ? `
                  <div class="bg-emerald-900 text-white p-8 rounded-[2rem] shadow-xl relative overflow-hidden">
                      <div class="relative z-10">
                        <h2 class="text-lg font-black mb-4 flex items-center gap-3 uppercase tracking-wider text-emerald-400">
                            Plan de Fertilisation Global
                        </h2>
                        <div class="text-sm leading-relaxed text-emerald-50 opacity-95 whitespace-pre-wrap font-medium">
                            ${globalFertPlan}
                        </div>
                      </div>
                      <div class="absolute -bottom-10 -right-10 w-40 h-40 bg-emerald-500/10 rounded-full blur-3xl"></div>
                  </div>
              ` : ''}

              <div class="mt-16 pt-8 border-t border-stone-200 text-center">
                  <p class="text-[9px] text-stone-400 font-black uppercase tracking-[0.3em] mb-2">Document officiel AgroExpert Afrique</p>
                  <p class="text-[10px] text-stone-500 font-medium">Expertise Agronomique IA au service de l'agriculteur moderne</p>
                  <p class="text-[10px] text-emerald-600 font-bold mt-2">(+235) 66022287 / 90659359</p>
              </div>
          </div>
          <script>
              window.onload = () => {
                  setTimeout(() => {
                      window.print();
                  }, 500);
              };
          </script>
      </body>
      </html>
    `;

    printWindow.document.write(content);
    printWindow.document.close();
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !isOnline) return;
    const mimeType = file.type;

    const reader = new FileReader();
    reader.onloadstart = () => setLoading(true);
    reader.onloadend = async () => {
      const dataUrl = reader.result as string;
      const base64 = dataUrl.split(',')[1];
      setMessages(prev => [...prev, { role: 'user', text: "Diagnostic photo en cours...", image: dataUrl }]);
      const diagnosis = await diagnosePlant(base64, mimeType);
      setMessages(prev => [...prev, { role: 'bot', text: diagnosis }]);
      setLoading(false);
    };
    reader.readAsDataURL(file);
  };

  const addStep = () => {
    if (!newStepDesc || !newStepDate) return;
    const newStep: ItineraryStep = {
      id: Date.now().toString(),
      description: newStepDesc,
      deadline: newStepDate,
      completed: false,
    };
    setSteps([...steps, newStep]);
    setNewStepDesc('');
    setNewStepDate('');
  };

  const handleAiSuggest = async () => {
    if (!cropName || !isOnline) return;
    setSuggesting(true);
    const suggestedSteps = await generateCropItinerary(cropName);
    if (suggestedSteps) {
      const start = new Date(startDate);
      const newSteps: ItineraryStep[] = suggestedSteps.map((s: any, idx: number) => {
        const deadlineDate = new Date(start);
        deadlineDate.setDate(start.getDate() + s.daysFromStart);
        return {
          id: `ai-${Date.now()}-${idx}`,
          description: s.description,
          deadline: deadlineDate.toISOString().split('T')[0],
          completed: false,
          daysFromStart: s.daysFromStart
        };
      });
      setSteps(newSteps);
    }
    setSuggesting(false);
  };

  const handleFetchGlobalFert = async () => {
    if (!cropName || !isOnline) return;
    setFetchingGlobalFert(true);
    const plan = await getCropFertilizationPlan(cropName);
    setGlobalFertPlan(plan);
    setFetchingGlobalFert(false);
  };

  const toggleStep = (id: string) => {
    setSteps(steps.map(s => s.id === id ? { ...s, completed: !s.completed } : s));
  };

  const removeStep = (id: string) => {
    setSteps(steps.filter(s => s.id !== id));
  };

  const fetchFertilizerAdviceForStep = async (stepId: string, description: string) => {
    if (!cropName || !isOnline) return;

    // Toggle off if already showing
    if (stepAdvice[stepId] && !stepAdvice[stepId].loading) {
      const newAdvice = { ...stepAdvice };
      delete newAdvice[stepId];
      setStepAdvice(newAdvice);
      return;
    }

    setStepAdvice(prev => ({ ...prev, [stepId]: { text: '', loading: true } }));
    const advice = await getFertilizerAdvice(cropName, description);
    setStepAdvice(prev => ({ ...prev, [stepId]: { text: advice, loading: false } }));
  };

  const getStepStatus = (step: ItineraryStep) => {
    if (step.completed) return 'completed';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const deadlineDate = new Date(step.deadline);
    if (deadlineDate < today) return 'overdue';
    const diffDays = Math.ceil((deadlineDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    return diffDays <= 3 ? 'upcoming' : 'pending';
  };

  const counts = useMemo(() => {
    const today = new Date();
    today.setHours(0,0,0,0);
    return steps.reduce((acc, s) => {
      if (!s.completed) {
        const d = new Date(s.deadline);
        if (d < today) acc.overdue++;
        else if (Math.ceil((d.getTime() - today.getTime())/(86400000)) <= 3) acc.upcoming++;
      }
      return acc;
    }, { overdue: 0, upcoming: 0 });
  }, [steps]);

  // Current stage logic
  const currentStageInfo = useMemo(() => {
    if (!cropName || steps.length === 0) return null;
    const today = new Date();
    today.setHours(0,0,0,0);
    const sorted = [...steps].sort((a,b) => new Date(a.deadline).getTime() - new Date(b.deadline).getTime());
    // Find the current active step (not completed and closest to today)
    const active = sorted.find(s => !s.completed && new Date(s.deadline) >= today);
    return active ? active.description : "Phase de récolte ou fin de cycle";
  }, [steps, cropName]);

  return (
    <div className="flex flex-col space-y-4">
      {/* Header Statut & Profil */}
      <div className="bg-white rounded-[2rem] p-4 border border-stone-200 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4 flex-1">
          <div className="relative group cursor-pointer shrink-0" onClick={() => avatarInputRef.current?.click()}>
            <div className="w-[48px] h-[48px] rounded-full overflow-hidden border-2 border-emerald-100 flex items-center justify-center bg-stone-100 shadow-inner">
              {userAvatar ? <img src={userAvatar} className="w-full h-full object-cover" /> : <User size={24} className="text-stone-400" />}
            </div>
            <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 rounded-full transition-opacity flex items-center justify-center">
              <Camera size={14} className="text-white" />
            </div>
            <input 
              type="file" 
              ref={avatarInputRef} 
              className="hidden" 
              accept="image/png, image/gif, image/jpeg, image/jpg" 
              onChange={(e) => {
               const file = e.target.files?.[0];
               if (file) {
                 const reader = new FileReader();
                 reader.onloadend = () => setUserAvatar(reader.result as string);
                 reader.readAsDataURL(file);
               }
            }} />
          </div>
          <div className="flex-1">
            <h4 className="text-sm font-bold text-stone-900 leading-tight">Mon Espace Agricole</h4>
            <div className="flex flex-col gap-1 mt-1">
              <div className="flex items-center gap-2">
                <span className={`flex items-center gap-1 text-[9px] font-black uppercase tracking-widest ${isOnline ? 'text-emerald-600' : 'text-amber-600'}`}>
                  {isOnline ? <Wifi size={10} /> : <WifiOff size={10} />}
                  {isOnline ? 'En ligne' : 'Hors ligne'}
                </span>
                {lastSaved && (
                  <span className="text-[8px] text-stone-300 font-bold uppercase flex items-center gap-1">
                    <Save size={8} /> {lastSaved.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                  </span>
                )}
              </div>
              <input 
                type="email" 
                value={userEmail} 
                onChange={(e) => setUserEmail(e.target.value)}
                placeholder="votre@email.com"
                className="text-[10px] font-medium text-stone-600 bg-stone-50 border border-stone-100 rounded-lg px-2 py-1 outline-none focus:ring-1 focus:ring-emerald-500 w-full max-w-[180px]"
              />
            </div>
          </div>
        </div>
      </div>

      {/* Chat IA */}
      <div className="flex flex-col h-[55vh] bg-white rounded-[2rem] shadow-sm border border-stone-200 overflow-hidden relative">
        <div className="bg-emerald-600 px-6 py-4 text-white flex items-center justify-between shadow-lg relative z-10">
          <div className="flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl"><Sparkles size={20} /></div>
            <div>
              <span className="font-bold block leading-tight">Assistant IA</span>
              <span className="text-[10px] uppercase font-black tracking-widest opacity-80 italic">Contextualisé Afrique</span>
            </div>
          </div>
          <button onClick={handleReset} className="p-2 hover:bg-white/10 rounded-xl transition-colors"><RotateCcw size={18} /></button>
        </div>

        {!isOnline && (
          <div className="bg-amber-50 px-4 py-2 border-b border-amber-100 flex items-center gap-2 animate-pulse">
            <AlertCircle size={14} className="text-amber-600" />
            <span className="text-[9px] font-black text-amber-700 uppercase tracking-widest">Connexion perdue. IA indisponible.</span>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-stone-50/50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
               <div className={`max-w-[85%] rounded-3xl p-4 shadow-sm ${
                 m.role === 'user' ? 'bg-emerald-600 text-white rounded-tr-none' : 'bg-white border border-stone-200 text-stone-800 rounded-tl-none'
               }`}>
                 {m.image && <img src={m.image} className="rounded-xl mb-2 max-h-48 w-full object-cover" />}
                 <p className="text-sm leading-relaxed">{m.text}</p>
               </div>
            </div>
          ))}
          {loading && <div className="flex gap-2 p-2"><Loader2 size={16} className="animate-spin text-emerald-600" /><span className="text-xs italic text-stone-400">L'IA réfléchit...</span></div>}
          <div ref={chatEndRef} />
        </div>

        <div className="p-4 bg-white border-t border-stone-100">
           <div className="flex items-center gap-2">
             <button onClick={() => fileInputRef.current?.click()} disabled={!isOnline} className={`p-3 rounded-2xl ${isOnline ? 'text-emerald-600 hover:bg-emerald-50' : 'text-stone-300 cursor-not-allowed'}`}><ImageIcon size={20} /></button>
             <input type="file" ref={fileInputRef} className="hidden" accept="image/png, image/gif, image/jpeg, image/jpg" onChange={handleFileUpload} />
             <input value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleSend()} disabled={!isOnline} placeholder={isOnline ? "Votre question..." : "Reconnectez-vous pour parler à l'IA"} className="flex-1 bg-stone-100 rounded-2xl px-4 py-3 text-sm outline-none disabled:opacity-50" />
             <button onClick={handleSend} disabled={!isOnline || !input.trim()} className="p-3.5 bg-emerald-600 text-white rounded-2xl shadow-lg disabled:bg-stone-200 transition-all active:scale-95"><Send size={18} /></button>
           </div>
        </div>
