                            <div className="whitespace-pre-wrap font-medium text-stone-200 bg-emerald-950/40 p-3 rounded-2xl border border-emerald-800/50">
                              {currentAdvice.text}
                            </div>
                            <div className="mt-3 flex items-center gap-1.5 text-[8px] font-bold text-emerald-500 uppercase tracking-widest opacity-60">
                              <Sparkles size={8} /> Dosages indicatifs pour contexte local
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })
                ) : (
                  <div className="py-12 text-center border-2 border-dashed border-stone-100 rounded-3xl">
                     <ClipboardList className="mx-auto text-stone-200 mb-2" size={32} />
                     <p className="text-xs text-stone-400 font-bold uppercase tracking-widest">Aucun plan enregistré localement</p>
                  </div>
                )}
             </div>
          </div>
        )}
      </div>

      <p className="text-[8px] text-center text-stone-300 font-bold uppercase tracking-[0.2em] py-2">
        AgroExpert Afrique • Sécurité & Sauvegarde Locale Active
      </p>
    </div>
  );
};

