                <span className="text-[9px] font-black text-emerald-700 dark:text-emerald-500 uppercase tracking-widest block">Ajouter une tâche manuelle</span>
                <div className="flex flex-col sm:flex-row gap-2">
                  <input value={newStepDesc} onChange={e => setNewStepDesc(e.target.value)} placeholder="Ex: Sarclage n°1" className="flex-1 bg-white dark:bg-stone-800 text-stone-900 dark:text-stone-100 border border-stone-200 dark:border-stone-700 rounded-xl px-4 py-2 text-sm outline-none focus:ring-1 focus:ring-emerald-500 transition-colors" />
                  <div className="flex gap-2">
                    <input type="date" value={newStepDate} onChange={e => setNewStepDate(e.target.value)} className="bg-white dark:bg-stone-800 text-stone-900 dark:text-stone-100 border border-stone-200 dark:border-stone-700 rounded-xl px-3 py-2 text-xs font-bold transition-colors" />
