const STORAGE_KEYS = {
  CHAT: 'agroexpert_chat_history',
  ITINERARY: 'agroexpert_itinerary_data',
  AVATAR: 'agroexpert_user_avatar',
  EMAIL: 'agroexpert_user_email'
};

const AgroExpert: React.FC = () => {
