            </div>
          ))}
          {loading && <div className="flex gap-2 p-2"><Loader2 size={16} className="animate-spin text-emerald-600" /><span className="text-xs italic text-stone-400 dark:text-stone-500">L'IA réfléchit...</span></div>}
          <div ref={chatEndRef} />
        </div>

