  const handleShareCourse = async (course: any) => {
    const shareData = {
      title: `Cours AgroExpert : ${course.title}`,
      text: `Découvrez ce cours sur AgroExpert Afrique : "${course.title}". ${course.description}`,
      url: window.location.href,
    };

    try {
      if (navigator.share) {
        await navigator.share(shareData);
      } else {
        await navigator.clipboard.writeText(`${shareData.text} - ${shareData.url}`);
        alert("Lien du cours copié dans le presse-papier !");
      }
    } catch (err) {
      console.error("Erreur de partage :", err);
    }
  };

