            <input 
              type="file" 
              ref={avatarInputRef} 
              className="hidden" 
              accept="image/png, image/gif, image/jpeg, image/jpg" 
              onChange={(e) => {
               const file = e.target.files?.[0];
               if (file) {
                 const reader = new FileReader();
                 reader.onloadend = () => setUserAvatar(reader.result as string);
                 reader.readAsDataURL(file);
