               <ClipboardList size={22} />
               {(counts.overdue > 0 || counts.upcoming > 0) && <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white dark:border-stone-900 animate-pulse"></span>}
